    g_rtcore_trace_invocation_publication_source_shadow;
static unsigned long long
    g_rtcore_trace_invocation_publication_source_next_seq = 0;

static bool rtcore_env_flag_enabled(const char *name) {
  const char *value = getenv(name);
  return value != NULL && value[0] != '\0' && strcmp(value, "0") != 0;
}

enum rtcore_path_mode_policy {
  RTCORE_PATH_MODE_POLICY_CUSTOM = 0,
  RTCORE_PATH_MODE_POLICY_LEGACY,
  RTCORE_PATH_MODE_POLICY_INVALID,
};

static char rtcore_ascii_lower(char value) {
  return value >= 'A' && value <= 'Z' ? value - 'A' + 'a' : value;
}

static bool rtcore_path_mode_is(const char *mode, const char *value) {
  if (mode == NULL || value == NULL) {
    return false;
  }
  while (*mode != '\0' && *value != '\0') {
    if (rtcore_ascii_lower(*mode) != rtcore_ascii_lower(*value)) {
      return false;
    }
    ++mode;
    ++value;
  }
  return *mode == '\0' && *value == '\0';
}

static bool rtcore_rt_env_value_is_explicit_false(const char *value) {
  return value != NULL && value[0] != '\0' &&
         (strcmp(value, "0") == 0 || rtcore_path_mode_is(value, "false") ||
          rtcore_path_mode_is(value, "off") ||
          rtcore_path_mode_is(value, "no") ||
          rtcore_path_mode_is(value, "disabled") ||
          rtcore_path_mode_is(value, "disable") ||
          rtcore_path_mode_is(value, "deny") ||
          rtcore_path_mode_is(value, "denied"));
}

static bool rtcore_rt_env_value_is_explicit_true(const char *value) {
  return value != NULL && value[0] != '\0' &&
         (strcmp(value, "1") == 0 || rtcore_path_mode_is(value, "true") ||
          rtcore_path_mode_is(value, "on") ||
          rtcore_path_mode_is(value, "yes") ||
          rtcore_path_mode_is(value, "allow") ||
          rtcore_path_mode_is(value, "allowed") ||
          rtcore_path_mode_is(value, "enabled") ||
          rtcore_path_mode_is(value, "enable") ||
          rtcore_path_mode_is(value, "default"));
}

static const char *rtcore_path_mode_raw_value() {
  const char *mode = getenv("VULKAN_SIM_RTCORE_PATH_MODE");
  return mode == NULL ? "" : mode;
}

static bool rtcore_path_mode_compat_custom_enabled() {
  return rtcore_env_flag_enabled("VULKAN_SIM_RTCORE_SYMBOLIC_SUBMIT") ||
         rtcore_env_flag_enabled("VULKAN_SIM_RTCORE_FORWARD_SIDEBAND_PATH") ||
         rtcore_env_flag_enabled(
             "VULKAN_SIM_RTCORE_COMPILER_DRIVER_PUBLICATION_SOURCE") ||
         rtcore_env_flag_enabled(
             "VULKAN_SIM_RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_BRIDGE");
}

static rtcore_path_mode_policy rtcore_get_path_mode_policy() {
  const char *mode = getenv("VULKAN_SIM_RTCORE_PATH_MODE");
  if (mode != NULL && mode[0] != '\0') {
    if (rtcore_path_mode_is(mode, "legacy") ||
        rtcore_path_mode_is(mode, "trace_ray") ||
        rtcore_path_mode_is(mode, "trace-ray") ||
        rtcore_path_mode_is(mode, "trace_ray_only") ||
        rtcore_path_mode_is(mode, "trace-ray-only")) {
      return RTCORE_PATH_MODE_POLICY_LEGACY;
    }
    if (rtcore_path_mode_is(mode, "custom") ||
        rtcore_path_mode_is(mode, "forward") ||
        rtcore_path_mode_is(mode, "forward_sideband") ||
        rtcore_path_mode_is(mode, "forward-sideband") ||
        rtcore_path_mode_is(mode, "sideband")) {
      return RTCORE_PATH_MODE_POLICY_CUSTOM;
    }
    return RTCORE_PATH_MODE_POLICY_INVALID;
  }
  if (rtcore_env_flag_enabled("VULKAN_SIM_RTCORE_LEGACY_TRACE_RAY_PATH")) {
    return RTCORE_PATH_MODE_POLICY_LEGACY;
  }
  if (rtcore_path_mode_compat_custom_enabled()) {
    return RTCORE_PATH_MODE_POLICY_CUSTOM;
  }
  return RTCORE_PATH_MODE_POLICY_CUSTOM;
}

static bool rtcore_path_mode_policy_legacy_path_enabled(
    rtcore_path_mode_policy policy) {
  return policy == RTCORE_PATH_MODE_POLICY_LEGACY;
}

static bool rtcore_path_mode_policy_enables_custom_path(
    rtcore_path_mode_policy policy) {
  return policy == RTCORE_PATH_MODE_POLICY_CUSTOM;
}

static bool rtcore_path_mode_policy_is_invalid(
    rtcore_path_mode_policy policy) {
  return policy == RTCORE_PATH_MODE_POLICY_INVALID;
}

static bool rtcore_legacy_trace_ray_path_enabled() {
  return rtcore_path_mode_policy_legacy_path_enabled(
      rtcore_get_path_mode_policy());
}

static bool rtcore_forward_sideband_path_enabled() {
  return rtcore_path_mode_policy_enables_custom_path(
      rtcore_get_path_mode_policy());
}

static bool rtcore_trace_invocation_publication_source_enabled() {
  const rtcore_path_mode_policy policy = rtcore_get_path_mode_policy();
  if (rtcore_path_mode_policy_legacy_path_enabled(policy) ||
      rtcore_path_mode_policy_is_invalid(policy)) {
    return false;
  }
  return rtcore_env_flag_enabled(
      "VULKAN_SIM_RTCORE_TRACE_INVOCATION_PUBLICATION_SOURCE");
}

static bool rtcore_compiler_driver_publication_source_enabled() {
  const rtcore_path_mode_policy policy = rtcore_get_path_mode_policy();
  if (rtcore_path_mode_policy_legacy_path_enabled(policy) ||
      rtcore_path_mode_policy_is_invalid(policy)) {
    return false;
  }
  return rtcore_path_mode_policy_enables_custom_path(policy);
}

static bool rtcore_fail_closed_on_invalid_path_mode(const ptx_instruction *pI) {
  if (!rtcore_path_mode_policy_is_invalid(rtcore_get_path_mode_policy())) {
    return false;
  }
  printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
         "invalid VULKAN_SIM_RTCORE_PATH_MODE=%s\n",
         pI->source_file(), pI->source_line(), rtcore_path_mode_raw_value());
  fflush(stdout);
  inst_not_implemented(pI);
  return true;
}

static bool
rtcore_trace_invocation_publication_source_fallback_enabled() {
  return rtcore_trace_invocation_publication_source_enabled() &&
         !rtcore_compiler_driver_publication_source_enabled();
}

static bool
rtcore_compiler_driver_publication_source_failpoint_corrupt_context_window_key() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_COMPILER_DRIVER_PUBLICATION_SOURCE_FAILPOINT");
  return value != NULL && strcmp(value, "corrupt_context_window_key") == 0;
}

static bool
rtcore_compiler_driver_publication_source_failpoint_drop_context_window_key() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_COMPILER_DRIVER_PUBLICATION_SOURCE_FAILPOINT");
  return value != NULL && strcmp(value, "drop_context_window_key") == 0;
}

static bool rtcore_trace_invocation_publication_source_owner_tuple_matches(
    ptx_thread_info *thread,
    const rtcore_trace_invocation_publication_source_shadow &shadow) {
  if (thread == NULL) {
    return false;
  }
  return shadow.owner_hw_tid == thread->get_hw_tid() &&
         shadow.owner_hw_wid == thread->get_hw_wid() &&
         shadow.owner_hw_sid == thread->get_hw_sid();
}

static bool
rtcore_trace_invocation_publication_source_failpoint_drop_publish() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_TRACE_INVOCATION_PUBLICATION_SOURCE_FAILPOINT");
  return value != NULL && strcmp(value, "drop_publish") == 0;
}

static bool
rtcore_trace_invocation_publication_source_failpoint_corrupt_owner_tuple() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_TRACE_INVOCATION_PUBLICATION_SOURCE_FAILPOINT");
  return value != NULL && strcmp(value, "corrupt_owner_tuple") == 0;
}

static void rtcore_publish_trace_invocation_publication_source_shadow(
    const ptx_instruction *pI, ptx_thread_info *thread, uint64_t top_level_as,
    uint32_t ray_flags, uint32_t cull_mask, uint32_t sbt_record_offset,
    uint32_t sbt_record_stride, uint32_t miss_index, float3 ray_origin,
    float ray_tmin, float3 ray_direction, float ray_tmax) {
  if (rtcore_trace_invocation_publication_source_enabled() &&
      rtcore_compiler_driver_publication_source_enabled()) {
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "compiler-driver-publication-source-policy-suppressed-trace-shadow "
           "(%s:%u), source=trace_ray_impl, "
           "preferred_source=compiler_driver_publication_sideband\n",
           pI->source_file(), pI->source_line());
    fflush(stdout);
    return;
  }
  if (!rtcore_trace_invocation_publication_source_fallback_enabled() ||
      thread == NULL) {
    return;
  }
  if (rtcore_trace_invocation_publication_source_failpoint_drop_publish()) {
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "trace-invocation-publication-source-drop-publish (%s:%u), "
           "source=trace_ray_impl, top_level_as=0x%llx, ray_flags=%u, "
           "cull_mask=%u, sbt_record_offset=%u, sbt_record_stride=%u, "
           "miss_index=%u\n",
           pI->source_file(), pI->source_line(),
           (unsigned long long)top_level_as, ray_flags, cull_mask,
           sbt_record_offset, sbt_record_stride, miss_index);
    fflush(stdout);
    return;
  }

  rtcore_trace_invocation_publication_source_shadow shadow;
  shadow.valid = true;
  shadow.thread = thread;
  shadow.source_publication_seq =
      ++g_rtcore_trace_invocation_publication_source_next_seq;
  shadow.owner_hw_tid = thread->get_hw_tid();
  shadow.owner_hw_wid = thread->get_hw_wid();
  shadow.owner_hw_sid = thread->get_hw_sid();
  shadow.owner_tuple_match = true;
  shadow.top_level_as = top_level_as;
  shadow.has_top_level_as = top_level_as != 0;
  shadow.ray_origin = ray_origin;
  shadow.ray_direction = ray_direction;
  shadow.ray_tmin = ray_tmin;
  shadow.ray_tmax = ray_tmax;
  shadow.ray_flags = ray_flags;
  shadow.cull_mask = cull_mask;
  shadow.sbt_record_offset = sbt_record_offset;
  shadow.sbt_record_stride = sbt_record_stride;
  shadow.miss_index = miss_index;
  if (rtcore_trace_invocation_publication_source_failpoint_corrupt_owner_tuple()) {
    unsigned expected_owner_hw_sid = shadow.owner_hw_sid;
    shadow.owner_hw_sid = shadow.owner_hw_sid + 1;
    shadow.owner_tuple_match = false;
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "trace-invocation-publication-source-owner-mismatch (%s:%u), "
           "source=trace_ray_impl, source_publication_seq=%llu, "
           "expected_owner_hw_tid=%u, expected_owner_hw_wid=%u, "
           "expected_owner_hw_sid=%u, owner_hw_tid=%u, owner_hw_wid=%u, "
           "owner_hw_sid=%u\n",
           pI->source_file(), pI->source_line(),
           shadow.source_publication_seq, shadow.owner_hw_tid,
           shadow.owner_hw_wid, expected_owner_hw_sid,
           shadow.owner_hw_tid, shadow.owner_hw_wid, shadow.owner_hw_sid);
    fflush(stdout);
  }
  g_rtcore_trace_invocation_publication_source_shadow[thread] = shadow;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "trace-invocation-publication-source-shadow (%s:%u), "
         "source=trace_ray_impl, top_level_as=0x%llx, "
         "has_top_level_as=%u, ray_flags=%u, cull_mask=%u, "
         "sbt_record_offset=%u, sbt_record_stride=%u, miss_index=%u, "
         "source_publication_seq=%llu, owner_hw_tid=%u, "
         "owner_hw_wid=%u, owner_hw_sid=%u\n",
         pI->source_file(), pI->source_line(),
         (unsigned long long)shadow.top_level_as,
         shadow.has_top_level_as ? 1 : 0, shadow.ray_flags,
         shadow.cull_mask, shadow.sbt_record_offset,
         shadow.sbt_record_stride, shadow.miss_index,
         shadow.source_publication_seq, shadow.owner_hw_tid,
         shadow.owner_hw_wid, shadow.owner_hw_sid);
  fflush(stdout);
}

static bool rtcore_consume_trace_invocation_publication_source_shadow(
    ptx_thread_info *thread,
    rtcore_trace_invocation_publication_source_shadow *out_shadow) {
  if (thread == NULL || out_shadow == NULL) {
    return false;
  }
  std::map<ptx_thread_info *,
           rtcore_trace_invocation_publication_source_shadow>::iterator found =
      g_rtcore_trace_invocation_publication_source_shadow.find(thread);
  if (found == g_rtcore_trace_invocation_publication_source_shadow.end()) {
    return false;
  }
  *out_shadow = found->second;
  g_rtcore_trace_invocation_publication_source_shadow.erase(found);
  out_shadow->owner_tuple_match =
      rtcore_trace_invocation_publication_source_owner_tuple_matches(
          thread, *out_shadow);
  return out_shadow->valid && out_shadow->thread == thread &&
         out_shadow->owner_tuple_match;
}

static void rtcore_publish_trace_context_publication_source_shadow(
    const ptx_instruction *pI, ptx_thread_info *thread,
    unsigned long long context_ptr, unsigned long long handoff_window_base,
    uint64_t top_level_as, uint32_t ray_flags, uint32_t cull_mask,
    uint32_t sbt_record_offset, uint32_t sbt_record_stride,
    uint32_t miss_index, float3 ray_origin, float ray_tmin,
    float3 ray_direction, float ray_tmax) {
  if (!rtcore_compiler_driver_publication_source_enabled() || thread == NULL) {
    return;
  }

  rtcore_trace_invocation_publication_source_shadow shadow;
  shadow.valid = true;
  shadow.thread = thread;
  shadow.source_publication_seq =
      ++g_rtcore_trace_invocation_publication_source_next_seq;
  shadow.owner_hw_tid = thread->get_hw_tid();
  shadow.owner_hw_wid = thread->get_hw_wid();
  shadow.owner_hw_sid = thread->get_hw_sid();
  shadow.owner_tuple_match = true;
  shadow.source = "compiler_driver_publication_sideband";
  shadow.has_context_window_owner_key = true;
  shadow.context_ptr = context_ptr;
  shadow.handoff_window_base = handoff_window_base;
  shadow.top_level_as = top_level_as;
  shadow.has_top_level_as = top_level_as != 0;
  shadow.ray_origin = ray_origin;
  shadow.ray_direction = ray_direction;
  shadow.ray_tmin = ray_tmin;
  shadow.ray_tmax = ray_tmax;
  shadow.ray_flags = ray_flags;
  shadow.cull_mask = cull_mask;
  shadow.sbt_record_offset = sbt_record_offset;
  shadow.sbt_record_stride = sbt_record_stride;
  shadow.miss_index = miss_index;
  if (rtcore_compiler_driver_publication_source_failpoint_corrupt_context_window_key()) {
    unsigned long long expected_context_ptr = shadow.context_ptr;
    unsigned long long expected_handoff_window_base = shadow.handoff_window_base;
    shadow.context_ptr = shadow.context_ptr + 64;
    shadow.handoff_window_base = shadow.handoff_window_base + 128;
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "compiler-driver-publication-source-context-window-mismatch "
           "(%s:%u), source=compiler_driver_publication_sideband, "
           "source_publication_seq=%llu, "
           "expected_context_ptr=0x%llx, expected_handoff_window_base=0x%llx, "
           "published_context_ptr=0x%llx, "
           "published_handoff_window_base=0x%llx\n",
           pI->source_file(), pI->source_line(),
           shadow.source_publication_seq, expected_context_ptr,
           expected_handoff_window_base, shadow.context_ptr,
           shadow.handoff_window_base);
    fflush(stdout);
  }
  if (rtcore_compiler_driver_publication_source_failpoint_drop_context_window_key()) {
    shadow.has_context_window_owner_key = false;
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "compiler-driver-publication-source-missing-context-window-key "
           "(%s:%u), source=compiler_driver_publication_sideband, "
           "source_publication_seq=%llu, published_context_ptr=0x%llx, "
           "published_handoff_window_base=0x%llx\n",
           pI->source_file(), pI->source_line(),
           shadow.source_publication_seq, shadow.context_ptr,
           shadow.handoff_window_base);
    fflush(stdout);
  }
  g_rtcore_trace_invocation_publication_source_shadow[thread] = shadow;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "rt-publish-trace-context-publication-source (%s:%u), "
         "source=compiler_driver_publication_sideband, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "top_level_as=0x%llx, has_top_level_as=%u, "
         "ray_flags=%u, cull_mask=%u, sbt_record_offset=%u, "
         "sbt_record_stride=%u, miss_index=%u, "
         "source_publication_seq=%llu, owner_hw_tid=%u, "
         "owner_hw_wid=%u, owner_hw_sid=%u\n",
         pI->source_file(), pI->source_line(), context_ptr,
         handoff_window_base, (unsigned long long)shadow.top_level_as,
         shadow.has_top_level_as ? 1 : 0, shadow.ray_flags,
         shadow.cull_mask, shadow.sbt_record_offset,
         shadow.sbt_record_stride, shadow.miss_index,
         shadow.source_publication_seq, shadow.owner_hw_tid,
         shadow.owner_hw_wid, shadow.owner_hw_sid);
  fflush(stdout);
}

static bool rtcore_fail_closed_on_rt_publish_trace_context_operand_contract(
    const ptx_instruction *pI) {
  if (pI->get_num_operands() == 16) {
    return false;
  }
  printf("GPGPU-Sim PTX: RT_PUBLISH_TRACE_CONTEXT fail-closed (%s:%u), "
         "reason=RT_PUBLISH_TRACE_CONTEXT_OPERAND_CONTRACT, "
         "observed_operands=%u, expected_operands=16\n",
         pI->source_file(), pI->source_line(), pI->get_num_operands());
  fflush(stdout);
  inst_not_implemented(pI);
  return true;
}

void rt_publish_trace_context_impl(const ptx_instruction *pI, ptx_thread_info *thread) {
  if (rtcore_fail_closed_on_rt_publish_trace_context_operand_contract(pI)) {
    return;
  }

  const operand_info &context_ptr = pI->operand_lookup(0);
  ptx_reg_t context_ptr_data =
      thread->get_operand_value(context_ptr, context_ptr, B64_TYPE, thread, 1);

  const operand_info &handoff_window_base = pI->operand_lookup(1);
  ptx_reg_t handoff_window_base_data = thread->get_operand_value(
      handoff_window_base, handoff_window_base, B64_TYPE, thread, 1);

  const operand_info &topLevelAS = pI->operand_lookup(2);
  ptx_reg_t topLevelAS_data =
      thread->get_operand_value(topLevelAS, topLevelAS, B64_TYPE, thread, 1);

  const operand_info &rayFlags = pI->operand_lookup(3);
  ptx_reg_t rayFlags_data =
      thread->get_operand_value(rayFlags, rayFlags, U32_TYPE, thread, 1);

  const operand_info &cullMask = pI->operand_lookup(4);
  ptx_reg_t cullMask_data =
      thread->get_operand_value(cullMask, cullMask, U32_TYPE, thread, 1);

  const operand_info &sbtRecordOffset = pI->operand_lookup(5);
  ptx_reg_t sbtRecordOffset_data = thread->get_operand_value(
      sbtRecordOffset, sbtRecordOffset, U32_TYPE, thread, 1);

  const operand_info &sbtRecordStride = pI->operand_lookup(6);
  ptx_reg_t sbtRecordStride_data = thread->get_operand_value(
      sbtRecordStride, sbtRecordStride, U32_TYPE, thread, 1);

  const operand_info &missIndex = pI->operand_lookup(7);
  ptx_reg_t missIndex_data =
      thread->get_operand_value(missIndex, missIndex, U32_TYPE, thread, 1);

  const operand_info &originX = pI->operand_lookup(8);
  ptx_reg_t originX_data =
      thread->get_operand_value(originX, originX, F32_TYPE, thread, 1);

  const operand_info &originY = pI->operand_lookup(9);
  ptx_reg_t originY_data =
      thread->get_operand_value(originY, originY, F32_TYPE, thread, 1);

  const operand_info &originZ = pI->operand_lookup(10);
  ptx_reg_t originZ_data =
      thread->get_operand_value(originZ, originZ, F32_TYPE, thread, 1);

  const operand_info &Tmin = pI->operand_lookup(11);
  ptx_reg_t Tmin_data =
      thread->get_operand_value(Tmin, Tmin, F32_TYPE, thread, 1);

  const operand_info &directionX = pI->operand_lookup(12);
  ptx_reg_t directionX_data =
      thread->get_operand_value(directionX, directionX, F32_TYPE, thread, 1);

  const operand_info &directionY = pI->operand_lookup(13);
  ptx_reg_t directionY_data =
      thread->get_operand_value(directionY, directionY, F32_TYPE, thread, 1);

  const operand_info &directionZ = pI->operand_lookup(14);
  ptx_reg_t directionZ_data =
      thread->get_operand_value(directionZ, directionZ, F32_TYPE, thread, 1);

  const operand_info &Tmax = pI->operand_lookup(15);
  ptx_reg_t Tmax_data =
      thread->get_operand_value(Tmax, Tmax, F32_TYPE, thread, 1);

  float3 ray_origin = {originX_data.f32, originY_data.f32, originZ_data.f32};
  float3 ray_direction = {directionX_data.f32, directionY_data.f32,
                          directionZ_data.f32};
  rtcore_publish_trace_context_publication_source_shadow(
      pI, thread, context_ptr_data.u64, handoff_window_base_data.u64,
      (uint64_t)topLevelAS_data.u64, rayFlags_data.u32, cullMask_data.u32,
      sbtRecordOffset_data.u32, sbtRecordStride_data.u32,
      missIndex_data.u32, ray_origin, Tmin_data.f32, ray_direction,
      Tmax_data.f32);
}

void trace_ray_impl(const ptx_instruction *pI, ptx_thread_info *thread) {
  // if(thread->get_tid().x == 0 && thread->get_tid().y == 0 && thread->get_tid().z == 0)
  //   if(thread->get_ctaid().x == 0 && thread->get_ctaid().y == 0 && thread->get_ctaid().z == 0)
    VSIM_DPRINTF("gpgpusim: trace ray implementation\n");
    if(print_debug_insts)
    {
      printf("########## running line %d of file %s. thread(%d, %d, %d), cta(%d, %d, %d)\n", pI->source_line(), pI->source_file(),
                                        thread->get_tid().x, thread->get_tid().y, thread->get_tid().z,
                                        thread->get_ctaid().x, thread->get_ctaid().y, thread->get_ctaid().z);
      fflush(stdout);
    }

  // const operand_info &target = pI->func_addr();
  // const symbol *func_addr = target.get_symbol();
  // function_info *target_func = func_addr->get_pc();

  // unsigned n_return = target_func->has_return();
  // assert(n_return == 0);
  // unsigned n_args = target_func->num_args();
  // assert(n_args == 11);



  int arg = 0;
  const operand_info &op1 = pI->operand_lookup(arg);
  ptx_reg_t op1_data = thread->get_operand_value(op1, op1, B64_TYPE, thread, 1);
  VkAccelerationStructureKHR _topLevelAS = (VkAccelerationStructureKHR)(op1_data.s64);

  arg++;
  const operand_info &op2 = pI->operand_lookup(arg);
  ptx_reg_t op2_data = thread->get_operand_value(op2, op2, U32_TYPE, thread, 1);
  uint rayFlags = op2_data.u32;


  arg++;
  const operand_info &op3 = pI->operand_lookup(arg);
  ptx_reg_t op3_data = thread->get_operand_value(op3, op3, U32_TYPE, thread, 1);
  uint cullMask = op3_data.u32;

  arg++;
  const operand_info &op4 = pI->operand_lookup(arg);
  ptx_reg_t op4_data = thread->get_operand_value(op4, op4, U32_TYPE, thread, 1);
  uint sbtRecordOffset = op4_data.u32;

  arg++;
  const operand_info &op5 = pI->operand_lookup(arg);
  ptx_reg_t op5_data = thread->get_operand_value(op5, op5, U32_TYPE, thread, 1);
  uint sbtRecordStride = op5_data.u32;

  arg++;
  const operand_info &op6 = pI->operand_lookup(arg);
  ptx_reg_t op6_data = thread->get_operand_value(op6, op6, U32_TYPE, thread, 1);
  uint missIndex = op6_data.u32;

  arg++;
  const operand_info &op7 = pI->operand_lookup(arg);
  ptx_reg_t op7_data = thread->get_operand_value(op7, op7, F32_TYPE, thread, 1);
  float originX = op7_data.f32;

  arg++;
  const operand_info &op8 = pI->operand_lookup(arg);
  ptx_reg_t op8_data = thread->get_operand_value(op8, op8, F32_TYPE, thread, 1);
  float originY = op8_data.f32;

  arg++;
  const operand_info &op9 = pI->operand_lookup(arg);
  ptx_reg_t op9_data = thread->get_operand_value(op9, op9, F32_TYPE, thread, 1);
  float originZ = op9_data.f32;

  arg++;
  const operand_info &op10 = pI->operand_lookup(arg);
  ptx_reg_t op10_data = thread->get_operand_value(op10, op10, F32_TYPE, thread, 1);
  float Tmin = op10_data.f32;

  arg++;
  const operand_info &op11 = pI->operand_lookup(arg);
  ptx_reg_t op11_data = thread->get_operand_value(op11, op11, F32_TYPE, thread, 1);
  float directionX = op11_data.f32;

  arg++;
  const operand_info &op12 = pI->operand_lookup(arg);
  ptx_reg_t op12_data = thread->get_operand_value(op12, op12, F32_TYPE, thread, 1);
  float directionY = op12_data.f32;

  arg++;
  const operand_info &op13 = pI->operand_lookup(arg);
  ptx_reg_t op13_data = thread->get_operand_value(op13, op13, F32_TYPE, thread, 1);
  float directionZ = op13_data.f32;

  arg++;
  const operand_info &op14 = pI->operand_lookup(arg);
  ptx_reg_t op14_data = thread->get_operand_value(op14, op14, F32_TYPE, thread, 1);
  float Tmax = op14_data.f32;

  // arg++;
  // const operand_info &op15 = pI->operand_lookup(arg);
  // ptx_reg_t op15_data = thread->get_operand_value(op15, op15, U64_TYPE, thread, 1);
  // uint32_t payload = op15_data.u64;

  // thread->dump_regs(stdout);

  float3 ray_origin = {originX, originY, originZ};
  float3 ray_direction = {directionX, directionY, directionZ};
  rtcore_publish_trace_invocation_publication_source_shadow(
      pI, thread, (uint64_t)_topLevelAS, rayFlags, cullMask, sbtRecordOffset,
      sbtRecordStride, missIndex, ray_origin, Tmin, ray_direction, Tmax);

  VulkanRayTracing::traceRay(_topLevelAS, rayFlags, cullMask, sbtRecordOffset, sbtRecordStride, missIndex,
                   ray_origin,
                   Tmin,
                   ray_direction,
                   Tmax,
                   NULL,
                   pI,
                   thread);
}

