static std::map<std::pair<unsigned, unsigned>,
                rtcore_pending_traversal_completion>
    g_rtcore_pending_traversal_completions;

static rtcore_adapter_completion_publication
rtcore_make_adapter_completion_publication_from_pending(
    const rtcore_pending_traversal_completion &record) {
  rtcore_adapter_completion_publication publication;
  publication.warp_uid = record.warp_uid;
  publication.warp_id = record.warp_id;
  publication.owner_hw_sid = record.owner_hw_sid;
  publication.active_mask = record.active_mask;
  publication.static_inst_uid = record.static_inst_uid;
  publication.lane_slot_index = record.lane_slot_index;
  publication.lane_thread_mask = record.lane_thread_mask;
  publication.node_visits = record.traversal_snapshot.rtcore_node_visits;
  publication.primitive_tests =
      record.traversal_snapshot.rtcore_primitive_tests;
  publication.provider_backend_input_completion_publication_annotation =
      record.provider_backend_input_pending_completion_annotation;
  return publication;
}

static bool rtcore_backend_input_completion_annotation_values_match(
    const rtcore_traversal_completion_provider_backend_input_annotation &lhs,
    const rtcore_traversal_completion_provider_backend_input_annotation &rhs) {
  return lhs.provider_payload_consumption_enabled ==
             rhs.provider_payload_consumption_enabled &&
         lhs.backend_input_snapshot_required ==
             rhs.backend_input_snapshot_required &&
         lhs.has_provider_payload_backend_input_snapshot ==
             rhs.has_provider_payload_backend_input_snapshot &&
         lhs.provider_payload_backend_input_snapshot_valid ==
             rhs.provider_payload_backend_input_snapshot_valid &&
         lhs.provider_payload_backend_input_snapshot_accepted ==
             rhs.provider_payload_backend_input_snapshot_accepted &&
         lhs.has_provider_materialized_traversal_input_snapshot ==
             rhs.has_provider_materialized_traversal_input_snapshot &&
         lhs.provider_materialized_traversal_input_snapshot_valid ==
             rhs.provider_materialized_traversal_input_snapshot_valid &&
         strcmp(lhs.provider_materialized_traversal_input_snapshot_source,
                rhs.provider_materialized_traversal_input_snapshot_source) ==
             0 &&
         lhs.provider_materialized_traversal_input_actual_abi_snapshot_admitted ==
             rhs.provider_materialized_traversal_input_actual_abi_snapshot_admitted;
}

static void
rtcore_maybe_perturb_backend_input_completion_publication_annotation_for_claim_test(
    rtcore_adapter_completion_record *record,
    rtcore_traversal_completion_provider_backend_input_annotation *annotation,
    const rtcore_adapter_completion_publication &publication) {
  if (record == NULL || annotation == NULL || !annotation->valid ||
      !record->provider_backend_input_completion_record_annotation.valid ||
      g_rtcore_test_provider_backend_input_claim_aggregate_mismatch_injected ||
      !rtcore_test_provider_backend_input_claim_aggregate_mismatch_enabled()) {
    return;
  }

  annotation->provider_payload_backend_input_snapshot_accepted =
      !annotation->provider_payload_backend_input_snapshot_accepted;
  g_rtcore_test_provider_backend_input_claim_aggregate_mismatch_injected = true;
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-backend-input-claim-aggregate-mismatch-test, "
         "warp_uid=%u, lane_slot_index=%u, lane_thread_mask=0x%08x, "
         "provider-backend-input-claim-aggregate-mismatch-test=1, "
         "provider_payload_backend_input_snapshot_accepted=%u\n",
         publication.warp_uid, publication.lane_slot_index,
         publication.lane_thread_mask,
         annotation->provider_payload_backend_input_snapshot_accepted ? 1 : 0);
  fflush(stdout);
}

static void
rtcore_record_backend_input_completion_publication_annotation(
    rtcore_adapter_completion_record *record,
    const rtcore_adapter_completion_publication &publication) {
  if (record == NULL ||
      !publication.provider_backend_input_completion_publication_annotation
           .valid) {
    return;
  }

  const rtcore_traversal_completion_provider_backend_input_annotation
      &publication_annotation =
          publication.provider_backend_input_completion_publication_annotation;
  rtcore_traversal_completion_provider_backend_input_annotation
      aggregate_annotation = publication_annotation;
  rtcore_maybe_perturb_backend_input_completion_publication_annotation_for_claim_test(
      record, &aggregate_annotation, publication);
  rtcore_traversal_completion_provider_backend_input_annotation
      &record_annotation =
          record->provider_backend_input_completion_record_annotation;
  if (!record_annotation.valid) {
    record_annotation = aggregate_annotation;
  } else if (!rtcore_backend_input_completion_annotation_values_match(
                 record_annotation, aggregate_annotation)) {
    record->provider_backend_input_completion_record_aggregate_mismatch = true;
  }
  record->provider_backend_input_completion_record_observed_lane_mask |=
      publication.lane_thread_mask;
}

static bool rtcore_publish_adapter_completion_record(
    const rtcore_adapter_completion_publication &publication) {
  const bool valid_lane = publication.lane_slot_index < 32;
  const bool lane_active =
      (publication.active_mask & publication.lane_thread_mask) != 0;
  rtcore_adapter_completion_record &record =
      g_rtcore_adapter_completions[publication.warp_uid];
  if (!record.valid) {
    record.valid = true;
    record.warp_uid = publication.warp_uid;
    record.warp_id = publication.warp_id;
    record.owner_hw_sid = publication.owner_hw_sid;
    record.active_mask = publication.active_mask;
    record.static_inst_uid = publication.static_inst_uid;
  }

  const bool metadata_matches =
      record.warp_uid == publication.warp_uid &&
      record.warp_id == publication.warp_id &&
      record.owner_hw_sid == publication.owner_hw_sid &&
      record.active_mask == publication.active_mask &&
      record.static_inst_uid == publication.static_inst_uid;
  if (valid_lane && lane_active && metadata_matches) {
    record.completed_lane_mask |= publication.lane_thread_mask;
    if (publication.node_visits > record.max_node_visits) {
      record.max_node_visits = publication.node_visits;
    }
    if (publication.primitive_tests > record.max_primitive_tests) {
      record.max_primitive_tests = publication.primitive_tests;
    }
    rtcore_record_backend_input_completion_publication_annotation(
        &record, publication);
  }
  const bool accepted = valid_lane && lane_active && metadata_matches;
  const rtcore_traversal_completion_provider_backend_input_annotation
      &backend_input_annotation =
          publication.provider_backend_input_completion_publication_annotation;

  printf("GPGPU-Sim PTX: RT_SUBMIT adapter-completion-publish, "
         "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, active_mask=0x%08x, "
         "completed_lane_mask=0x%08x, static_inst_uid=%u, "
         "lane_slot_index=%u, lane_thread_mask=0x%08x, "
         "node_visits=%u, primitive_tests=%u, max_node_visits=%u, "
         "max_primitive_tests=%u, accepted=%u, "
         "adapter-completion-provider-backend-input-annotation=1, "
         "provider_backend_input_completion_publication_annotation_valid=%u, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_publication_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "adapter_completion_backend_input_annotation_consumes_completion_behavior=0\n",
         publication.warp_uid, publication.warp_id, publication.owner_hw_sid,
         publication.active_mask, record.completed_lane_mask,
         publication.static_inst_uid, publication.lane_slot_index,
         publication.lane_thread_mask, publication.node_visits,
         publication.primitive_tests,
         record.max_node_visits, record.max_primitive_tests,
         accepted ? 1 : 0,
         backend_input_annotation.valid ? 1 : 0,
         backend_input_annotation.provider_payload_consumption_enabled ? 1 : 0,
         backend_input_annotation.backend_input_snapshot_required ? 1 : 0,
         backend_input_annotation.has_provider_payload_backend_input_snapshot ? 1
                                                                        : 0,
         backend_input_annotation.provider_payload_backend_input_snapshot_valid
             ? 1
             : 0,
         backend_input_annotation
                 .provider_payload_backend_input_snapshot_accepted
             ? 1
             : 0,
         backend_input_annotation
                 .has_provider_materialized_traversal_input_snapshot
             ? 1
             : 0,
         backend_input_annotation
                 .provider_materialized_traversal_input_snapshot_valid
             ? 1
             : 0,
         backend_input_annotation
             .provider_materialized_traversal_input_snapshot_source,
         backend_input_annotation
                 .provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
  return accepted;
}

extern "C" bool rtcore_publish_adapter_completion(
    unsigned warp_uid, unsigned warp_id, unsigned owner_hw_sid,
    unsigned active_mask, unsigned static_inst_uid,
    unsigned lane_slot_index, unsigned node_visits,
    unsigned primitive_tests) {
  rtcore_adapter_completion_publication publication;
  publication.warp_uid = warp_uid;
  publication.warp_id = warp_id;
  publication.owner_hw_sid = owner_hw_sid;
  publication.active_mask = active_mask;
  publication.static_inst_uid = static_inst_uid;
  publication.lane_slot_index = lane_slot_index;
  publication.lane_thread_mask =
      lane_slot_index < 32 ? (1u << lane_slot_index) : 0;
  publication.node_visits = node_visits;
  publication.primitive_tests = primitive_tests;
  return rtcore_publish_adapter_completion_record(publication);
}

extern "C" bool rtcore_service_pending_traversal_completion(
    unsigned warp_uid, unsigned warp_id, unsigned owner_hw_sid,
    unsigned issued_active_mask) {
  if (!rtcore_delayed_traversal_completion_enabled()) {
    return false;
  }

  const bool test_drop_lane =
      rtcore_test_delayed_completion_drop_lane_enabled();
  bool serviced = false;
  bool dropped_lane = false;
  unsigned dropped_lane_mask = 0;
  unsigned published_lanes = 0;
  unsigned metadata_mismatch_lanes = 0;

  std::map<std::pair<unsigned, unsigned>,
           rtcore_pending_traversal_completion>::iterator event =
      g_rtcore_pending_traversal_completions.begin();
  while (event != g_rtcore_pending_traversal_completions.end()) {
    rtcore_pending_traversal_completion record = event->second;
    if (event->first.first != warp_uid) {
      ++event;
      continue;
    }

    serviced = true;
    const bool metadata_matches =
        record.valid && record.warp_uid == warp_uid &&
        record.warp_id == warp_id && record.owner_hw_sid == owner_hw_sid &&
        record.active_mask == issued_active_mask;
    const char *reject_reason =
        metadata_matches ? "accepted" : "metadata_mismatch";
    const bool drop_this_lane =
        test_drop_lane && !dropped_lane && metadata_matches;
    bool published = false;
    if (metadata_matches && !drop_this_lane) {
      rtcore_adapter_completion_publication publication =
          rtcore_make_adapter_completion_publication_from_pending(record);
      published = rtcore_publish_adapter_completion_record(publication);
      if (published) {
        published_lanes++;
      }
    } else if (drop_this_lane) {
      dropped_lane = true;
      dropped_lane_mask = record.lane_thread_mask;
      reject_reason = "dropped_lane";
    } else {
      metadata_mismatch_lanes++;
    }

    printf("GPGPU-Sim PTX: RT-unit delayed-completion-service, "
           "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, "
           "lane_slot_index=%u, lane_thread_mask=0x%08x, "
           "metadata_match=%u, reject_reason=%s, dropped_lane=%u, "
           "published=%u\n",
           warp_uid, warp_id, owner_hw_sid, record.lane_slot_index,
           record.lane_thread_mask, metadata_matches ? 1 : 0,
           reject_reason, drop_this_lane ? 1 : 0, published ? 1 : 0);
    fflush(stdout);
    event = g_rtcore_pending_traversal_completions.erase(event);
  }

  if (serviced) {
    printf("GPGPU-Sim PTX: RT-unit delayed-completion-service-summary, "
           "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, "
           "issued_active_mask=0x%08x, published_lanes=%u, "
           "dropped_lane=%u, dropped_lane_mask=0x%08x, "
           "metadata_mismatch_lanes=%u\n",
           warp_uid, warp_id, owner_hw_sid, issued_active_mask,
           published_lanes, dropped_lane ? 1 : 0, dropped_lane_mask,
           metadata_mismatch_lanes);
    fflush(stdout);
  }
  return serviced;
}

static rtcore_adapter_completion_claim_status rtcore_query_adapter_completion_status_internal(
    unsigned warp_uid, unsigned warp_id, unsigned owner_hw_sid) {
  rtcore_adapter_completion_claim_status status;
  std::map<unsigned, rtcore_adapter_completion_record>::iterator event =
      g_rtcore_adapter_completions.find(warp_uid);
  if (event == g_rtcore_adapter_completions.end()) {
    return status;
  }

  const rtcore_adapter_completion_record &record = event->second;
  status.found = true;
  status.active_mask = record.active_mask;
  status.completed_lane_mask = record.completed_lane_mask;
  status.static_inst_uid = record.static_inst_uid;
  status.max_node_visits = record.max_node_visits;
  status.max_primitive_tests = record.max_primitive_tests;
  const rtcore_traversal_completion_provider_backend_input_annotation
      &backend_input_annotation =
          record.provider_backend_input_completion_record_annotation;
  status.provider_backend_input_claim_annotation_valid =
      backend_input_annotation.valid;
  status.provider_backend_input_claim_observed_lane_mask =
      record.provider_backend_input_completion_record_observed_lane_mask;
  status.provider_backend_input_claim_all_completed_lanes_observed =
      record.completed_lane_mask != 0 &&
      (record.provider_backend_input_completion_record_observed_lane_mask &
       record.completed_lane_mask) == record.completed_lane_mask;
  status.provider_backend_input_claim_aggregate_mismatch =
      record.provider_backend_input_completion_record_aggregate_mismatch;
  status.provider_payload_consumption_enabled =
      backend_input_annotation.provider_payload_consumption_enabled;
  status.backend_input_snapshot_required =
      backend_input_annotation.backend_input_snapshot_required;
  status.has_provider_payload_backend_input_snapshot =
      backend_input_annotation.has_provider_payload_backend_input_snapshot;
  status.provider_payload_backend_input_snapshot_valid =
      backend_input_annotation.provider_payload_backend_input_snapshot_valid;
  status.provider_payload_backend_input_snapshot_accepted =
      backend_input_annotation.provider_payload_backend_input_snapshot_accepted;
  status.has_provider_materialized_traversal_input_snapshot =
      backend_input_annotation.has_provider_materialized_traversal_input_snapshot;
  status.provider_materialized_traversal_input_snapshot_valid =
      backend_input_annotation.provider_materialized_traversal_input_snapshot_valid;
  status.provider_materialized_traversal_input_snapshot_source =
      backend_input_annotation.provider_materialized_traversal_input_snapshot_source;
  status.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      backend_input_annotation
          .provider_materialized_traversal_input_actual_abi_snapshot_admitted;
  status.metadata_match =
      record.valid && record.warp_uid == warp_uid &&
      record.warp_id == warp_id && record.owner_hw_sid == owner_hw_sid;
  status.lanes_complete =
      record.active_mask != 0 &&
      (record.completed_lane_mask & record.active_mask) == record.active_mask;
  status.accepted = status.metadata_match && status.lanes_complete;
  if (status.accepted) {
    status.reject_reason = "accepted";
  } else if (!status.metadata_match) {
    status.reject_reason = "metadata_mismatch";
  } else {
    status.reject_reason = "incomplete_lanes";
  }
  return status;
}

static void rtcore_fill_adapter_completion_claim_snapshot(
    const rtcore_adapter_completion_claim_status &status,
    rtcore_adapter_completion_claim_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->found = status.found;
  snapshot->metadata_match = status.metadata_match;
  snapshot->lanes_complete = status.lanes_complete;
  snapshot->accepted = status.accepted;
  snapshot->active_mask = status.active_mask;
  snapshot->completed_lane_mask = status.completed_lane_mask;
  snapshot->static_inst_uid = status.static_inst_uid;
  snapshot->max_node_visits = status.max_node_visits;
  snapshot->max_primitive_tests = status.max_primitive_tests;
  snapshot->provider_backend_input_claim_annotation_valid =
      status.provider_backend_input_claim_annotation_valid;
  snapshot->provider_backend_input_claim_observed_lane_mask =
      status.provider_backend_input_claim_observed_lane_mask;
  snapshot->provider_backend_input_claim_all_completed_lanes_observed =
      status.provider_backend_input_claim_all_completed_lanes_observed;
  snapshot->provider_backend_input_claim_aggregate_mismatch =
      status.provider_backend_input_claim_aggregate_mismatch;
  snapshot->provider_payload_consumption_enabled =
      status.provider_payload_consumption_enabled;
  snapshot->backend_input_snapshot_required =
      status.backend_input_snapshot_required;
  snapshot->has_provider_payload_backend_input_snapshot =
      status.has_provider_payload_backend_input_snapshot;
  snapshot->provider_payload_backend_input_snapshot_valid =
      status.provider_payload_backend_input_snapshot_valid;
  snapshot->provider_payload_backend_input_snapshot_accepted =
      status.provider_payload_backend_input_snapshot_accepted;
  snapshot->has_provider_materialized_traversal_input_snapshot =
      status.has_provider_materialized_traversal_input_snapshot;
  snapshot->provider_materialized_traversal_input_snapshot_valid =
      status.provider_materialized_traversal_input_snapshot_valid;
  snapshot->provider_materialized_traversal_input_snapshot_source =
      status.provider_materialized_traversal_input_snapshot_source;
  snapshot->provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      status.provider_materialized_traversal_input_actual_abi_snapshot_admitted;
  snapshot->reject_reason = status.reject_reason;
}

extern "C" bool rtcore_claim_adapter_completion_snapshot(
    unsigned warp_uid, unsigned warp_id, unsigned owner_hw_sid,
    rtcore_adapter_completion_claim_snapshot *snapshot) {
  rtcore_adapter_completion_claim_status status =
      rtcore_query_adapter_completion_status_internal(
          warp_uid, warp_id, owner_hw_sid);
  rtcore_fill_adapter_completion_claim_snapshot(status, snapshot);
  if (!status.found) {
    printf("GPGPU-Sim PTX: RT-unit adapter-completion-claim, "
           "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, found=0, "
           "active_mask=0x%08x, completed_lane_mask=0x%08x, "
           "static_inst_uid=%u, max_node_visits=%u, "
           "max_primitive_tests=%u, metadata_match=%u, lanes_complete=%u, "
           "accepted=%u, reject_reason=%s, "
           "adapter-completion-provider-backend-input-claim-annotation=1, "
           "provider_backend_input_claim_annotation_valid=%u, "
           "provider_backend_input_claim_observed_lane_mask=0x%08x, "
           "provider_backend_input_claim_all_completed_lanes_observed=%u, "
           "provider_backend_input_claim_aggregate_mismatch=%u, "
           "provider_payload_consumption_enabled=%u, "
           "backend_input_snapshot_required=%u, "
           "has_provider_payload_backend_input_snapshot=%u, "
           "provider_payload_backend_input_snapshot_valid=%u, "
           "provider_payload_backend_input_snapshot_accepted=%u, "
           "provider_materialized_traversal_input_claim_provenance=1, "
           "provider_materialized_traversal_input_snapshot=1, "
           "has_provider_materialized_traversal_input_snapshot=%u, "
           "provider_materialized_traversal_input_snapshot_valid=%u, "
           "provider_materialized_traversal_input_snapshot_source=%s, "
           "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
           "adapter_completion_claim_backend_input_annotation_consumes_readiness_behavior=0\n",
           warp_uid, warp_id, owner_hw_sid, status.active_mask,
           status.completed_lane_mask, status.static_inst_uid,
           status.max_node_visits, status.max_primitive_tests,
           status.metadata_match ? 1 : 0, status.lanes_complete ? 1 : 0,
           status.accepted ? 1 : 0, status.reject_reason,
           status.provider_backend_input_claim_annotation_valid ? 1 : 0,
           status.provider_backend_input_claim_observed_lane_mask,
           status.provider_backend_input_claim_all_completed_lanes_observed ? 1
                                                                            : 0,
           status.provider_backend_input_claim_aggregate_mismatch ? 1 : 0,
           status.provider_payload_consumption_enabled ? 1 : 0,
           status.backend_input_snapshot_required ? 1 : 0,
           status.has_provider_payload_backend_input_snapshot ? 1 : 0,
           status.provider_payload_backend_input_snapshot_valid ? 1 : 0,
           status.provider_payload_backend_input_snapshot_accepted ? 1 : 0,
           status.has_provider_materialized_traversal_input_snapshot ? 1 : 0,
           status.provider_materialized_traversal_input_snapshot_valid ? 1 : 0,
           status.provider_materialized_traversal_input_snapshot_source,
           status.provider_materialized_traversal_input_actual_abi_snapshot_admitted
               ? 1
               : 0);
    fflush(stdout);
    return false;
  }

  if (status.accepted) {
    g_rtcore_adapter_completions.erase(warp_uid);
  }

  printf("GPGPU-Sim PTX: RT-unit adapter-completion-claim, "
         "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, found=1, "
         "active_mask=0x%08x, completed_lane_mask=0x%08x, "
         "static_inst_uid=%u, max_node_visits=%u, "
         "max_primitive_tests=%u, metadata_match=%u, lanes_complete=%u, "
         "accepted=%u, reject_reason=%s, "
         "adapter-completion-provider-backend-input-claim-annotation=1, "
         "provider_backend_input_claim_annotation_valid=%u, "
         "provider_backend_input_claim_observed_lane_mask=0x%08x, "
         "provider_backend_input_claim_all_completed_lanes_observed=%u, "
         "provider_backend_input_claim_aggregate_mismatch=%u, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_claim_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "adapter_completion_claim_backend_input_annotation_consumes_readiness_behavior=0\n",
         warp_uid, warp_id, owner_hw_sid, status.active_mask,
         status.completed_lane_mask, status.static_inst_uid,
         status.max_node_visits, status.max_primitive_tests,
         status.metadata_match ? 1 : 0, status.lanes_complete ? 1 : 0,
         status.accepted ? 1 : 0, status.reject_reason,
         status.provider_backend_input_claim_annotation_valid ? 1 : 0,
         status.provider_backend_input_claim_observed_lane_mask,
         status.provider_backend_input_claim_all_completed_lanes_observed ? 1
                                                                          : 0,
         status.provider_backend_input_claim_aggregate_mismatch ? 1 : 0,
         status.provider_payload_consumption_enabled ? 1 : 0,
         status.backend_input_snapshot_required ? 1 : 0,
         status.has_provider_payload_backend_input_snapshot ? 1 : 0,
         status.provider_payload_backend_input_snapshot_valid ? 1 : 0,
         status.provider_payload_backend_input_snapshot_accepted ? 1 : 0,
         status.has_provider_materialized_traversal_input_snapshot ? 1 : 0,
         status.provider_materialized_traversal_input_snapshot_valid ? 1 : 0,
         status.provider_materialized_traversal_input_snapshot_source,
         status.provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
  return status.accepted;
}

extern "C" bool rtcore_claim_adapter_completion(
    unsigned warp_uid, unsigned warp_id, unsigned owner_hw_sid,
    unsigned *active_mask, unsigned *completed_lane_mask,
    unsigned *static_inst_uid, unsigned *max_node_visits,
    unsigned *max_primitive_tests) {
  rtcore_adapter_completion_claim_snapshot snapshot;
  const bool accepted = rtcore_claim_adapter_completion_snapshot(
      warp_uid, warp_id, owner_hw_sid, &snapshot);
  if (accepted) {
    if (active_mask != NULL) {
      *active_mask = snapshot.active_mask;
    }
    if (completed_lane_mask != NULL) {
      *completed_lane_mask = snapshot.completed_lane_mask;
    }
    if (static_inst_uid != NULL) {
      *static_inst_uid = snapshot.static_inst_uid;
    }
    if (max_node_visits != NULL) {
      *max_node_visits = snapshot.max_node_visits;
    }
    if (max_primitive_tests != NULL) {
      *max_primitive_tests = snapshot.max_primitive_tests;
    }
  }
  return accepted;
}

