static bool rtcore_replay_provider_decoded_abi_authority_complete(
    const rtcore_traversal_source_request &request) {
  return request.from_provider_backend_input_snapshot &&
         request.has_replay_ray_origin_direction_tmin_tmax &&
         request.has_replay_ray_flags_cull_mask &&
         request.has_replay_launch_context_input &&
         strcmp(request.replay_ray_origin_direction_tmin_tmax_authority,
                "compiler_driver_publication") == 0 &&
         strcmp(request.replay_ray_flags_cull_mask_authority,
                "compiler_driver_publication") == 0 &&
         strcmp(request.replay_launch_context_input_authority,
                "compiler_driver_publication") == 0 &&
         strcmp(request.replay_context_window_authority, "driver_runtime") ==
             0 &&
         request.replay_context_window_bound_to_provider_decoded_abi;
}

static const char *rtcore_full_backend_input_abi_block_reason_label(
    bool provider_decoded_abi_authority_complete,
    bool root_profile_abi_gap_open,
    bool actual_abi_evidence_for_proxy_fields) {
  if (!provider_decoded_abi_authority_complete) {
    return "provider_decoded_abi_authority_incomplete";
  }
  if (root_profile_abi_gap_open) {
    return "root_profile_abi_gap_open";
  }
  if (!actual_abi_evidence_for_proxy_fields) {
    return "actual_abi_evidence_for_proxy_fields_unavailable";
  }
  return "none";
}

static const char *
rtcore_existing_traversal_backend_input_source_snapshot_label(
    bool actual_abi_source_snapshot_admitted) {
  return actual_abi_source_snapshot_admitted
             ? "provider_actual_abi_source_snapshot"
             : "provider_backend_input_compatibility_snapshot";
}

static const char *rtcore_actual_abi_source_snapshot_block_reason_label(
    bool actual_abi_source_snapshot_admitted,
    const char *full_backend_input_abi_block_reason) {
  return actual_abi_source_snapshot_admitted
             ? "none"
             : full_backend_input_abi_block_reason;
}

static rtcore_traversal_source_request
rtcore_make_traversal_source_request(
    const ptx_instruction *pI, ptx_thread_info *thread,
    unsigned long long context_ptr, unsigned long long handoff_window_base,
    unsigned lane_slot_index,
    const ptx_thread_info::rtcore_current_warp_metadata *warp_metadata) {
  rtcore_traversal_source_request request;
  request.pI = pI;
  request.thread = thread;
  request.context_ptr = context_ptr;
  request.handoff_window_base = handoff_window_base;
  request.lane_slot_index = lane_slot_index;
  if (warp_metadata != NULL) {
    request.warp_metadata = *warp_metadata;
  }
  request.provider = rtcore_select_traversal_source_provider();
  printf("GPGPU-Sim PTX: RT_SUBMIT traversal-source-provider-selected, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "traversal-source-provider-selected=1\n",
         rtcore_traversal_source_provider_name(request.provider),
         request.context_ptr, request.handoff_window_base,
         request.lane_slot_index, request.warp_metadata.warp_uid,
         request.warp_metadata.active_mask);
  fflush(stdout);
  return request;
}

struct rtcore_provider_facing_registry_payload_shadow;

enum rtcore_decoded_input_field_owner_class {
  RTCORE_DECODED_INPUT_OWNER_FORBIDDEN = 0,
  RTCORE_DECODED_INPUT_OWNER_DRIVER_RUNTIME,
  RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION,
  RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY,
};

static const char *rtcore_decoded_input_field_owner_class_name(
    rtcore_decoded_input_field_owner_class owner) {
  switch (owner) {
    case RTCORE_DECODED_INPUT_OWNER_DRIVER_RUNTIME:
      return "driver_runtime";
    case RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION:
      return "compiler_driver_publication";
    case RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY:
      return "simulator_proxy";
    case RTCORE_DECODED_INPUT_OWNER_FORBIDDEN:
    default:
      return "forbidden";
  }
}

static const char *rtcore_decoded_input_field_source_label(
    rtcore_decoded_input_field_owner_class owner) {
  switch (owner) {
    case RTCORE_DECODED_INPUT_OWNER_DRIVER_RUNTIME:
      return "driver_runtime";
    case RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION:
      return "compiler_driver_publication_sideband";
    case RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY:
      return "simulator_proxy";
    case RTCORE_DECODED_INPUT_OWNER_FORBIDDEN:
    default:
      return "unavailable";
  }
}

