static const char *rtcore_selected_root_descriptor_label_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_SELECTED_ROOT_DESCRIPTOR_LABEL_FAILPOINT";
}

static bool
rtcore_selected_root_descriptor_label_failpoint_payload_route_owner_drift() {
  const char *value =
      getenv(rtcore_selected_root_descriptor_label_failpoint_env_name());
  return value != NULL && strcmp(value, "payload_route_owner_drift") == 0;
}

static const char *rtcore_selected_root_field_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_SELECTED_ROOT_FIELD_FAILPOINT";
}

static bool rtcore_selected_root_field_failpoint_metadata_handle_drift() {
  const char *value = getenv(rtcore_selected_root_field_failpoint_env_name());
  // replay_selected_root_descriptor_root_field_failpoint=metadata_handle_drift;
  return value != NULL && strcmp(value, "metadata_handle_drift") == 0;
}

static const char *rtcore_backend_root_descriptor_payload_selected_owner_label(
    bool actual_producer_authority_enabled) {
  // selected_root_descriptor_label_failpoint_payload_route_owner_drift=1;
  if (actual_producer_authority_enabled &&
      rtcore_selected_root_descriptor_label_failpoint_payload_route_owner_drift()) {
    return "simulator_proxy";
  }
  return rtcore_backend_root_descriptor_selected_owner_label(
      actual_producer_authority_enabled);
}

static bool rtcore_decoded_input_field_owner_has_lifetime(
    rtcore_decoded_input_field_owner_class owner) {
  return owner == RTCORE_DECODED_INPUT_OWNER_DRIVER_RUNTIME ||
         owner == RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION ||
         owner == RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

static bool rtcore_decoded_input_fields_all_owned_with_lifetime(
    bool has_ray_origin_direction_tmin_tmax,
    rtcore_decoded_input_field_owner_class ray_origin_direction_tmin_tmax_owner,
    bool has_ray_flags_cull_mask,
    rtcore_decoded_input_field_owner_class ray_flags_cull_mask_owner,
    bool has_launch_context_input,
    rtcore_decoded_input_field_owner_class launch_context_input_owner,
    bool has_traversable_root_proxy,
    rtcore_decoded_input_field_owner_class traversable_root_proxy_owner,
    bool has_bvh_format_profile,
    rtcore_decoded_input_field_owner_class bvh_format_profile_owner) {
  return has_ray_origin_direction_tmin_tmax &&
         rtcore_decoded_input_field_owner_has_lifetime(
             ray_origin_direction_tmin_tmax_owner) &&
         has_ray_flags_cull_mask &&
         rtcore_decoded_input_field_owner_has_lifetime(
             ray_flags_cull_mask_owner) &&
         has_launch_context_input &&
         rtcore_decoded_input_field_owner_has_lifetime(
             launch_context_input_owner) &&
         has_traversable_root_proxy &&
         rtcore_decoded_input_field_owner_has_lifetime(
             traversable_root_proxy_owner) &&
         has_bvh_format_profile &&
         rtcore_decoded_input_field_owner_has_lifetime(
             bvh_format_profile_owner);
}

static bool rtcore_proxy_delegation_gate_passed_for_proxy_fields(
    bool has_traversable_root_proxy,
    rtcore_decoded_input_field_owner_class traversable_root_proxy_owner,
    bool has_bvh_format_profile,
    rtcore_decoded_input_field_owner_class bvh_format_profile_owner) {
  return has_traversable_root_proxy &&
         traversable_root_proxy_owner ==
             RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY &&
         has_bvh_format_profile &&
         bvh_format_profile_owner == RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

