struct rtcore_traversal_work_descriptor {
  rtcore_traversal_work_descriptor()
      : valid(false),
        provider(RTCORE_TRAVERSAL_SOURCE_PROVIDER_LEGACY_FUNCTIONAL),
        context_ptr(0),
        handoff_window_base(0),
        lane_slot_index(0),
        has_registry_payload_shadow(false),
        has_provider_decoded_input_observation(false),
        provider_decoded_input_observation(),
        provider_payload_consumption_enabled(false),
        has_provider_payload_consumed_input(false),
        provider_payload_consumed_input(),
        has_provider_materialized_traversal_input_snapshot(false),
        provider_materialized_traversal_input_snapshot(),
        registry_payload_shadow(NULL) {}

  bool valid;
  rtcore_traversal_source_provider provider;
  unsigned long long context_ptr;
  unsigned long long handoff_window_base;
  unsigned lane_slot_index;
  ptx_thread_info::rtcore_current_warp_metadata warp_metadata;
  bool has_registry_payload_shadow;
  bool has_provider_decoded_input_observation;
  rtcore_provider_decoded_input_observation
      provider_decoded_input_observation;
  bool provider_payload_consumption_enabled;
  bool has_provider_payload_consumed_input;
  rtcore_provider_payload_consumed_input_view provider_payload_consumed_input;
  bool has_provider_materialized_traversal_input_snapshot;
  rtcore_provider_materialized_traversal_input_snapshot
      provider_materialized_traversal_input_snapshot;
  const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow;
};

static rtcore_traversal_work_descriptor
rtcore_make_traversal_work_descriptor(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow,
    const rtcore_provider_decoded_input_observation
        *provider_decoded_input_observation) {
  rtcore_traversal_work_descriptor descriptor;
  descriptor.valid = true;
  descriptor.provider = request.provider;
  descriptor.context_ptr = request.context_ptr;
  descriptor.handoff_window_base = request.handoff_window_base;
  descriptor.lane_slot_index = request.lane_slot_index;
  descriptor.warp_metadata = request.warp_metadata;
  descriptor.has_registry_payload_shadow = registry_payload_shadow != NULL;
  descriptor.provider_decoded_input_observation =
      provider_decoded_input_observation != NULL &&
              provider_decoded_input_observation->valid
          ? *provider_decoded_input_observation
          : rtcore_make_provider_decoded_input_observation(
                registry_payload_shadow);
  descriptor.has_provider_decoded_input_observation =
      descriptor.provider_decoded_input_observation.valid;
  descriptor.provider_payload_consumption_enabled =
      rtcore_provider_payload_consumption_effective_enabled(
          registry_payload_shadow);
  descriptor.has_provider_payload_consumed_input =
      descriptor.provider_payload_consumption_enabled;
  descriptor.provider_payload_consumed_input =
      rtcore_make_provider_payload_consumed_input_view(
          registry_payload_shadow,
          descriptor.provider_payload_consumption_enabled);
  descriptor.provider_materialized_traversal_input_snapshot =
      rtcore_make_provider_materialized_traversal_input_snapshot(
          descriptor.provider_payload_consumed_input);
  descriptor.has_provider_materialized_traversal_input_snapshot =
      descriptor.provider_materialized_traversal_input_snapshot.valid;
  descriptor.registry_payload_shadow = registry_payload_shadow;
  return descriptor;
}

static rtcore_traversal_work_descriptor
rtcore_make_traversal_work_descriptor(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow) {
  return rtcore_make_traversal_work_descriptor(request, registry_payload_shadow,
                                              NULL);
}

static rtcore_traversal_work_descriptor
rtcore_make_traversal_work_descriptor(
    const rtcore_traversal_source_request &request) {
  return rtcore_make_traversal_work_descriptor(request, NULL);
}

struct rtcore_provider_payload_backend_input_snapshot {
  rtcore_provider_payload_backend_input_snapshot()
      : valid(false),
        provider_payload_consumption_enabled(false),
        has_provider_materialized_traversal_input_snapshot(false),
        provider_materialized_traversal_input_snapshot_valid(false),
        provider_materialized_traversal_input_snapshot_source("unavailable"),
        provider_materialized_traversal_input_actual_abi_snapshot_admitted(
            false),
        consumed_input_view() {}

  bool valid;
  bool provider_payload_consumption_enabled;
  bool has_provider_materialized_traversal_input_snapshot;
  bool provider_materialized_traversal_input_snapshot_valid;
  const char *provider_materialized_traversal_input_snapshot_source;
  bool provider_materialized_traversal_input_actual_abi_snapshot_admitted;
  rtcore_provider_payload_consumed_input_view consumed_input_view;
};

static rtcore_provider_payload_backend_input_snapshot
rtcore_make_provider_payload_backend_input_snapshot(
    const rtcore_traversal_work_descriptor &descriptor) {
  rtcore_provider_payload_backend_input_snapshot snapshot;
  snapshot.provider_payload_consumption_enabled =
      descriptor.provider_payload_consumption_enabled;
  if (!descriptor.provider_payload_consumption_enabled ||
      !descriptor.has_provider_payload_consumed_input ||
      !descriptor.provider_payload_consumed_input.valid) {
    return snapshot;
  }

  snapshot.valid = true;
  snapshot.consumed_input_view = descriptor.provider_payload_consumed_input;
  snapshot.has_provider_materialized_traversal_input_snapshot =
      descriptor.has_provider_materialized_traversal_input_snapshot;
  snapshot.provider_materialized_traversal_input_snapshot_valid =
      descriptor.provider_materialized_traversal_input_snapshot.valid;
  snapshot.provider_materialized_traversal_input_snapshot_source =
      descriptor.provider_materialized_traversal_input_snapshot.source;
  snapshot.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      snapshot.has_provider_materialized_traversal_input_snapshot &&
      snapshot.provider_materialized_traversal_input_snapshot_valid &&
      rtcore_provider_payload_view_proxy_fields_retired_by_actual_producer(
          descriptor.provider_payload_consumed_input);
  return snapshot;
}

enum rtcore_traversal_provider_reject_reason {
  RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE = 0,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_UNSUPPORTED = 1,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_WORK_DESCRIPTOR_REJECTED = 2,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_ACCEPTED_PAYLOAD_MISSING = 3,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_PAYLOAD_BACKEND_INPUT_MISSING = 4,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_DECODED_ABI_AUTHORITY = 5,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_SELECTED_ROOT_DESCRIPTOR_PAYLOAD_ROUTE_DRIFT = 6,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_SELECTED_ROOT_DESCRIPTOR_ROOT_FIELD_DRIFT = 7,
  RTCORE_TRAVERSAL_PROVIDER_REJECT_PRODUCER_ROOT_DESCRIPTOR_TRAVERSAL_AUTHORITY_NOT_READY = 8
};

static const char *rtcore_traversal_provider_reject_reason_name(
    rtcore_traversal_provider_reject_reason reason) {
  switch (reason) {
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_ACCEPTED_PAYLOAD_MISSING:
      return "RTCORE_TRAVERSAL_PROVIDER_ACCEPTED_PAYLOAD_MISSING";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_PAYLOAD_BACKEND_INPUT_MISSING:
      return "RTCORE_TRAVERSAL_PROVIDER_PAYLOAD_BACKEND_INPUT_MISSING";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_DECODED_ABI_AUTHORITY:
      return "RTCORE_TRAVERSAL_PROVIDER_DECODED_ABI_AUTHORITY_REJECTED";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_SELECTED_ROOT_DESCRIPTOR_PAYLOAD_ROUTE_DRIFT:
      return "RTCORE_TRAVERSAL_PROVIDER_SELECTED_ROOT_DESCRIPTOR_PAYLOAD_ROUTE_DRIFT";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_SELECTED_ROOT_DESCRIPTOR_ROOT_FIELD_DRIFT:
      return "RTCORE_TRAVERSAL_PROVIDER_SELECTED_ROOT_DESCRIPTOR_ROOT_FIELD_DRIFT";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_PRODUCER_ROOT_DESCRIPTOR_TRAVERSAL_AUTHORITY_NOT_READY:
      return "RTCORE_TRAVERSAL_PROVIDER_PRODUCER_ROOT_DESCRIPTOR_TRAVERSAL_AUTHORITY_NOT_READY";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_WORK_DESCRIPTOR_REJECTED:
      return "RTCORE_TRAVERSAL_PROVIDER_WORK_DESCRIPTOR_REJECTED";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_UNSUPPORTED:
      return "RTCORE_TRAVERSAL_SOURCE_PROVIDER_UNSUPPORTED";
    case RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE:
      return "RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE";
    default:
      return "RTCORE_TRAVERSAL_PROVIDER_REJECT_UNKNOWN";
  }
}

