static bool
rtcore_selected_root_descriptor_payload_route_consistency_fail_closed_required(
    const rtcore_custom_backend_result &custom_result) {
  if (!custom_result.supported || !custom_result.accepted ||
      custom_result.reject_reason != RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE ||
      !custom_result.has_provider_payload_backend_input_snapshot ||
      !custom_result.provider_payload_backend_input_snapshot.valid) {
    return false;
  }

  const rtcore_provider_payload_consumed_input_view &view =
      custom_result.provider_payload_backend_input_snapshot.consumed_input_view;
  if (!view.resolve_backend_root_descriptor_actual_producer_authority_enabled) {
    return false;
  }

  const char *selected_owner = rtcore_backend_root_descriptor_selected_owner_label(
      view.resolve_backend_root_descriptor_actual_producer_authority_enabled);
  const char *selected_source = rtcore_backend_root_descriptor_selected_source_label(
      view.resolve_backend_root_descriptor_actual_producer_authority_enabled);
  const char *payload_owner =
      rtcore_backend_root_descriptor_payload_selected_owner_label(
          view.resolve_backend_root_descriptor_actual_producer_authority_enabled);
  const char *payload_source =
      rtcore_backend_root_descriptor_selected_source_label(
          view.resolve_backend_root_descriptor_actual_producer_authority_enabled);

  return strcmp(selected_owner, payload_owner) != 0 ||
         strcmp(selected_source, payload_source) != 0;
}

static void
rtcore_apply_selected_root_descriptor_payload_route_consistency_policy(
    rtcore_traversal_provider_response *response,
    const rtcore_custom_backend_result &custom_result) {
  if (response == NULL || !response->provider_supported ||
      !response->provider_accepted ||
      response->reject_reason != RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE ||
      !rtcore_selected_root_descriptor_payload_route_consistency_fail_closed_required(
          custom_result)) {
    return;
  }

  response->provider_accepted = false;
  response->reject_reason =
      RTCORE_TRAVERSAL_PROVIDER_REJECT_SELECTED_ROOT_DESCRIPTOR_PAYLOAD_ROUTE_DRIFT;
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "selected-root-descriptor-payload-route-consistency-policy, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "selected_root_descriptor_payload_route_consistency_policy=fail_closed_actual_producer, "
         "selected_root_descriptor_payload_route_consistency_fail_closed=1, "
         "reject_reason=%s\n",
         rtcore_traversal_source_provider_name(response->provider),
         custom_result.context_ptr, custom_result.handoff_window_base,
         custom_result.lane_slot_index,
         custom_result.warp_metadata.warp_uid,
         custom_result.warp_metadata.active_mask,
         rtcore_traversal_provider_reject_reason_name(response->reject_reason));
  fflush(stdout);
}

static void
rtcore_annotate_provider_response_with_backend_input_snapshot_result(
    rtcore_traversal_provider_response *response,
    const rtcore_custom_backend_result &custom_result) {
  if (response == NULL) {
    return;
  }

  rtcore_provider_backend_input_response_annotation &annotation =
      response->provider_backend_input_response_annotation;
  annotation.valid = true;
  annotation.provider_payload_consumption_enabled =
      custom_result.provider_payload_backend_input_snapshot
          .provider_payload_consumption_enabled;
  annotation.backend_input_snapshot_required =
      rtcore_custom_backend_result_requires_provider_payload_backend_input_snapshot(
          custom_result);
  annotation.has_provider_payload_backend_input_snapshot =
      custom_result.has_provider_payload_backend_input_snapshot;
  annotation.provider_payload_backend_input_snapshot_valid =
      custom_result.provider_payload_backend_input_snapshot.valid;
  annotation.provider_payload_backend_input_snapshot_accepted =
      annotation.backend_input_snapshot_required &&
      response->provider_accepted &&
      annotation.has_provider_payload_backend_input_snapshot &&
      annotation.provider_payload_backend_input_snapshot_valid;
  annotation.has_provider_materialized_traversal_input_snapshot =
      custom_result.provider_payload_backend_input_snapshot
          .has_provider_materialized_traversal_input_snapshot;
  annotation.provider_materialized_traversal_input_snapshot_valid =
      custom_result.provider_payload_backend_input_snapshot
          .provider_materialized_traversal_input_snapshot_valid;
  annotation.provider_materialized_traversal_input_snapshot_source =
      custom_result.provider_payload_backend_input_snapshot
          .provider_materialized_traversal_input_snapshot_source;
  annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      custom_result.provider_payload_backend_input_snapshot
          .provider_materialized_traversal_input_actual_abi_snapshot_admitted;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-backend-input-response-annotation, provider=%s, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, provider-backend-input-response-annotation=1, "
         "provider_backend_input_response_annotation_valid=1, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_response_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "response_backend_input_annotation_consumes_traversal_behavior=0\n",
         rtcore_traversal_source_provider_name(response->provider),
         custom_result.context_ptr, custom_result.handoff_window_base,
         custom_result.lane_slot_index,
         annotation.provider_payload_consumption_enabled ? 1 : 0,
         annotation.backend_input_snapshot_required ? 1 : 0,
         annotation.has_provider_payload_backend_input_snapshot ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_valid ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_accepted ? 1 : 0,
         annotation.has_provider_materialized_traversal_input_snapshot ? 1 : 0,
         annotation.provider_materialized_traversal_input_snapshot_valid ? 1
                                                                         : 0,
         annotation.provider_materialized_traversal_input_snapshot_source,
         annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
}

static rtcore_traversal_provider_response
rtcore_make_provider_response_from_custom_rtcore_backend_result(
    const rtcore_custom_backend_result &custom_result) {
  rtcore_traversal_provider_response response;
  response.provider = custom_result.provider;
  response.provider_supported = custom_result.supported;
  response.provider_accepted = custom_result.accepted;
  response.reject_reason = custom_result.reject_reason;
  response.traversal_snapshot = custom_result.traversal_snapshot;
  response.has_traversal_data = custom_result.has_traversal_data;
  response.initialized_default_miss = custom_result.initialized_default_miss;
  response.hit_geometry = custom_result.hit_geometry;
  const bool provider_payload_backend_input_missing =
      rtcore_custom_backend_result_missing_required_provider_payload_backend_input_snapshot(
          custom_result);
  const bool accepted_payload_missing =
      rtcore_custom_backend_result_accepted_payload_missing(custom_result);
  if (provider_payload_backend_input_missing) {
    response.provider_accepted = false;
    response.reject_reason =
        RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_PAYLOAD_BACKEND_INPUT_MISSING;
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "custom-rtcore-backend-provider-payload-input-missing, "
           "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
           "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
           "custom-rtcore-backend-provider-payload-input-missing=1, "
           "provider_supported=%u, provider_accepted=%u, reject_reason=%s, "
           "provider_payload_consumption_enabled=%u, "
           "has_provider_payload_backend_input_snapshot=%u, "
           "provider_payload_backend_input_snapshot_valid=%u\n",
           rtcore_traversal_source_provider_name(custom_result.provider),
           custom_result.context_ptr, custom_result.handoff_window_base,
           custom_result.lane_slot_index,
           custom_result.warp_metadata.warp_uid,
           custom_result.warp_metadata.active_mask,
           response.provider_supported ? 1 : 0,
           custom_result.accepted ? 1 : 0,
           rtcore_traversal_provider_reject_reason_name(
               response.reject_reason),
           custom_result.provider_payload_backend_input_snapshot
                   .provider_payload_consumption_enabled
               ? 1
               : 0,
           custom_result.has_provider_payload_backend_input_snapshot ? 1 : 0,
           custom_result.provider_payload_backend_input_snapshot.valid ? 1 : 0);
    fflush(stdout);
  } else if (accepted_payload_missing) {
    response.provider_accepted = false;
    response.reject_reason = RTCORE_TRAVERSAL_PROVIDER_REJECT_ACCEPTED_PAYLOAD_MISSING;
    printf("GPGPU-Sim PTX: RT_SUBMIT custom-rtcore-backend-payload-missing, "
           "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
           "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
           "custom-rtcore-backend-payload-missing=1, "
           "provider_supported=%u, provider_accepted=%u, reject_reason=%s, "
           "has_traversal_data=%u, initialized_default_miss=%u\n",
           rtcore_traversal_source_provider_name(custom_result.provider),
           custom_result.context_ptr, custom_result.handoff_window_base,
           custom_result.lane_slot_index,
           custom_result.warp_metadata.warp_uid,
           custom_result.warp_metadata.active_mask,
           response.provider_supported ? 1 : 0,
           custom_result.accepted ? 1 : 0,
           rtcore_traversal_provider_reject_reason_name(
               response.reject_reason),
           response.has_traversal_data ? 1 : 0,
           response.initialized_default_miss ? 1 : 0);
    fflush(stdout);
  }
  rtcore_apply_selected_root_descriptor_payload_route_consistency_policy(
      &response, custom_result);
  rtcore_annotate_provider_response_with_backend_input_snapshot_result(
      &response, custom_result);
  rtcore_log_provider_backend_input_consumption_route_record(custom_result,
                                                             response);
  const rtcore_provider_backend_input_response_annotation
      &backend_input_annotation =
          response.provider_backend_input_response_annotation;
  printf("GPGPU-Sim PTX: RT_SUBMIT custom-rtcore-backend-result-adapt, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "custom-rtcore-backend-result-adapted=1, "
         "provider_supported=%u, provider_accepted=%u, reject_reason=%s, "
         "provider_backend_input_response_annotation_valid=%u, "
         "backend_input_snapshot_required=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "has_traversal_data=%u, initialized_default_miss=%u, "
         "hit_geometry=%u, node_visits=%u, primitive_tests=%u\n",
         rtcore_traversal_source_provider_name(custom_result.provider),
         custom_result.context_ptr, custom_result.handoff_window_base,
         custom_result.lane_slot_index,
         custom_result.warp_metadata.warp_uid,
         custom_result.warp_metadata.active_mask,
         response.provider_supported ? 1 : 0,
         response.provider_accepted ? 1 : 0,
         rtcore_traversal_provider_reject_reason_name(
             response.reject_reason),
         backend_input_annotation.valid ? 1 : 0,
         backend_input_annotation.backend_input_snapshot_required ? 1 : 0,
         backend_input_annotation.provider_payload_backend_input_snapshot_accepted
             ? 1
             : 0,
         response.has_traversal_data ? 1 : 0,
         response.initialized_default_miss ? 1 : 0,
         response.hit_geometry ? 1 : 0,
         response.traversal_snapshot.rtcore_node_visits,
         response.traversal_snapshot.rtcore_primitive_tests);
  fflush(stdout);
  return response;
}

struct rtcore_traversal_source_snapshot {
  rtcore_traversal_source_snapshot()
      : provider(RTCORE_TRAVERSAL_SOURCE_PROVIDER_LEGACY_FUNCTIONAL),
        provider_supported(true),
        provider_accepted(true),
        reject_reason(RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE),
        registry_payload_source_snapshot_annotation(),
        provider_backend_input_source_snapshot_annotation(),
        registry_payload_consumption_admission(),
        has_traversal_data(false),
        initialized_default_miss(false),
        hit_geometry(false) {
    memset(&traversal_snapshot, 0, sizeof(traversal_snapshot));
  }

  rtcore_traversal_source_provider provider;
  bool provider_supported;
  bool provider_accepted;
  rtcore_traversal_provider_reject_reason reject_reason;
  rtcore_traversal_source_registry_payload_annotation
      registry_payload_source_snapshot_annotation;
  rtcore_traversal_source_provider_backend_input_annotation
      provider_backend_input_source_snapshot_annotation;
  rtcore_registry_payload_consumption_admission_decision
      registry_payload_consumption_admission;
  Traversal_data traversal_snapshot;
  bool has_traversal_data;
  bool initialized_default_miss;
  bool hit_geometry;
};

static rtcore_traversal_provider_response
rtcore_make_legacy_functional_traversal_provider_response(
    const rtcore_traversal_source_request &request) {
  const ptx_instruction *pI = request.pI;
  ptx_thread_info *thread = request.thread;
  rtcore_traversal_provider_response response;
  response.provider = request.provider;
  response.provider_supported = true;
  response.provider_accepted = true;
  response.reject_reason = RTCORE_TRAVERSAL_PROVIDER_REJECT_NONE;
  memory_space *mem = thread->get_global_memory();
  response.has_traversal_data =
      !thread->RT_thread_data->traversal_data.empty();
  if (response.has_traversal_data) {
    Traversal_data *device_traversal_data =
        thread->RT_thread_data->traversal_data.back();
    mem->read((mem_addr_t)device_traversal_data,
              sizeof(response.traversal_snapshot),
              &response.traversal_snapshot);
    response.hit_geometry = response.traversal_snapshot.hit_geometry;
  } else {
    response.traversal_snapshot.hit_geometry = false;
    response.traversal_snapshot.current_shader_counter = -1;
    response.traversal_snapshot.current_shader_type = -1;
    response.traversal_snapshot.missIndex = 0;

    Traversal_data *device_traversal_data =
        (Traversal_data *)VulkanRayTracing::gpgpusim_alloc(
            sizeof(Traversal_data));
    mem->write((mem_addr_t)device_traversal_data, sizeof(Traversal_data),
               &response.traversal_snapshot, thread, pI);
    thread->RT_thread_data->all_hit_data.clear();
    thread->RT_thread_data->traversal_data.push_back(device_traversal_data);
    response.initialized_default_miss = true;
    response.hit_geometry = response.traversal_snapshot.hit_geometry;
  }
  return response;
}

