static rtcore_traversal_provider_response
rtcore_make_custom_rtcore_existing_traversal_backend_response(
    const rtcore_traversal_work_descriptor &descriptor,
    const rtcore_traversal_source_request &request) {
  rtcore_traversal_source_request effective_request = request;
  if (descriptor.provider_payload_consumption_enabled &&
      !rtcore_try_build_existing_traversal_replay_request_from_provider_backend_input(
          &effective_request, request, descriptor)) {
    return rtcore_make_custom_rtcore_existing_traversal_replay_missing_response(
        descriptor, "provider_backend_input_snapshot_replay_request_missing");
  }
  const bool existing_traversal_input_replay_requested =
      effective_request.from_provider_backend_input_snapshot;
  bool existing_traversal_request_replay_live_input_match =
      !existing_traversal_input_replay_requested;
  if (existing_traversal_input_replay_requested &&
      !effective_request.replay_selected_root_descriptor_policy_passed) {
    return rtcore_make_custom_rtcore_existing_traversal_selected_descriptor_pre_traversal_rejected_response(
        descriptor, effective_request);
  }
  const bool selected_root_field_policy_failed =
      existing_traversal_input_replay_requested &&
      !effective_request.replay_selected_root_descriptor_root_field_consistency_policy_passed;
  if (selected_root_field_policy_failed) {
    return rtcore_make_custom_rtcore_existing_traversal_selected_descriptor_root_field_pre_traversal_rejected_response(
        descriptor, effective_request);
  }
  bool producer_root_descriptor_traversal_authority_consumes_backend_input =
      false;
  const rtcore_producer_root_descriptor_traversal_authority_policy
      producer_root_descriptor_traversal_authority_policy =
          rtcore_make_producer_root_descriptor_traversal_authority_policy();
  if (producer_root_descriptor_traversal_authority_policy.requested) {
    if (!rtcore_producer_root_descriptor_traversal_authority_request_ready(
            effective_request)) {
      return rtcore_make_custom_rtcore_existing_traversal_producer_root_authority_pre_traversal_rejected_response(
          descriptor, effective_request,
          producer_root_descriptor_traversal_authority_policy);
    }
    effective_request.replay_bridge_trace_replay_top_level_as =
        effective_request.replay_root_metadata_handle;
    if (!rtcore_materialize_existing_traversal_input_from_producer_root_descriptor(
            descriptor, effective_request,
            producer_root_descriptor_traversal_authority_policy)) {
      return rtcore_make_custom_rtcore_existing_traversal_replay_missing_response(
          descriptor,
          "producer_root_descriptor_traversal_input_materialization_failed");
    }
    producer_root_descriptor_traversal_authority_consumes_backend_input = true;
  }
  rtcore_traversal_provider_response existing_response =
      rtcore_make_legacy_functional_traversal_provider_response(effective_request);
  if (existing_traversal_input_replay_requested) {
    const rtcore_existing_traversal_replay_input_match_record match_record =
        rtcore_make_existing_traversal_replay_input_match_record(
            effective_request, existing_response);
    rtcore_log_existing_traversal_replay_input_match_record(descriptor,
                                                           match_record);
    existing_traversal_request_replay_live_input_match =
        match_record.all_fields_match;
    printf("GPGPU-Sim PTX: RT_SUBMIT "
           "custom-rtcore-backend-existing-traversal-input-replay-check, "
           "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
           "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
           "existing_traversal_request_replay_live_input_match=%u, "
           "existing_traversal_replay_backend_input_source_snapshot=%s, "
           "existing_traversal_replay_actual_abi_source_snapshot_admitted=%u, "
           "existing_traversal_replay_actual_abi_source_snapshot_consumed_by_existing_traversal=%u, "
           "existing_traversal_replay_actual_abi_source_snapshot_block_reason=%s, "
           "existing_traversal_input_replay_source=provider_backend_input_snapshot\n",
           rtcore_traversal_source_provider_name(descriptor.provider),
           descriptor.context_ptr, descriptor.handoff_window_base,
           descriptor.lane_slot_index, descriptor.warp_metadata.warp_uid,
           descriptor.warp_metadata.active_mask,
           existing_traversal_request_replay_live_input_match ? 1 : 0,
           match_record.backend_input_source_snapshot,
           match_record.actual_abi_source_snapshot_admitted ? 1 : 0,
           match_record.actual_abi_source_snapshot_consumed_by_existing_traversal
               ? 1
               : 0,
           match_record.actual_abi_source_snapshot_block_reason);
    fflush(stdout);
    if (!existing_traversal_request_replay_live_input_match) {
      return rtcore_make_custom_rtcore_existing_traversal_replay_missing_response(
          descriptor, "provider_backend_input_snapshot_live_input_mismatch");
    }
  }
  rtcore_custom_backend_result custom_result =
      rtcore_make_custom_rtcore_existing_traversal_backend_result(
          descriptor, existing_response,
          producer_root_descriptor_traversal_authority_consumes_backend_input);
  custom_result.existing_traversal_input_replay_requested =
      existing_traversal_input_replay_requested;
  custom_result.existing_traversal_request_replay_live_input_match =
      existing_traversal_request_replay_live_input_match;
  return rtcore_make_provider_response_from_custom_rtcore_backend_result(
      custom_result);
}

