static bool
rtcore_provider_decoded_abi_authority_owner_lifetime_blocked_fault_enabled();
static bool rtcore_provider_decoded_abi_authority_fault_enabled();
static const char *rtcore_provider_decoded_abi_authority_fault_name();

static void
rtcore_annotate_provider_response_with_registry_payload_observation(
    rtcore_traversal_provider_response *response,
    const rtcore_traversal_work_descriptor &descriptor);

static bool rtcore_provider_decoded_abi_authority_rejection_required(
    const rtcore_traversal_work_descriptor &descriptor) {
  if (!rtcore_provider_decoded_abi_authority_fault_enabled()) {
    return false;
  }
  if (!descriptor.has_registry_payload_shadow) {
    return false;
  }
  return !descriptor.provider_payload_consumption_enabled;
}

static rtcore_traversal_provider_response
rtcore_make_provider_decoded_abi_authority_rejected_response(
    const rtcore_traversal_work_descriptor &descriptor) {
  rtcore_traversal_provider_response response;
  response.provider = descriptor.provider;
  response.provider_supported = true;
  response.provider_accepted = false;
  response.reject_reason =
      RTCORE_TRAVERSAL_PROVIDER_REJECT_PROVIDER_DECODED_ABI_AUTHORITY;
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-decoded-abi-authority-readiness-negative=1, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "provider_decoded_abi_authority_rejected=1, "
         "provider_backend_dispatch_skipped=1, "
         "provider_payload_consumption_enabled=%u, "
         "provider_consumed_input_fields_all_owned_with_lifetime=%u, "
         "fault=%s, provider_decoded_abi_authority_fault_kind=%s, "
         "reject_reason=%s, "
         "provider_decoded_abi_authority_rejection_consumes_traversal_behavior=0\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index, descriptor.warp_metadata.warp_uid,
         descriptor.warp_metadata.active_mask,
         descriptor.provider_payload_consumption_enabled ? 1 : 0,
         descriptor.provider_payload_consumed_input
                 .provider_consumed_input_fields_all_owned_with_lifetime
             ? 1
             : 0,
         rtcore_provider_decoded_abi_authority_fault_name(),
         rtcore_provider_decoded_abi_authority_fault_name(),
         rtcore_traversal_provider_reject_reason_name(response.reject_reason));
  fflush(stdout);
  return response;
}

static rtcore_traversal_provider_response
rtcore_invoke_rtcore_provider_bridge(
    const rtcore_traversal_work_descriptor &descriptor,
    const rtcore_traversal_source_request *request) {
  printf("GPGPU-Sim PTX: RT_SUBMIT rtcore-provider-bridge-invoke, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "descriptor_valid=%u, registry_payload_shadow_attached=%u, "
         "provider_decoded_input_observation_attached=%u, "
         "provider_decoded_input_observed=%u, "
         "provider_payload_consumption_enabled=%u, "
         "rtcore-provider-bridge-invoked=1\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index, descriptor.warp_metadata.warp_uid,
         descriptor.warp_metadata.active_mask, descriptor.valid ? 1 : 0,
         descriptor.has_registry_payload_shadow ? 1 : 0,
         descriptor.has_provider_decoded_input_observation ? 1 : 0,
         descriptor.provider_decoded_input_observation.valid ? 1 : 0,
         descriptor.provider_payload_consumption_enabled ? 1 : 0);
  fflush(stdout);
  rtcore_log_provider_facing_registry_payload_admission_mirror(descriptor);
  rtcore_log_provider_payload_consumption_eligibility_shadow(descriptor);
  rtcore_log_provider_payload_consumption_preflight_record(descriptor);
  rtcore_log_compiler_driver_runtime_consumption_readiness_record(descriptor);
  rtcore_log_provider_decoded_input_observation(descriptor);
  rtcore_log_provider_payload_consumed_input_view(descriptor);
  rtcore_log_provider_side_registry_payload_shadow_diagnostic_read(descriptor);

  if (rtcore_provider_decoded_abi_authority_rejection_required(descriptor)) {
    return rtcore_make_provider_decoded_abi_authority_rejected_response(
        descriptor);
  }

  rtcore_traversal_provider_response response;
  switch (descriptor.provider) {
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_STUB:
      response =
          rtcore_make_rtcore_stub_traversal_provider_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_REJECT:
      response =
          rtcore_make_rtcore_reject_traversal_provider_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_EMPTY:
      response =
          rtcore_make_rtcore_empty_traversal_provider_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_DEFAULT_MISS:
      response = rtcore_make_rtcore_default_miss_traversal_provider_response(
          descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_STATS_MISS:
      response =
          rtcore_make_rtcore_stats_miss_traversal_provider_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_LANE_STATS_MISS:
      response = rtcore_make_rtcore_lane_stats_miss_traversal_provider_response(
          descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_STUB:
      response = rtcore_invoke_custom_rtcore_backend_stub(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EMPTY:
      response = rtcore_make_custom_rtcore_empty_backend_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_DEFAULT_MISS:
      response =
          rtcore_make_custom_rtcore_default_miss_backend_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_STATS_MISS:
      response =
          rtcore_make_custom_rtcore_stats_miss_backend_response(descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_LANE_STATS_MISS:
      response = rtcore_make_custom_rtcore_lane_stats_miss_backend_response(
          descriptor);
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EXISTING_TRAVERSAL:
      if (request != NULL) {
        response = rtcore_make_custom_rtcore_existing_traversal_backend_response(
            descriptor, *request);
      } else {
        response.provider = descriptor.provider;
        response.provider_supported = true;
        response.provider_accepted = false;
        response.reject_reason =
            RTCORE_TRAVERSAL_PROVIDER_REJECT_WORK_DESCRIPTOR_REJECTED;
      }
      break;
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_LEGACY_FUNCTIONAL:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_UNSUPPORTED:
    default:
      response.provider = descriptor.provider;
      response.provider_supported = false;
      response.provider_accepted = false;
      response.reject_reason = RTCORE_TRAVERSAL_PROVIDER_REJECT_UNSUPPORTED;
      break;
  }

  rtcore_annotate_provider_response_with_registry_payload_observation(
      &response, descriptor);
  const unsigned registry_payload_response_annotation_valid =
      response.registry_payload_response_annotation.valid ? 1 : 0;
  const unsigned registry_payload_shadow_observed =
      response.registry_payload_response_annotation.observed_valid_shadow ? 1 : 0;
  const unsigned provider_payload_consumption_enabled =
      response.registry_payload_response_annotation
              .provider_payload_consumption_enabled
          ? 1
          : 0;

  printf("GPGPU-Sim PTX: RT_SUBMIT rtcore-provider-bridge-response, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, warp_uid=%u, active_mask=0x%08x, "
         "rtcore-provider-bridge-responded=1, "
         "provider_supported=%u, provider_accepted=%u, reject_reason=%s, "
         "has_traversal_data=%u, initialized_default_miss=%u, "
         "hit_geometry=%u, registry_payload_response_annotation_valid=%u, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_consumption_enabled=%u\n",
         rtcore_traversal_source_provider_name(response.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index, descriptor.warp_metadata.warp_uid,
         descriptor.warp_metadata.active_mask, response.provider_supported ? 1 : 0,
         response.provider_accepted ? 1 : 0,
         rtcore_traversal_provider_reject_reason_name(response.reject_reason),
         response.has_traversal_data ? 1 : 0,
         response.initialized_default_miss ? 1 : 0,
         response.hit_geometry ? 1 : 0,
         registry_payload_response_annotation_valid,
         registry_payload_shadow_observed, provider_payload_consumption_enabled);
  fflush(stdout);
  return response;
}

static rtcore_traversal_provider_response
rtcore_invoke_rtcore_provider_bridge(
    const rtcore_traversal_work_descriptor &descriptor) {
  return rtcore_invoke_rtcore_provider_bridge(descriptor, NULL);
}

static void
rtcore_copy_registry_payload_response_annotation_to_source_snapshot(
    rtcore_traversal_source_snapshot *snapshot,
    const rtcore_traversal_provider_response &response) {
  if (snapshot == NULL ||
      !response.registry_payload_response_annotation.valid) {
    return;
  }

  const rtcore_registry_payload_response_annotation &response_annotation =
      response.registry_payload_response_annotation;
  snapshot->registry_payload_source_snapshot_annotation.valid = true;
  snapshot->registry_payload_source_snapshot_annotation.observed_valid_shadow =
      response_annotation.observed_valid_shadow;
  snapshot->registry_payload_source_snapshot_annotation
          .provider_payload_consumption_enabled =
      response_annotation.provider_payload_consumption_enabled;
  snapshot->registry_payload_source_snapshot_annotation
          .has_ray_origin_direction_tmin_tmax =
      response_annotation.has_ray_origin_direction_tmin_tmax;
  snapshot->registry_payload_source_snapshot_annotation.has_ray_flags_cull_mask =
      response_annotation.has_ray_flags_cull_mask;
  snapshot->registry_payload_source_snapshot_annotation
          .has_launch_context_input =
      response_annotation.has_launch_context_input;
  snapshot->registry_payload_source_snapshot_annotation
          .has_traversable_root_proxy =
      response_annotation.has_traversable_root_proxy;
  snapshot->registry_payload_source_snapshot_annotation.has_bvh_format_profile =
      response_annotation.has_bvh_format_profile;
  snapshot->registry_payload_source_snapshot_annotation.bvh_format_version =
      response_annotation.bvh_format_version;

  const rtcore_traversal_source_registry_payload_annotation &annotation =
      snapshot->registry_payload_source_snapshot_annotation;
  const unsigned registry_payload_shadow_observed =
      annotation.observed_valid_shadow ? 1 : 0;
  const unsigned provider_payload_consumption_enabled =
      annotation.provider_payload_consumption_enabled ? 1 : 0;
  const unsigned has_ray_origin_direction_tmin_tmax =
      annotation.has_ray_origin_direction_tmin_tmax ? 1 : 0;
  const unsigned has_ray_flags_cull_mask =
      annotation.has_ray_flags_cull_mask ? 1 : 0;
  const unsigned has_launch_context_input =
      annotation.has_launch_context_input ? 1 : 0;
  const unsigned has_traversable_root_proxy =
      annotation.has_traversable_root_proxy ? 1 : 0;
  const unsigned has_bvh_format_profile =
      annotation.has_bvh_format_profile ? 1 : 0;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "traversal-source-registry-payload-annotation, provider=%s, "
         "traversal-source-registry-payload-annotation=1, "
         "registry_payload_source_snapshot_annotation_valid=1, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_consumption_enabled=%u, "
         "source_snapshot_annotation_consumes_traversal_behavior=0, "
         "has_ray_origin_direction_tmin_tmax=%u, has_ray_flags_cull_mask=%u, "
         "has_launch_context_input=%u, has_traversable_root_proxy=%u, "
         "has_bvh_format_profile=%u, bvh_format_version=%u\n",
         rtcore_traversal_source_provider_name(response.provider),
         registry_payload_shadow_observed, provider_payload_consumption_enabled,
         has_ray_origin_direction_tmin_tmax, has_ray_flags_cull_mask,
         has_launch_context_input, has_traversable_root_proxy,
         has_bvh_format_profile,
         annotation.bvh_format_version);
  fflush(stdout);
}

static void
rtcore_copy_provider_backend_input_response_annotation_to_source_snapshot(
    rtcore_traversal_source_snapshot *snapshot,
    const rtcore_traversal_provider_response &response) {
  if (snapshot == NULL ||
      !response.provider_backend_input_response_annotation.valid) {
    return;
  }

  const rtcore_provider_backend_input_response_annotation &response_annotation =
      response.provider_backend_input_response_annotation;
  rtcore_traversal_source_provider_backend_input_annotation &annotation =
      snapshot->provider_backend_input_source_snapshot_annotation;
  annotation.valid = true;
  annotation.provider_payload_consumption_enabled =
      response_annotation.provider_payload_consumption_enabled;
  annotation.backend_input_snapshot_required =
      response_annotation.backend_input_snapshot_required;
  annotation.has_provider_payload_backend_input_snapshot =
      response_annotation.has_provider_payload_backend_input_snapshot;
  annotation.provider_payload_backend_input_snapshot_valid =
      response_annotation.provider_payload_backend_input_snapshot_valid;
  annotation.provider_payload_backend_input_snapshot_accepted =
      response_annotation.provider_payload_backend_input_snapshot_accepted;
  annotation.has_provider_materialized_traversal_input_snapshot =
      response_annotation.has_provider_materialized_traversal_input_snapshot;
  annotation.provider_materialized_traversal_input_snapshot_valid =
      response_annotation.provider_materialized_traversal_input_snapshot_valid;
  annotation.provider_materialized_traversal_input_snapshot_source =
      response_annotation.provider_materialized_traversal_input_snapshot_source;
  annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      response_annotation
          .provider_materialized_traversal_input_actual_abi_snapshot_admitted;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "traversal-source-provider-backend-input-annotation, provider=%s, "
         "traversal-source-provider-backend-input-annotation=1, "
         "provider_backend_input_source_snapshot_annotation_valid=1, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_source_snapshot_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "source_snapshot_backend_input_annotation_consumes_traversal_behavior=0\n",
         rtcore_traversal_source_provider_name(response.provider),
         annotation.provider_payload_consumption_enabled ? 1 : 0,
         annotation.backend_input_snapshot_required ? 1 : 0,
         annotation.has_provider_payload_backend_input_snapshot ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_valid ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_accepted ? 1 : 0,
         annotation.has_provider_materialized_traversal_input_snapshot ? 1 : 0,
         annotation.provider_materialized_traversal_input_snapshot_valid ? 1
                                                                         : 0,
         annotation.provider_materialized_traversal_input_snapshot_source,
         annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
}

static void
rtcore_apply_source_snapshot_registry_payload_consumption_admission_gate(
    rtcore_traversal_source_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }

  const rtcore_traversal_source_registry_payload_annotation &annotation =
      snapshot->registry_payload_source_snapshot_annotation;
  rtcore_registry_payload_consumption_admission_decision admission;
  admission.valid = true;
  admission.annotation_valid = annotation.valid;
  admission.observed_valid_shadow =
      annotation.valid && annotation.observed_valid_shadow;
  admission.provider_payload_consumption_enabled =
      annotation.valid && annotation.provider_payload_consumption_enabled;
  admission.has_ray_origin_direction_tmin_tmax =
      annotation.valid && annotation.has_ray_origin_direction_tmin_tmax;
  admission.has_ray_flags_cull_mask =
      annotation.valid && annotation.has_ray_flags_cull_mask;
  admission.has_launch_context_input =
      annotation.valid && annotation.has_launch_context_input;
  admission.has_traversable_root_proxy =
      annotation.valid && annotation.has_traversable_root_proxy;
  admission.has_bvh_format_profile =
      annotation.valid && annotation.has_bvh_format_profile;
  admission.bvh_format_version =
      annotation.valid ? annotation.bvh_format_version : 0;
  admission.admission_allowed =
      rtcore_registry_payload_consumption_admission_policy_allows(
          "source-snapshot");
  admission.default_deny =
      rtcore_registry_payload_consumption_admission_policy_default_deny();
  snapshot->registry_payload_consumption_admission = admission;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "source-snapshot-registry-payload-consumption-admission=1, "
         "provider=%s, "
         "registry_payload_consumption_admission_valid=%u, "
         "registry_payload_consumption_admission_allowed=%u, "
         "registry_payload_consumption_admission_default_deny=%u, "
         "registry_payload_admission_policy_opt_in_source=%s, "
         "registry_payload_admission_policy_opt_in_enabled=%u, "
         "registry_payload_source_snapshot_annotation_valid=%u, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_consumption_enabled=%u, "
         "source_snapshot_admission_consumes_traversal_behavior=0, "
         "has_ray_origin_direction_tmin_tmax=%u, has_ray_flags_cull_mask=%u, "
         "has_launch_context_input=%u, has_traversable_root_proxy=%u, "
         "has_bvh_format_profile=%u, bvh_format_version=%u\n",
         rtcore_traversal_source_provider_name(snapshot->provider),
         admission.valid ? 1 : 0, admission.admission_allowed ? 1 : 0,
         admission.default_deny ? 1 : 0,
         rtcore_registry_payload_consumption_admission_policy_opt_in_source(),
         admission.admission_allowed ? 1 : 0,
         admission.annotation_valid ? 1 : 0,
         admission.observed_valid_shadow ? 1 : 0,
         admission.provider_payload_consumption_enabled ? 1 : 0,
         admission.has_ray_origin_direction_tmin_tmax ? 1 : 0,
         admission.has_ray_flags_cull_mask ? 1 : 0,
         admission.has_launch_context_input ? 1 : 0,
         admission.has_traversable_root_proxy ? 1 : 0,
         admission.has_bvh_format_profile ? 1 : 0,
         admission.bvh_format_version);
  fflush(stdout);
}

static rtcore_traversal_source_snapshot
rtcore_make_traversal_source_snapshot_from_provider_response(
    const rtcore_traversal_provider_response &response) {
  rtcore_traversal_source_snapshot snapshot;
  snapshot.provider = response.provider;
  snapshot.provider_supported = response.provider_supported;
  snapshot.provider_accepted = response.provider_accepted;
  snapshot.reject_reason = response.reject_reason;
  snapshot.traversal_snapshot = response.traversal_snapshot;
  snapshot.has_traversal_data = response.has_traversal_data;
  snapshot.initialized_default_miss = response.initialized_default_miss;
  snapshot.hit_geometry = response.hit_geometry;
  rtcore_copy_registry_payload_response_annotation_to_source_snapshot(
      &snapshot, response);
  rtcore_copy_provider_backend_input_response_annotation_to_source_snapshot(
      &snapshot, response);
  rtcore_apply_source_snapshot_registry_payload_consumption_admission_gate(
      &snapshot);
  return snapshot;
}

static rtcore_traversal_provider_response
rtcore_make_unsupported_traversal_provider_response(
    const rtcore_traversal_source_request &request) {
  rtcore_traversal_provider_response response;
  response.provider = request.provider;
  response.provider_supported = false;
  response.provider_accepted = false;
  response.reject_reason = RTCORE_TRAVERSAL_PROVIDER_REJECT_UNSUPPORTED;
  return response;
}

static rtcore_traversal_provider_response
rtcore_make_traversal_provider_response(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow,
    const rtcore_provider_decoded_input_observation
        *provider_decoded_input_observation) {
  switch (request.provider) {
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_LEGACY_FUNCTIONAL:
      return rtcore_make_legacy_functional_traversal_provider_response(request);
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EXISTING_TRAVERSAL: {
      rtcore_traversal_work_descriptor descriptor =
          rtcore_make_traversal_work_descriptor(
              request, registry_payload_shadow,
              provider_decoded_input_observation);
      return rtcore_invoke_rtcore_provider_bridge(descriptor, &request);
    }
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_STUB:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_REJECT:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_EMPTY:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_DEFAULT_MISS:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_STATS_MISS:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_LANE_STATS_MISS:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_STUB:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EMPTY:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_DEFAULT_MISS:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_STATS_MISS:
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_LANE_STATS_MISS: {
      rtcore_traversal_work_descriptor descriptor =
          rtcore_make_traversal_work_descriptor(
              request, registry_payload_shadow,
              provider_decoded_input_observation);
      return rtcore_invoke_rtcore_provider_bridge(descriptor);
    }
    case RTCORE_TRAVERSAL_SOURCE_PROVIDER_UNSUPPORTED:
    default:
      return rtcore_make_unsupported_traversal_provider_response(request);
  }
}

static rtcore_traversal_provider_response
rtcore_make_traversal_provider_response(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow) {
  return rtcore_make_traversal_provider_response(request, registry_payload_shadow,
                                                NULL);
}

static rtcore_traversal_provider_response
rtcore_make_traversal_provider_response(
    const rtcore_traversal_source_request &request) {
  return rtcore_make_traversal_provider_response(request, NULL);
}

static rtcore_traversal_source_snapshot
rtcore_make_traversal_source_snapshot(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow,
    const rtcore_provider_decoded_input_observation
        *provider_decoded_input_observation) {
  rtcore_traversal_provider_response response =
      rtcore_make_traversal_provider_response(
          request, registry_payload_shadow, provider_decoded_input_observation);
  return rtcore_make_traversal_source_snapshot_from_provider_response(response);
}

static rtcore_traversal_source_snapshot
rtcore_make_traversal_source_snapshot(
    const rtcore_traversal_source_request &request,
    const rtcore_provider_facing_registry_payload_shadow *registry_payload_shadow) {
  return rtcore_make_traversal_source_snapshot(request, registry_payload_shadow,
                                              NULL);
}

static rtcore_traversal_source_snapshot
rtcore_make_traversal_source_snapshot(
    const rtcore_traversal_source_request &request) {
  return rtcore_make_traversal_source_snapshot(request, NULL);
}

static bool rtcore_traversal_source_snapshot_has_accepted_payload(
    const rtcore_traversal_source_snapshot &snapshot) {
  return !snapshot.provider_accepted || snapshot.has_traversal_data ||
         snapshot.initialized_default_miss;
}

struct rtcore_context_window_owner_seq_snapshot {
  rtcore_context_window_owner_seq_snapshot()
      : valid(false),
        context_ptr(0),
        handoff_window_base(0),
        lane_slot_index(0),
        window_generation(0),
        completion_seq_low(0),
        resume_seq_low(0),
        window_tag(0) {}

  bool valid;
  unsigned long long context_ptr;
  unsigned long long handoff_window_base;
  unsigned lane_slot_index;
  ptx_thread_info::rtcore_current_warp_metadata warp_metadata;
  unsigned window_generation;
  unsigned completion_seq_low;
  unsigned resume_seq_low;
  unsigned window_tag;
};

static rtcore_context_window_owner_seq_snapshot
rtcore_make_context_window_owner_seq_snapshot(
    unsigned long long context_ptr, unsigned long long handoff_window_base,
    unsigned lane_slot_index,
    const ptx_thread_info::rtcore_current_warp_metadata &warp_metadata,
    unsigned window_generation, unsigned completion_seq_low,
    unsigned resume_seq_low, unsigned window_tag) {
  rtcore_context_window_owner_seq_snapshot snapshot;
  snapshot.valid = warp_metadata.valid;
  snapshot.context_ptr = context_ptr;
  snapshot.handoff_window_base = handoff_window_base;
  snapshot.lane_slot_index = lane_slot_index;
  snapshot.warp_metadata = warp_metadata;
  snapshot.window_generation = window_generation;
  snapshot.completion_seq_low = completion_seq_low;
  snapshot.resume_seq_low = resume_seq_low;
  snapshot.window_tag = window_tag;
  return snapshot;
}

