static const char *
rtcore_driver_runtime_context_window_lifetime_bridge_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_CONTEXT_WINDOW_LIFETIME_BRIDGE_FAILPOINT";
}

static const char *
rtcore_driver_runtime_context_window_lifetime_bridge_failpoint_name() {
  const char *value = getenv(
      rtcore_driver_runtime_context_window_lifetime_bridge_failpoint_env_name());
  if (value == NULL || value[0] == '\0' ||
      rtcore_path_mode_is(value, "none") ||
      rtcore_rt_env_value_is_explicit_false(value)) {
    return "none";
  }
  if (rtcore_path_mode_is(value, "wrong_owner_sequence") ||
      rtcore_path_mode_is(value, "owner_seq_mismatch")) {
    return "wrong_owner_sequence";
  }
  if (rtcore_path_mode_is(value, "wrong_lane_slot") ||
      rtcore_path_mode_is(value, "lane_slot_mismatch")) {
    return "wrong_lane_slot";
  }
  if (rtcore_path_mode_is(value, "stale_token_lifetime") ||
      rtcore_path_mode_is(value, "stale_token")) {
    return "stale_token_lifetime";
  }
  if (rtcore_path_mode_is(value, "wrong_owner_generation") ||
      rtcore_path_mode_is(value, "owner_generation_mismatch")) {
    return "wrong_owner_generation";
  }
  if (rtcore_path_mode_is(value, "missing_lifetime_record") ||
      rtcore_rt_env_value_is_explicit_true(value)) {
    return "missing_lifetime_record";
  }
  return "unsupported";
}

static void
rtcore_refresh_driver_runtime_context_window_lifetime_bridge_ready(
    rtcore_driver_runtime_context_window_lifetime_bridge_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->driver_runtime_context_window_lifetime_ready =
      snapshot->valid && snapshot->runtime_allocation_record_valid &&
      snapshot->lifetime_table_found &&
      snapshot->context_window_owner_seq_valid &&
      snapshot->context_window_owner_seq_matches_lifetime &&
      snapshot->lane_slot_matches && snapshot->active_lane_observed &&
      snapshot->owner_generation_matches && snapshot->token_lifetime_key_ready &&
      snapshot->retire_release_policy_ready;
  snapshot->provider_lifetime_ready =
      snapshot->driver_runtime_context_window_lifetime_ready;
  snapshot->provider_payload_runtime_lifetime_ready =
      snapshot->provider_lifetime_ready;
  snapshot->reject_reason =
      snapshot->provider_lifetime_ready
          ? "none"
          : "DRIVER_RUNTIME_CONTEXT_WINDOW_LIFETIME_BRIDGE_NOT_READY";
}

static rtcore_driver_runtime_context_window_lifetime_bridge_snapshot
rtcore_make_driver_runtime_context_window_lifetime_bridge_snapshot(
    const rtcore_runtime_context_window_allocation_record &allocation_record,
    const rtcore_launch_allocation_lifetime_record *lifetime_record,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot,
    const rtcore_symbolic_rt_token_key &token_key) {
  rtcore_driver_runtime_context_window_lifetime_bridge_snapshot snapshot;
  snapshot.valid = allocation_record.enabled;
  snapshot.runtime_allocation_record_valid =
      allocation_record.enabled && allocation_record.valid;
  snapshot.lifetime_table_found =
      lifetime_record != NULL && lifetime_record->valid;
  snapshot.context_window_owner_seq_valid = owner_seq_snapshot.valid;
  snapshot.context_ptr = allocation_record.context_ptr;
  snapshot.handoff_window_base = allocation_record.handoff_window_base;
  snapshot.context_base = allocation_record.context_base;
  snapshot.handoff_base = allocation_record.handoff_base;
  snapshot.context_window_index = allocation_record.context_window_index;
  snapshot.handoff_window_index = allocation_record.handoff_window_index;
  snapshot.lane_slot_index = allocation_record.lane_slot_index;
  snapshot.capacity_lane_slots = allocation_record.capacity_lane_slots;
  snapshot.owner_generation = allocation_record.owner_generation;
  snapshot.window_generation = owner_seq_snapshot.window_generation;
  snapshot.completion_seq_low = owner_seq_snapshot.completion_seq_low;
  snapshot.resume_seq_low = owner_seq_snapshot.resume_seq_low;
  snapshot.window_tag = owner_seq_snapshot.window_tag;
  snapshot.token_owner_hw_sid = token_key.owner_hw_sid;
  snapshot.token_owner_hw_wid = token_key.owner_hw_wid;
  snapshot.token_owner_hw_tid = token_key.owner_hw_tid;
  snapshot.token_lane_slot_index = token_key.lane_slot_index;
  snapshot.active_lane_mask =
      lifetime_record != NULL ? lifetime_record->active_lane_mask : 0;
  snapshot.retire_free_policy = allocation_record.retire_free_policy;

  snapshot.context_window_owner_seq_matches_lifetime =
      snapshot.context_window_owner_seq_valid && snapshot.lifetime_table_found &&
      owner_seq_snapshot.context_ptr == allocation_record.context_ptr &&
      owner_seq_snapshot.handoff_window_base ==
          allocation_record.handoff_window_base &&
      owner_seq_snapshot.lane_slot_index == allocation_record.lane_slot_index &&
      lifetime_record->context_base == allocation_record.context_base &&
      lifetime_record->handoff_base == allocation_record.handoff_base &&
      lifetime_record->context_window_index ==
          allocation_record.context_window_index &&
      lifetime_record->handoff_window_index ==
          allocation_record.handoff_window_index;
  snapshot.lane_slot_matches =
      owner_seq_snapshot.lane_slot_index == allocation_record.lane_slot_index &&
      token_key.lane_slot_index == allocation_record.lane_slot_index;
  snapshot.active_lane_observed =
      lifetime_record != NULL &&
      allocation_record.lane_slot_index < RTCORE_MAX_LANES_PER_WARP &&
      (lifetime_record->active_lane_mask &
       rtcore_lane_thread_mask(allocation_record.lane_slot_index)) != 0;
  snapshot.owner_generation_matches =
      lifetime_record != NULL &&
      lifetime_record->owner_generation == allocation_record.owner_generation;
  snapshot.token_lifetime_key_ready =
      token_key.context_ptr == allocation_record.context_ptr &&
      token_key.handoff_window_base == allocation_record.handoff_window_base &&
      token_key.owner_hw_sid == owner_seq_snapshot.warp_metadata.owner_hw_sid &&
      token_key.lane_slot_index == allocation_record.lane_slot_index;
  snapshot.retire_release_policy_ready =
      lifetime_record != NULL && allocation_record.retire_free_policy != NULL &&
      lifetime_record->retire_free_policy != NULL &&
      strcmp(lifetime_record->retire_free_policy,
             allocation_record.retire_free_policy) == 0;

  snapshot.failpoint =
      rtcore_driver_runtime_context_window_lifetime_bridge_failpoint_name();
  if (strcmp(snapshot.failpoint, "wrong_owner_sequence") == 0) {
    snapshot.context_window_owner_seq_matches_lifetime = false;
  } else if (strcmp(snapshot.failpoint, "wrong_lane_slot") == 0) {
    snapshot.lane_slot_matches = false;
  } else if (strcmp(snapshot.failpoint, "stale_token_lifetime") == 0) {
    snapshot.token_lifetime_key_ready = false;
  } else if (strcmp(snapshot.failpoint, "wrong_owner_generation") == 0) {
    snapshot.owner_generation_matches = false;
  } else if (strcmp(snapshot.failpoint, "missing_lifetime_record") == 0) {
    snapshot.lifetime_table_found = false;
  } else if (strcmp(snapshot.failpoint, "unsupported") == 0) {
    snapshot.valid = false;
  }

  rtcore_refresh_driver_runtime_context_window_lifetime_bridge_ready(
      &snapshot);
  return snapshot;
}

static void rtcore_log_driver_runtime_context_window_lifetime_bridge_snapshot(
    const ptx_instruction *pI,
    const rtcore_driver_runtime_context_window_lifetime_bridge_snapshot
        &snapshot) {
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "driver-runtime-context-window-lifetime-bridge=1, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, "
         "driver_runtime_context_window_lifetime_bridge_valid=%u, "
         "runtime_allocation_record_valid=%u, lifetime_table_found=%u, "
         "context_window_owner_seq_valid=%u, "
         "context_window_owner_seq_matches_lifetime=%u, "
         "lane_slot_matches=%u, active_lane_observed=%u, "
         "owner_generation_matches=%u, token_lifetime_key_ready=%u, "
         "retire_release_policy_ready=%u, "
         "driver_runtime_context_window_lifetime_ready=%u, "
         "provider_lifetime_ready=%u, "
         "provider_payload_runtime_lifetime_ready=%u, "
         "context_base=0x%llx, handoff_base=0x%llx, "
         "context_window_index=%llu, handoff_window_index=%llu, "
         "owner_generation=%u, window_generation=%u, "
         "completion_seq_low=%u, resume_seq_low=%u, window_tag=%u, "
         "token_owner_hw_sid=%u, token_owner_hw_wid=%u, "
         "token_owner_hw_tid=%u, token_lane_slot_index=%u, "
         "active_lane_mask=0x%08x, capacity_lane_slots=%u, "
         "retire_free_policy=%s, failpoint=%s, reject_reason=%s, "
         "driver_runtime_context_window_lifetime_bridge_consumes_traversal_behavior=0 "
         "(%s:%u)\n",
         snapshot.context_ptr, snapshot.handoff_window_base,
         snapshot.lane_slot_index, snapshot.valid ? 1 : 0,
         snapshot.runtime_allocation_record_valid ? 1 : 0,
         snapshot.lifetime_table_found ? 1 : 0,
         snapshot.context_window_owner_seq_valid ? 1 : 0,
         snapshot.context_window_owner_seq_matches_lifetime ? 1 : 0,
         snapshot.lane_slot_matches ? 1 : 0,
         snapshot.active_lane_observed ? 1 : 0,
         snapshot.owner_generation_matches ? 1 : 0,
         snapshot.token_lifetime_key_ready ? 1 : 0,
         snapshot.retire_release_policy_ready ? 1 : 0,
         snapshot.driver_runtime_context_window_lifetime_ready ? 1 : 0,
         snapshot.provider_lifetime_ready ? 1 : 0,
         snapshot.provider_payload_runtime_lifetime_ready ? 1 : 0,
         snapshot.context_base, snapshot.handoff_base,
         snapshot.context_window_index, snapshot.handoff_window_index,
         snapshot.owner_generation, snapshot.window_generation,
         snapshot.completion_seq_low, snapshot.resume_seq_low,
         snapshot.window_tag, snapshot.token_owner_hw_sid,
         snapshot.token_owner_hw_wid, snapshot.token_owner_hw_tid,
         snapshot.token_lane_slot_index, snapshot.active_lane_mask,
         snapshot.capacity_lane_slots,
         snapshot.retire_free_policy != NULL ? snapshot.retire_free_policy
                                             : "missing",
         snapshot.failpoint, snapshot.reject_reason,
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0);
  fflush(stdout);
}

static bool
rtcore_fail_closed_on_driver_runtime_context_window_lifetime_bridge_snapshot(
    const ptx_instruction *pI,
    const rtcore_driver_runtime_context_window_lifetime_bridge_snapshot
        &snapshot) {
  if (snapshot.provider_lifetime_ready) {
    return false;
  }
  const bool bridge_required = snapshot.runtime_allocation_record_valid ||
                               snapshot.lifetime_table_found ||
                               strcmp(snapshot.failpoint, "none") != 0;
  if (!bridge_required) {
    return false;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
         "reason=DRIVER_RUNTIME_CONTEXT_WINDOW_LIFETIME_BRIDGE_NOT_READY, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, "
         "driver_runtime_context_window_lifetime_bridge_valid=%u, "
         "runtime_allocation_record_valid=%u, lifetime_table_found=%u, "
         "context_window_owner_seq_matches_lifetime=%u, "
         "lane_slot_matches=%u, active_lane_observed=%u, "
         "owner_generation_matches=%u, token_lifetime_key_ready=%u, "
         "retire_release_policy_ready=%u, provider_backend_dispatch_skipped=1, "
         "failpoint=%s, reject_reason=%s\n",
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0, snapshot.context_ptr,
         snapshot.handoff_window_base, snapshot.lane_slot_index,
         snapshot.valid ? 1 : 0,
         snapshot.runtime_allocation_record_valid ? 1 : 0,
         snapshot.lifetime_table_found ? 1 : 0,
         snapshot.context_window_owner_seq_matches_lifetime ? 1 : 0,
         snapshot.lane_slot_matches ? 1 : 0,
         snapshot.active_lane_observed ? 1 : 0,
         snapshot.owner_generation_matches ? 1 : 0,
         snapshot.token_lifetime_key_ready ? 1 : 0,
         snapshot.retire_release_policy_ready ? 1 : 0, snapshot.failpoint,
         snapshot.reject_reason);
  fflush(stdout);
  return true;
}

enum rtcore_input_provenance_registry_fail_reason {
  RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE = 0,
  RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED = 1,
  RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_PROVENANCE = 2,
  RTCORE_INPUT_PROVENANCE_REGISTRY_KEY_MISMATCH = 3,
  RTCORE_INPUT_PROVENANCE_REGISTRY_STALE_OWNER_SEQUENCE = 4,
  RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_LANE_SLOT = 5,
  RTCORE_INPUT_PROVENANCE_REGISTRY_INACTIVE_LANE = 6,
  RTCORE_INPUT_PROVENANCE_REGISTRY_PARTIAL_FIELD_OWNERSHIP = 7
};

static const char *rtcore_input_provenance_registry_fail_reason_name(
    rtcore_input_provenance_registry_fail_reason reason) {
  switch (reason) {
    case RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_PROVENANCE:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_PROVENANCE";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_KEY_MISMATCH:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_KEY_MISMATCH";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_STALE_OWNER_SEQUENCE:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_STALE_OWNER_SEQUENCE";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_LANE_SLOT:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_LANE_SLOT";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_INACTIVE_LANE:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_INACTIVE_LANE";
    case RTCORE_INPUT_PROVENANCE_REGISTRY_PARTIAL_FIELD_OWNERSHIP:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_PARTIAL_FIELD_OWNERSHIP";
    default:
      return "RTCORE_INPUT_PROVENANCE_REGISTRY_UNKNOWN";
  }
}

struct rtcore_input_provenance_registry_key {
  rtcore_input_provenance_registry_key()
      : context_ptr(0),
        handoff_window_base(0),
        lane_slot_index(0),
        window_generation(0),
        completion_seq_low(0),
        resume_seq_low(0),
        window_tag(0),
        owner_hw_sid(0),
        active_mask(0),
        static_inst_uid(0) {}

  unsigned long long context_ptr;
  unsigned long long handoff_window_base;
  unsigned lane_slot_index;
  unsigned window_generation;
  unsigned completion_seq_low;
  unsigned resume_seq_low;
  unsigned window_tag;
  unsigned owner_hw_sid;
  unsigned active_mask;
  unsigned static_inst_uid;
};

struct rtcore_input_provenance_registry_owned_fields {
  rtcore_input_provenance_registry_owned_fields()
      : has_ray_origin_direction_tmin_tmax(false),
        has_ray_flags_cull_mask(false),
        has_launch_context_input(false),
        has_traversable_root_proxy(false),
        has_bvh_format_profile(false) {}

  bool has_ray_origin_direction_tmin_tmax;
  bool has_ray_flags_cull_mask;
  bool has_launch_context_input;
  bool has_traversable_root_proxy;
  bool has_bvh_format_profile;
};

struct rtcore_input_provenance_registry_entry {
  rtcore_input_provenance_registry_entry()
      : valid(false),
        fail_reason(RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED) {}

  bool valid;
  rtcore_input_provenance_registry_key key;
  rtcore_input_provenance_registry_owned_fields owned_fields;
  rtcore_input_provenance_registry_fail_reason fail_reason;
};

struct rtcore_input_provenance_registry_publication_snapshot {
  rtcore_input_provenance_registry_publication_snapshot()
      : publication_requested(false),
        publication_enabled(false),
        published(false),
        fail_reason(RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED) {}

  bool publication_requested;
  bool publication_enabled;
  bool published;
  rtcore_input_provenance_registry_entry entry;
  rtcore_input_provenance_registry_fail_reason fail_reason;
};

static bool rtcore_input_provenance_registry_enabled() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_INPUT_PROVENANCE_REGISTRY_ENABLE");
  if (value == NULL || value[0] == '\0') {
    return true;
  }
  if (rtcore_rt_env_value_is_explicit_false(value)) {
    return false;
  }
  return true;
}

static rtcore_input_provenance_registry_key
rtcore_make_input_provenance_registry_key(
    const rtcore_traversal_source_request &request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot) {
  rtcore_input_provenance_registry_key key;
  key.context_ptr = request.context_ptr;
  key.handoff_window_base = request.handoff_window_base;
  key.lane_slot_index = request.lane_slot_index;
  key.window_generation = owner_seq_snapshot.window_generation;
  key.completion_seq_low = owner_seq_snapshot.completion_seq_low;
  key.resume_seq_low = owner_seq_snapshot.resume_seq_low;
  key.window_tag = owner_seq_snapshot.window_tag;
  key.owner_hw_sid = owner_seq_snapshot.warp_metadata.owner_hw_sid;
  key.active_mask = owner_seq_snapshot.warp_metadata.active_mask;
  key.static_inst_uid = owner_seq_snapshot.warp_metadata.static_inst_uid;
  return key;
}

static rtcore_input_provenance_registry_entry
rtcore_make_disabled_input_provenance_registry_entry(
    const rtcore_traversal_source_request &request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot) {
  rtcore_input_provenance_registry_entry entry;
  entry.key =
      rtcore_make_input_provenance_registry_key(request, owner_seq_snapshot);
  entry.fail_reason = RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED;
  return entry;
}

static rtcore_input_provenance_registry_publication_snapshot
rtcore_publish_input_provenance_registry_entry_snapshot(
    const rtcore_traversal_source_request &request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot) {
  rtcore_input_provenance_registry_publication_snapshot snapshot;
  snapshot.publication_requested = true;
  snapshot.publication_enabled = rtcore_input_provenance_registry_enabled();
  snapshot.entry =
      rtcore_make_disabled_input_provenance_registry_entry(
          request, owner_seq_snapshot);
  snapshot.fail_reason = snapshot.entry.fail_reason;
  const char *fail_reason_name =
      rtcore_input_provenance_registry_fail_reason_name(snapshot.fail_reason);
  (void)fail_reason_name;
  if (!snapshot.publication_enabled) {
    return snapshot;
  }
  return snapshot;
}

struct rtcore_input_provenance_registry_validation_result {
  rtcore_input_provenance_registry_validation_result()
      : validation_requested(false),
        validation_enabled(false),
        key_matches(false),
        fail_reason(RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED) {}

  bool validation_requested;
  bool validation_enabled;
  bool key_matches;
  rtcore_input_provenance_registry_key expected_key;
  rtcore_input_provenance_registry_key observed_key;
  rtcore_input_provenance_registry_fail_reason fail_reason;
};

static bool rtcore_input_provenance_registry_keys_match(
    const rtcore_input_provenance_registry_key &expected,
    const rtcore_input_provenance_registry_key &observed) {
  return expected.context_ptr == observed.context_ptr &&
         expected.handoff_window_base == observed.handoff_window_base &&
         expected.lane_slot_index == observed.lane_slot_index &&
         expected.window_generation == observed.window_generation &&
         expected.completion_seq_low == observed.completion_seq_low &&
         expected.resume_seq_low == observed.resume_seq_low &&
         expected.window_tag == observed.window_tag &&
         expected.owner_hw_sid == observed.owner_hw_sid &&
         expected.active_mask == observed.active_mask &&
         expected.static_inst_uid == observed.static_inst_uid;
}

static rtcore_input_provenance_registry_validation_result
rtcore_validate_input_provenance_registry_key_before_provider(
    const rtcore_input_provenance_registry_publication_snapshot
        &publication_snapshot,
    const rtcore_traversal_source_request &request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot) {
  rtcore_input_provenance_registry_validation_result result;
  result.validation_requested = true;
  result.validation_enabled = publication_snapshot.publication_enabled;
  result.expected_key =
      rtcore_make_input_provenance_registry_key(request, owner_seq_snapshot);
  result.observed_key = publication_snapshot.entry.key;
  result.fail_reason = publication_snapshot.fail_reason;
  if (!result.validation_enabled) {
    return result;
  }
  if (!publication_snapshot.entry.valid) {
    result.fail_reason =
        publication_snapshot.fail_reason !=
                RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE
            ? publication_snapshot.fail_reason
            : RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_PROVENANCE;
    return result;
  }

  result.key_matches = rtcore_input_provenance_registry_keys_match(
      result.expected_key, result.observed_key);
  result.fail_reason = result.key_matches
                           ? RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE
                           : RTCORE_INPUT_PROVENANCE_REGISTRY_KEY_MISMATCH;
  return result;
}

struct rtcore_input_provenance_registry_owned_field_coverage_result {
  rtcore_input_provenance_registry_owned_field_coverage_result()
      : coverage_requested(false),
        coverage_enabled(false),
        has_required_owned_fields(false),
        fail_reason(RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED) {}

  bool coverage_requested;
  bool coverage_enabled;
  bool has_required_owned_fields;
  rtcore_input_provenance_registry_owned_fields required_fields;
  rtcore_input_provenance_registry_owned_fields observed_fields;
  rtcore_input_provenance_registry_fail_reason fail_reason;
};

static rtcore_input_provenance_registry_owned_fields
rtcore_make_required_input_provenance_registry_owned_fields() {
  rtcore_input_provenance_registry_owned_fields required;
  required.has_ray_origin_direction_tmin_tmax = true;
  required.has_ray_flags_cull_mask = true;
  required.has_launch_context_input = true;
  required.has_traversable_root_proxy = true;
  required.has_bvh_format_profile = true;
  return required;
}

static bool rtcore_input_provenance_registry_owned_fields_cover_required_inputs(
    const rtcore_input_provenance_registry_owned_fields &observed,
    const rtcore_input_provenance_registry_owned_fields &required) {
  return (!required.has_ray_origin_direction_tmin_tmax ||
          observed.has_ray_origin_direction_tmin_tmax) &&
         (!required.has_ray_flags_cull_mask ||
          observed.has_ray_flags_cull_mask) &&
         (!required.has_launch_context_input ||
          observed.has_launch_context_input) &&
         (!required.has_traversable_root_proxy ||
          observed.has_traversable_root_proxy) &&
         (!required.has_bvh_format_profile ||
          observed.has_bvh_format_profile);
}

static rtcore_input_provenance_registry_owned_field_coverage_result
rtcore_validate_input_provenance_registry_owned_field_coverage_before_provider(
    const rtcore_input_provenance_registry_publication_snapshot
        &publication_snapshot) {
  rtcore_input_provenance_registry_owned_field_coverage_result result;
  result.coverage_requested = true;
  result.coverage_enabled = publication_snapshot.publication_enabled;
  result.required_fields =
      rtcore_make_required_input_provenance_registry_owned_fields();
  result.observed_fields = publication_snapshot.entry.owned_fields;
  result.fail_reason = publication_snapshot.fail_reason;
  if (!result.coverage_enabled) {
    return result;
  }
  if (!publication_snapshot.entry.valid) {
    result.fail_reason =
        publication_snapshot.fail_reason !=
                RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE
            ? publication_snapshot.fail_reason
            : RTCORE_INPUT_PROVENANCE_REGISTRY_MISSING_PROVENANCE;
    return result;
  }

  result.has_required_owned_fields =
      rtcore_input_provenance_registry_owned_fields_cover_required_inputs(
          result.observed_fields, result.required_fields);
  result.fail_reason =
      result.has_required_owned_fields
          ? RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE
          : RTCORE_INPUT_PROVENANCE_REGISTRY_PARTIAL_FIELD_OWNERSHIP;
  return result;
}

struct rtcore_input_provenance_registry_read_gate_result {
  rtcore_input_provenance_registry_read_gate_result()
      : gate_requested(false),
        gate_enabled(false),
        read_allowed(false),
        fail_reason(RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED) {}

  bool gate_requested;
  bool gate_enabled;
  bool read_allowed;
  rtcore_input_provenance_registry_fail_reason fail_reason;
};

static rtcore_input_provenance_registry_read_gate_result
rtcore_gate_input_provenance_registry_read_before_provider(
    const rtcore_input_provenance_registry_validation_result
        &key_validation_result,
    const rtcore_input_provenance_registry_owned_field_coverage_result
        &owned_field_coverage_result) {
  rtcore_input_provenance_registry_read_gate_result result;
  result.gate_requested = true;
  result.gate_enabled = rtcore_input_provenance_registry_enabled();
  result.fail_reason = RTCORE_INPUT_PROVENANCE_REGISTRY_DISABLED;
  if (!result.gate_enabled) {
    return result;
  }

  if (!key_validation_result.key_matches) {
    result.fail_reason = RTCORE_INPUT_PROVENANCE_REGISTRY_KEY_MISMATCH;
    return result;
  }
  if (!owned_field_coverage_result.has_required_owned_fields) {
    result.fail_reason =
        RTCORE_INPUT_PROVENANCE_REGISTRY_PARTIAL_FIELD_OWNERSHIP;
    return result;
  }

  result.read_allowed = true;
  result.fail_reason = RTCORE_INPUT_PROVENANCE_REGISTRY_FAIL_NONE;
  return result;
}

static bool
rtcore_fail_closed_on_input_provenance_registry_read_gate_before_provider(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    const rtcore_input_provenance_registry_read_gate_result
        &read_gate_result) {
  if (!read_gate_result.gate_enabled || read_gate_result.read_allowed) {
    return false;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
         "reason=%s, provider=%s, context_ptr=0x%llx, "
         "handoff_window_base=0x%llx, lane_slot_index=%u, "
         "input-provenance-registry-read-gate-fail-closed=1, "
         "registry_gate_enabled=1, registry_read_allowed=0\n",
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0,
         rtcore_input_provenance_registry_fail_reason_name(
             read_gate_result.fail_reason),
         rtcore_traversal_source_provider_name(source_request.provider),
         source_request.context_ptr, source_request.handoff_window_base,
         source_request.lane_slot_index);
  fflush(stdout);
  return true;
}

static void
rtcore_log_input_provenance_registry_read_gate_allowed_before_provider(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    const rtcore_input_provenance_registry_read_gate_result
        &read_gate_result,
    const rtcore_input_provenance_registry_owned_field_coverage_result
        &owned_field_coverage_result) {
  if (!read_gate_result.gate_enabled || !read_gate_result.read_allowed) {
    return;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT registry-read-gate-allowed (%s:%u), "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, input-provenance-registry-read-gate-allowed=1, "
         "registry_gate_enabled=1, registry_read_allowed=1, "
         "has_ray_origin_direction_tmin_tmax=%u, has_ray_flags_cull_mask=%u, "
         "has_launch_context_input=%u, has_traversable_root_proxy=%u, "
         "has_bvh_format_profile=%u\n",
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0,
         rtcore_traversal_source_provider_name(source_request.provider),
         source_request.context_ptr, source_request.handoff_window_base,
         source_request.lane_slot_index,
         owned_field_coverage_result.observed_fields
                 .has_ray_origin_direction_tmin_tmax
             ? 1
             : 0,
         owned_field_coverage_result.observed_fields.has_ray_flags_cull_mask ? 1
                                                                             : 0,
         owned_field_coverage_result.observed_fields.has_launch_context_input ? 1
                                                                              : 0,
         owned_field_coverage_result.observed_fields.has_traversable_root_proxy
             ? 1
             : 0,
         owned_field_coverage_result.observed_fields.has_bvh_format_profile ? 1
                                                                            : 0);
  fflush(stdout);
}

