static const char *rtcore_provider_payload_consumption_policy_env_name() {
  return "VULKAN_SIM_RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_POLICY";
}

static const char *rtcore_provider_payload_consumption_policy_source() {
  const char *value =
      getenv(rtcore_provider_payload_consumption_policy_env_name());
  return value != NULL && value[0] != '\0'
             ? rtcore_provider_payload_consumption_policy_env_name()
             : "default-enabled";
}

static bool rtcore_provider_payload_consumption_policy_enabled() {
  const char *value =
      getenv(rtcore_provider_payload_consumption_policy_env_name());
  if (value == NULL || value[0] == '\0') {
    return true;
  }
  if (rtcore_rt_env_value_is_explicit_true(value)) {
    return true;
  }
  if (rtcore_rt_env_value_is_explicit_false(value) ||
      rtcore_path_mode_is(value, "deny")) {
    return false;
  }
  return false;
}

static const char *
rtcore_provider_payload_consumption_parity_evidence_env_name() {
  return "VULKAN_SIM_RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_PARITY_EVIDENCE";
}

static const char *
rtcore_provider_payload_consumption_resource_evidence_env_name() {
  return "VULKAN_SIM_RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_RESOURCE_EVIDENCE";
}

static bool rtcore_provider_payload_consumption_evidence_available(
    const char *env_name) {
  const char *value = getenv(env_name);
  if (value == NULL || value[0] == '\0') {
    return false;
  }
  return strcmp(value, "1") == 0 || rtcore_path_mode_is(value, "true") ||
         rtcore_path_mode_is(value, "allow") ||
         rtcore_path_mode_is(value, "allowed") ||
         rtcore_path_mode_is(value, "available") ||
         rtcore_path_mode_is(value, "passed");
}

static bool rtcore_provider_payload_consumption_parity_evidence_available() {
  return rtcore_provider_payload_consumption_evidence_available(
      rtcore_provider_payload_consumption_parity_evidence_env_name());
}

static bool rtcore_provider_payload_consumption_resource_evidence_available() {
  return rtcore_provider_payload_consumption_evidence_available(
      rtcore_provider_payload_consumption_resource_evidence_env_name());
}

static const char *
rtcore_provider_payload_consumption_evidence_source_env_name() {
  return "VULKAN_SIM_RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE";
}

static rtcore_provider_payload_consumption_evidence_source
rtcore_get_provider_payload_consumption_evidence_source() {
  const char *value =
      getenv(rtcore_provider_payload_consumption_evidence_source_env_name());
  if (value == NULL || value[0] == '\0') {
    return RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE_RUNTIME_SHADOW;
  }
  if (value != NULL &&
      (rtcore_path_mode_is(value, "runtime_shadow") ||
       rtcore_path_mode_is(value, "runtime"))) {
    return RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE_RUNTIME_SHADOW;
  }
  if (rtcore_path_mode_is(value, "external")) {
    return RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE_EXTERNAL;
  }
  return RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE_EXTERNAL;
}

static bool rtcore_provider_payload_consumption_uses_runtime_evidence() {
  return rtcore_get_provider_payload_consumption_evidence_source() ==
         RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_EVIDENCE_SOURCE_RUNTIME_SHADOW;
}

static const char *rtcore_provider_decoded_abi_authority_fault_env_name() {
  return "VULKAN_SIM_RTCORE_TEST_PROVIDER_DECODED_ABI_AUTHORITY_FAULT";
}

enum rtcore_provider_decoded_abi_authority_fault_kind_t {
  RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_NONE = 0,
  RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_RAY_INPUT_OWNER_BLOCKED,
  RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_LAUNCH_CONTEXT_OWNER_BLOCKED,
  RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_PROXY_OWNER_BLOCKED,
  RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_UNSUPPORTED
};

static const char *
rtcore_provider_decoded_abi_authority_fault_ray_input_owner_blocked_name() {
  return "ray_input_owner_blocked";
}

static const char *
rtcore_provider_decoded_abi_authority_fault_launch_context_owner_blocked_name() {
  return "launch_context_owner_blocked";
}

static const char *
rtcore_provider_decoded_abi_authority_fault_proxy_owner_blocked_name() {
  return "proxy_owner_blocked";
}

static const char *
rtcore_provider_decoded_abi_authority_fault_owner_lifetime_blocked_name() {
  return "owner_lifetime_blocked";
}

static rtcore_provider_decoded_abi_authority_fault_kind_t
rtcore_get_provider_decoded_abi_authority_fault_kind() {
  const char *value =
      getenv(rtcore_provider_decoded_abi_authority_fault_env_name());
  if (value == NULL || value[0] == '\0' ||
      rtcore_path_mode_is(value, "none") ||
      rtcore_rt_env_value_is_explicit_false(value)) {
    return RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_NONE;
  }
  if (rtcore_path_mode_is(
          value,
          rtcore_provider_decoded_abi_authority_fault_ray_input_owner_blocked_name())) {
    return RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_RAY_INPUT_OWNER_BLOCKED;
  }
  if (rtcore_path_mode_is(
          value,
          rtcore_provider_decoded_abi_authority_fault_launch_context_owner_blocked_name()) ||
      rtcore_path_mode_is(value,
          rtcore_provider_decoded_abi_authority_fault_owner_lifetime_blocked_name()) ||
      rtcore_rt_env_value_is_explicit_true(value)) {
    return RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_LAUNCH_CONTEXT_OWNER_BLOCKED;
  }
  if (rtcore_path_mode_is(
          value,
          rtcore_provider_decoded_abi_authority_fault_proxy_owner_blocked_name())) {
    return RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_PROXY_OWNER_BLOCKED;
  }
  return RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_UNSUPPORTED;
}

static const char *rtcore_provider_decoded_abi_authority_fault_name() {
  switch (rtcore_get_provider_decoded_abi_authority_fault_kind()) {
    case RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_RAY_INPUT_OWNER_BLOCKED:
      return rtcore_provider_decoded_abi_authority_fault_ray_input_owner_blocked_name();
    case RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_LAUNCH_CONTEXT_OWNER_BLOCKED:
      return rtcore_provider_decoded_abi_authority_fault_launch_context_owner_blocked_name();
    case RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_PROXY_OWNER_BLOCKED:
      return rtcore_provider_decoded_abi_authority_fault_proxy_owner_blocked_name();
    case RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_UNSUPPORTED:
      return "unsupported";
    case RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_NONE:
    default:
      return "none";
  }
}

static bool rtcore_provider_decoded_abi_authority_fault_enabled() {
  const rtcore_provider_decoded_abi_authority_fault_kind_t fault_kind =
      rtcore_get_provider_decoded_abi_authority_fault_kind();
  return fault_kind != RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_NONE &&
         fault_kind != RTCORE_PROVIDER_DECODED_ABI_AUTHORITY_FAULT_UNSUPPORTED;
}

static bool
rtcore_provider_decoded_abi_authority_owner_lifetime_blocked_fault_enabled() {
  return rtcore_provider_decoded_abi_authority_fault_enabled();
}

static bool rtcore_provider_payload_consumption_default_custom_path() {
  if (!rtcore_path_mode_policy_enables_custom_path(
          rtcore_get_path_mode_policy())) {
    return false;
  }
  const char *provider_override =
      getenv("VULKAN_SIM_RTCORE_TRAVERSAL_SOURCE_PROVIDER");
  if (!rtcore_traversal_source_provider_override_unset(provider_override)) {
    return false;
  }
  return rtcore_select_default_traversal_source_provider() ==
         RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EXISTING_TRAVERSAL;
}

static bool rtcore_provider_payload_shadow_has_complete_field_coverage(
    const rtcore_provider_facing_registry_payload_shadow
        *registry_payload_shadow) {
  if (registry_payload_shadow == NULL || !registry_payload_shadow->valid) {
    return false;
  }
  return registry_payload_shadow->has_ray_origin_direction_tmin_tmax &&
         registry_payload_shadow->has_ray_flags_cull_mask &&
         registry_payload_shadow->has_launch_context_input &&
         registry_payload_shadow->has_traversable_root_proxy &&
         registry_payload_shadow->has_bvh_format_profile;
}

static bool
rtcore_provider_payload_consumption_existing_traversal_backend_available() {
  return rtcore_select_default_traversal_source_provider() ==
         RTCORE_TRAVERSAL_SOURCE_PROVIDER_RTCORE_CUSTOM_EXISTING_TRAVERSAL;
}

static rtcore_provider_payload_consumption_runtime_evidence_record
rtcore_make_provider_payload_consumption_runtime_evidence_record(
    const rtcore_provider_facing_registry_payload_shadow
        *registry_payload_shadow,
    bool provider_payload_consumption_enabled) {
  rtcore_provider_payload_consumption_runtime_evidence_record record;
  record.valid = true;
  record.default_custom_path =
      rtcore_provider_payload_consumption_default_custom_path();
  record.admission_allowed =
      rtcore_registry_payload_consumption_admission_policy_allows(
          "provider-payload-consumption-runtime-evidence-shadow");
  record.has_registry_payload_shadow = registry_payload_shadow != NULL;
  record.consumption_policy_enabled =
      rtcore_provider_payload_consumption_policy_enabled();
  record.evidence_source =
      rtcore_get_provider_payload_consumption_evidence_source();
  record.preflight_uses_runtime_evidence =
      rtcore_provider_payload_consumption_uses_runtime_evidence();
  record.runtime_evidence_gates_preflight =
      record.preflight_uses_runtime_evidence;
  record.existing_traversal_backend_available =
      rtcore_provider_payload_consumption_existing_traversal_backend_available();
  record.provider_payload_consumption_enabled =
      provider_payload_consumption_enabled;

  if (registry_payload_shadow != NULL && registry_payload_shadow->valid) {
    record.observed_valid_shadow = true;
    record.field_coverage_complete =
        rtcore_provider_payload_shadow_has_complete_field_coverage(
            registry_payload_shadow);
    const bool registry_fields_owned_with_lifetime =
        registry_payload_shadow
            ->provider_consumed_input_fields_all_owned_with_lifetime;
    const bool registry_runtime_lifetime_ready =
        registry_payload_shadow->driver_runtime_context_window_lifetime_ready;
    const bool registry_provider_payload_runtime_lifetime_ready =
        registry_payload_shadow->provider_payload_runtime_lifetime_ready;
    record.owner_lifetime_ok =
        registry_fields_owned_with_lifetime &&
        registry_runtime_lifetime_ready &&
        registry_provider_payload_runtime_lifetime_ready;
    record.driver_runtime_context_window_lifetime_ready =
        registry_payload_shadow
            ->driver_runtime_context_window_lifetime_ready;
    record.context_window_owner_seq_matches_lifetime =
        registry_payload_shadow->context_window_owner_seq_matches_lifetime;
    record.token_lifetime_key_ready =
        registry_payload_shadow->token_lifetime_key_ready;
  }

  const rtcore_symbolic_resource_profile resource_profile =
      rtcore_get_symbolic_resource_profile();
  record.resident_rt_warps = resource_profile.resident_rt_warps;
  record.token_limited_warps = resource_profile.token_limited_warps;
  record.handoff_window_limited_warps =
      resource_profile.handoff_window_limited_warps;
  record.traversal_stack_limited_warps =
      resource_profile.traversal_stack_limited_warps;
  record.runtime_token_resource_model_available =
      resource_profile.token_limited_warps != 0;
  record.runtime_handoff_slot_model_available =
      resource_profile.handoff_window_limited_warps != 0;
  record.runtime_traversal_stack_model_available =
      resource_profile.traversal_stack_limited_warps != 0;
  record.runtime_resident_warp_model_available =
      resource_profile.resident_rt_warps != 0;
  record.runtime_issue_side_resource_evidence_available =
      record.runtime_token_resource_model_available &&
      record.runtime_handoff_slot_model_available &&
      record.runtime_traversal_stack_model_available &&
      record.runtime_resident_warp_model_available;
  record.runtime_resource_evidence_available =
      record.runtime_issue_side_resource_evidence_available;
  record.runtime_parity_evidence_available =
      record.default_custom_path && record.existing_traversal_backend_available &&
      record.observed_valid_shadow && record.field_coverage_complete &&
      record.owner_lifetime_ok;
  record.runtime_evidence_complete =
      record.runtime_parity_evidence_available &&
      record.runtime_resource_evidence_available;
  return record;
}

