static void rtcore_log_provider_facing_registry_payload_admission_mirror(
    const rtcore_traversal_work_descriptor &descriptor) {
  rtcore_provider_facing_registry_payload_admission_mirror mirror;
  mirror.valid = true;
  mirror.has_registry_payload_shadow = descriptor.has_registry_payload_shadow;
  mirror.provider_payload_consumption_enabled =
      descriptor.provider_payload_consumption_enabled;
  if (descriptor.has_registry_payload_shadow &&
      descriptor.registry_payload_shadow != NULL &&
      descriptor.registry_payload_shadow->valid) {
    const rtcore_provider_facing_registry_payload_shadow &shadow =
        *descriptor.registry_payload_shadow;
    mirror.observed_valid_shadow = true;
    mirror.has_ray_origin_direction_tmin_tmax =
        shadow.has_ray_origin_direction_tmin_tmax;
    mirror.has_ray_flags_cull_mask = shadow.has_ray_flags_cull_mask;
    mirror.has_launch_context_input = shadow.has_launch_context_input;
    mirror.has_traversable_root_proxy = shadow.has_traversable_root_proxy;
    mirror.has_bvh_format_profile = shadow.has_bvh_format_profile;
    mirror.bvh_format_version = shadow.bvh_format_version;
  }
  mirror.admission_allowed =
      rtcore_registry_payload_consumption_admission_policy_allows(
          "provider-facing-mirror");
  mirror.default_deny =
      rtcore_registry_payload_consumption_admission_policy_default_deny();

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-facing-registry-payload-admission-mirror=1, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, registry_payload_admission_mirror_valid=%u, "
         "registry_payload_admission_mirror_allowed=%u, "
         "registry_payload_admission_mirror_default_deny=%u, "
         "registry_payload_admission_policy_opt_in_source=%s, "
         "registry_payload_admission_policy_opt_in_enabled=%u, "
         "registry_payload_shadow_attached=%u, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_consumption_enabled=%u, "
         "provider_admission_mirror_consumes_traversal_behavior=0, "
         "has_ray_origin_direction_tmin_tmax=%u, has_ray_flags_cull_mask=%u, "
         "has_launch_context_input=%u, has_traversable_root_proxy=%u, "
         "has_bvh_format_profile=%u, bvh_format_version=%u\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index, mirror.valid ? 1 : 0,
         mirror.admission_allowed ? 1 : 0, mirror.default_deny ? 1 : 0,
         rtcore_registry_payload_consumption_admission_policy_opt_in_source(),
         mirror.admission_allowed ? 1 : 0,
         mirror.has_registry_payload_shadow ? 1 : 0,
         mirror.observed_valid_shadow ? 1 : 0,
         mirror.provider_payload_consumption_enabled ? 1 : 0,
         mirror.has_ray_origin_direction_tmin_tmax ? 1 : 0,
         mirror.has_ray_flags_cull_mask ? 1 : 0,
         mirror.has_launch_context_input ? 1 : 0,
         mirror.has_traversable_root_proxy ? 1 : 0,
         mirror.has_bvh_format_profile ? 1 : 0,
         mirror.bvh_format_version);
  fflush(stdout);
}

static void rtcore_log_provider_payload_consumption_eligibility_shadow(
    const rtcore_traversal_work_descriptor &descriptor) {
  rtcore_provider_payload_consumption_eligibility_shadow shadow_decision;
  shadow_decision.valid = true;
  shadow_decision.admission_allowed =
      rtcore_registry_payload_consumption_admission_policy_allows(
          "provider-payload-consumption-eligibility-shadow");
  shadow_decision.has_registry_payload_shadow =
      descriptor.has_registry_payload_shadow;
  shadow_decision.consumption_policy_enabled =
      rtcore_provider_payload_consumption_policy_enabled();
  shadow_decision.provider_payload_consumption_enabled =
      descriptor.provider_payload_consumption_enabled;

  if (descriptor.has_registry_payload_shadow &&
      descriptor.registry_payload_shadow != NULL &&
      descriptor.registry_payload_shadow->valid) {
    const rtcore_provider_facing_registry_payload_shadow &shadow =
        *descriptor.registry_payload_shadow;
    shadow_decision.observed_valid_shadow = true;
    shadow_decision.field_coverage_complete =
        rtcore_provider_payload_shadow_has_complete_field_coverage(&shadow);
  }
  shadow_decision.provider_payload_consumption_eligible =
      shadow_decision.admission_allowed &&
      shadow_decision.observed_valid_shadow &&
      shadow_decision.field_coverage_complete &&
      shadow_decision.consumption_policy_enabled;

  if (!shadow_decision.admission_allowed) {
    shadow_decision.fail_reason =
        RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_ELIGIBILITY_ADMISSION_DISABLED;
  } else if (!shadow_decision.observed_valid_shadow) {
    shadow_decision.fail_reason =
        RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_ELIGIBILITY_REGISTRY_SHADOW_MISSING;
  } else if (!shadow_decision.field_coverage_complete) {
    shadow_decision.fail_reason =
        RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_ELIGIBILITY_FIELD_COVERAGE_INCOMPLETE;
  } else if (!shadow_decision.consumption_policy_enabled) {
    shadow_decision.fail_reason =
        RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_ELIGIBILITY_CONSUMPTION_POLICY_DISABLED;
  } else {
    shadow_decision.fail_reason =
        RTCORE_PROVIDER_PAYLOAD_CONSUMPTION_ELIGIBILITY_NONE;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-payload-consumption-eligibility-shadow=1, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, "
         "registry_payload_admission_allowed=%u, "
         "registry_payload_shadow_attached=%u, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_field_coverage_complete=%u, "
         "provider_payload_consumption_policy_source=%s, "
         "provider_payload_consumption_policy_enabled=%u, "
         "provider_payload_consumption_eligible=%u, "
         "provider_payload_consumption_enabled=%u, "
         "provider_payload_consumption_eligibility_fail_reason=%s, "
         "provider_payload_consumption_eligibility_consumes_traversal_behavior=0\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index,
         shadow_decision.admission_allowed ? 1 : 0,
         shadow_decision.has_registry_payload_shadow ? 1 : 0,
         shadow_decision.observed_valid_shadow ? 1 : 0,
         shadow_decision.field_coverage_complete ? 1 : 0,
         rtcore_provider_payload_consumption_policy_source(),
         shadow_decision.consumption_policy_enabled ? 1 : 0,
         shadow_decision.provider_payload_consumption_eligible ? 1 : 0,
         shadow_decision.provider_payload_consumption_enabled ? 1 : 0,
         rtcore_provider_payload_consumption_eligibility_shadow_fail_reason_name(
             shadow_decision.fail_reason));
  fflush(stdout);
}

static void rtcore_log_provider_payload_consumption_preflight_record(
    const rtcore_traversal_work_descriptor &descriptor) {
  rtcore_log_provider_payload_consumption_runtime_evidence_record(descriptor);
  const rtcore_provider_payload_consumption_preflight_record preflight =
      rtcore_make_provider_payload_consumption_preflight_record(
          descriptor.registry_payload_shadow);

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-payload-consumption-opt-in-preflight=1, "
         "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, "
         "provider_payload_consumption_preflight_valid=%u, "
         "provider_payload_consumption_default_custom_path=%u, "
         "registry_payload_admission_allowed=%u, "
         "registry_payload_shadow_attached=%u, "
         "registry_payload_shadow_observed=%u, "
         "provider_payload_field_coverage_complete=%u, "
         "provider_payload_consumption_owner_lifetime_ok=%u, "
         "provider_payload_consumption_policy_source=%s, "
         "provider_payload_consumption_policy_enabled=%u, "
         "provider_payload_consumption_evidence_source=%s, "
         "provider_payload_consumption_preflight_uses_runtime_evidence=%u, "
         "provider_payload_consumption_parity_evidence_available=%u, "
         "provider_payload_consumption_resource_evidence_available=%u, "
         "provider_payload_consumption_preflight_passed=%u, "
         "provider_payload_consumption_enabled=%u, "
         "provider_payload_consumption_preflight_fail_reason=%s, "
         "provider_payload_consumption_preflight_consumes_traversal_behavior=0\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index, preflight.valid ? 1 : 0,
         preflight.default_custom_path ? 1 : 0,
         preflight.admission_allowed ? 1 : 0,
         preflight.has_registry_payload_shadow ? 1 : 0,
         preflight.observed_valid_shadow ? 1 : 0,
         preflight.field_coverage_complete ? 1 : 0,
         preflight.owner_lifetime_ok ? 1 : 0,
         rtcore_provider_payload_consumption_policy_source(),
         preflight.consumption_policy_enabled ? 1 : 0,
         rtcore_provider_payload_consumption_evidence_source_name(
             preflight.evidence_source),
         preflight.uses_runtime_evidence ? 1 : 0,
         preflight.parity_evidence_available ? 1 : 0,
         preflight.resource_evidence_available ? 1 : 0,
         preflight.provider_payload_consumption_preflight_passed ? 1 : 0,
         descriptor.provider_payload_consumption_enabled ? 1 : 0,
         rtcore_provider_payload_consumption_preflight_fail_reason_name(
             preflight.fail_reason));
  fflush(stdout);
}

static const uint32_t RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT = 1;

struct rtcore_decoded_traversal_input_snapshot {
  rtcore_decoded_traversal_input_snapshot()
      : valid(false),
        has_context_window_owner_seq(false),
        context_window_owner_seq_owner(RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        has_traversable_root_proxy(false),
        traversable_root_proxy_owner(RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        traversable_proxy_id(0),
        root_proxy_id(0),
        has_bvh_format_version(false),
        bvh_format_profile_owner(RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        bvh_format_version(0),
        has_ray_origin_direction_tmin_tmax(false),
        ray_origin_direction_tmin_tmax_owner(
            RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        has_ray_flags_cull_mask(false),
        ray_flags_cull_mask_owner(RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        has_launch_context_input(false),
        launch_context_input_owner(RTCORE_DECODED_INPUT_OWNER_FORBIDDEN),
        ray_flags(0),
        cull_mask(0),
        bridge_trace_replay_top_level_as(0),
        sbt_record_offset(0),
        sbt_record_stride(0),
        miss_index(0),
        ray_tmin(0.0f),
        ray_tmax(0.0f) {
    memset(&ray_origin, 0, sizeof(ray_origin));
    memset(&ray_direction, 0, sizeof(ray_direction));
  }

  bool valid;
  bool has_context_window_owner_seq;
  rtcore_decoded_input_field_owner_class context_window_owner_seq_owner;
  rtcore_context_window_owner_seq_snapshot context_window_owner_seq;
  bool has_traversable_root_proxy;
  rtcore_decoded_input_field_owner_class traversable_root_proxy_owner;
  uint64_t traversable_proxy_id;
  uint64_t root_proxy_id;
  bool has_bvh_format_version;
  rtcore_decoded_input_field_owner_class bvh_format_profile_owner;
  uint32_t bvh_format_version;
  bool has_ray_origin_direction_tmin_tmax;
  rtcore_decoded_input_field_owner_class ray_origin_direction_tmin_tmax_owner;
  bool has_ray_flags_cull_mask;
  rtcore_decoded_input_field_owner_class ray_flags_cull_mask_owner;
  bool has_launch_context_input;
  rtcore_decoded_input_field_owner_class launch_context_input_owner;
  float3 ray_origin;
  float3 ray_direction;
  uint32_t ray_flags;
  uint32_t cull_mask;
  uint64_t bridge_trace_replay_top_level_as;
  uint32_t sbt_record_offset;
  uint32_t sbt_record_stride;
  uint32_t miss_index;
  float ray_tmin;
  float ray_tmax;
};

static rtcore_decoded_traversal_input_snapshot
rtcore_make_decoded_traversal_input_snapshot(
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot) {
  rtcore_decoded_traversal_input_snapshot snapshot;
  snapshot.valid = owner_seq_snapshot.valid;
  snapshot.has_context_window_owner_seq = owner_seq_snapshot.valid;
  snapshot.context_window_owner_seq_owner =
      owner_seq_snapshot.valid ? RTCORE_DECODED_INPUT_OWNER_DRIVER_RUNTIME
                               : RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  snapshot.context_window_owner_seq = owner_seq_snapshot;
  return snapshot;
}

static rtcore_decoded_input_field_owner_class
rtcore_decoded_input_owner_from_publication_source(const char *source) {
  if (source != NULL &&
      strcmp(source, "compiler_driver_publication_sideband") == 0) {
    return RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION;
  }
  if (source != NULL &&
      (strcmp(source, "trace_invocation_publication_source_shadow") == 0 ||
       strcmp(source, "trace_ray_impl") == 0)) {
    return RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
  }
  return RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
}

static bool rtcore_decoded_input_snapshot_all_fields_owned_with_lifetime(
    const rtcore_decoded_traversal_input_snapshot &snapshot) {
  return rtcore_decoded_input_fields_all_owned_with_lifetime(
      snapshot.has_ray_origin_direction_tmin_tmax,
      snapshot.ray_origin_direction_tmin_tmax_owner,
      snapshot.has_ray_flags_cull_mask, snapshot.ray_flags_cull_mask_owner,
      snapshot.has_launch_context_input, snapshot.launch_context_input_owner,
      snapshot.has_traversable_root_proxy,
      snapshot.traversable_root_proxy_owner, snapshot.has_bvh_format_version,
      snapshot.bvh_format_profile_owner);
}

static rtcore_provider_decoded_input_observation
rtcore_make_provider_decoded_input_observation(
    const rtcore_decoded_traversal_input_snapshot &decoded_input_snapshot) {
  rtcore_provider_decoded_input_observation observation;
  if (!decoded_input_snapshot.valid) {
    return observation;
  }

  observation.valid = true;
  observation.from_registry_payload_shadow = false;
  observation.has_ray_origin_direction_tmin_tmax =
      decoded_input_snapshot.has_ray_origin_direction_tmin_tmax;
  observation.ray_origin_direction_tmin_tmax_owner =
      decoded_input_snapshot.ray_origin_direction_tmin_tmax_owner;
  observation.has_ray_flags_cull_mask =
      decoded_input_snapshot.has_ray_flags_cull_mask;
  observation.ray_flags_cull_mask_owner =
      decoded_input_snapshot.ray_flags_cull_mask_owner;
  observation.ray_origin = decoded_input_snapshot.ray_origin;
  observation.ray_direction = decoded_input_snapshot.ray_direction;
  observation.ray_tmin = decoded_input_snapshot.ray_tmin;
  observation.ray_tmax = decoded_input_snapshot.ray_tmax;
  observation.ray_flags = decoded_input_snapshot.ray_flags;
  observation.cull_mask = decoded_input_snapshot.cull_mask;
  observation.has_launch_context_input =
      decoded_input_snapshot.has_launch_context_input;
  observation.launch_context_input_owner =
      decoded_input_snapshot.launch_context_input_owner;
  observation.bridge_trace_replay_top_level_as =
      decoded_input_snapshot.bridge_trace_replay_top_level_as;
  observation.sbt_record_offset = decoded_input_snapshot.sbt_record_offset;
  observation.sbt_record_stride = decoded_input_snapshot.sbt_record_stride;
  observation.miss_index = decoded_input_snapshot.miss_index;
  observation.has_traversable_root_proxy =
      decoded_input_snapshot.has_traversable_root_proxy;
  observation.traversable_root_proxy_owner =
      decoded_input_snapshot.traversable_root_proxy_owner;
  observation.traversable_proxy_id =
      decoded_input_snapshot.traversable_proxy_id;
  observation.root_proxy_id = decoded_input_snapshot.root_proxy_id;
  observation.has_bvh_format_profile =
      decoded_input_snapshot.has_bvh_format_version;
  observation.bvh_format_profile_owner =
      decoded_input_snapshot.bvh_format_profile_owner;
  observation.bvh_format_version = decoded_input_snapshot.bvh_format_version;
  observation.provider_consumed_input_fields_all_owned_with_lifetime =
      rtcore_decoded_input_snapshot_all_fields_owned_with_lifetime(
          decoded_input_snapshot);
  observation.provider_payload_consumption_owner_lifetime_blocked =
      !observation.provider_consumed_input_fields_all_owned_with_lifetime;
  return observation;
}

static void rtcore_update_decoded_traversal_input_ray_proxy_snapshot(
    rtcore_decoded_traversal_input_snapshot *snapshot,
    const rtcore_traversal_source_snapshot &source_snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->has_ray_origin_direction_tmin_tmax = false;
  snapshot->ray_origin_direction_tmin_tmax_owner =
      RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  if (!source_snapshot.has_traversal_data) {
    return;
  }
  snapshot->ray_origin = source_snapshot.traversal_snapshot.ray_world_origin;
  snapshot->ray_direction = source_snapshot.traversal_snapshot.ray_world_direction;
  snapshot->ray_tmin = source_snapshot.traversal_snapshot.Tmin;
  snapshot->ray_tmax = source_snapshot.traversal_snapshot.Tmax;
  snapshot->has_ray_origin_direction_tmin_tmax = true;
  snapshot->ray_origin_direction_tmin_tmax_owner =
      RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

static void rtcore_update_decoded_traversal_input_flags_mask_proxy_snapshot(
    rtcore_decoded_traversal_input_snapshot *snapshot,
    const rtcore_traversal_source_snapshot &source_snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->has_ray_flags_cull_mask = false;
  snapshot->ray_flags_cull_mask_owner = RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  if (!source_snapshot.has_traversal_data) {
    return;
  }
  snapshot->ray_flags = source_snapshot.traversal_snapshot.rayFlags;
  snapshot->cull_mask = source_snapshot.traversal_snapshot.cullMask;
  snapshot->has_ray_flags_cull_mask = true;
  snapshot->ray_flags_cull_mask_owner =
      RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

static void rtcore_update_decoded_traversal_input_launch_context_snapshot(
    rtcore_decoded_traversal_input_snapshot *snapshot,
    const rtcore_traversal_source_snapshot &source_snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->has_launch_context_input = false;
  snapshot->launch_context_input_owner = RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  if (!source_snapshot.has_traversal_data ||
      source_snapshot.traversal_snapshot.rtcore_trace_input_has_top_level_as ==
          0) {
    return;
  }
  snapshot->bridge_trace_replay_top_level_as =
      source_snapshot.traversal_snapshot.rtcore_trace_input_top_level_as;
  snapshot->sbt_record_offset =
      source_snapshot.traversal_snapshot.sbtRecordOffset;
  snapshot->sbt_record_stride =
      source_snapshot.traversal_snapshot.sbtRecordStride;
  snapshot->miss_index = source_snapshot.traversal_snapshot.missIndex;
  snapshot->has_launch_context_input = true;
  snapshot->launch_context_input_owner =
      RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

static void rtcore_update_decoded_traversal_input_traversable_root_proxy_snapshot(
    rtcore_decoded_traversal_input_snapshot *snapshot,
    const rtcore_traversal_source_snapshot &source_snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->has_traversable_root_proxy = false;
  snapshot->traversable_root_proxy_owner =
      RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  if (!source_snapshot.has_traversal_data) {
    return;
  }
  snapshot->traversable_proxy_id =
      source_snapshot.traversal_snapshot.rtcore_traversable_proxy_id;
  snapshot->root_proxy_id =
      source_snapshot.traversal_snapshot.rtcore_root_proxy_id;
  if (snapshot->traversable_proxy_id == 0 || snapshot->root_proxy_id == 0) {
    return;
  }
  snapshot->has_traversable_root_proxy = true;
  snapshot->traversable_root_proxy_owner =
      RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

static void rtcore_update_decoded_traversal_input_bvh_format_profile_snapshot(
    rtcore_decoded_traversal_input_snapshot *snapshot,
    const rtcore_traversal_source_snapshot &source_snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->has_bvh_format_version = false;
  snapshot->bvh_format_profile_owner = RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
  if (!source_snapshot.has_traversal_data) {
    return;
  }
  snapshot->bvh_format_version = RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT;
  snapshot->has_bvh_format_version = true;
  snapshot->bvh_format_profile_owner =
      RTCORE_DECODED_INPUT_OWNER_SIMULATOR_PROXY;
}

enum rtcore_proxy_delegation_failpoint {
  RTCORE_PROXY_DELEGATION_FAILPOINT_NONE = 0,
  RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_TRAVERSABLE_ROOT_PROXY,
  RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_BVH_FORMAT_PROFILE,
  RTCORE_PROXY_DELEGATION_FAILPOINT_WRONG_PROXY_SOURCE_LABEL,
  RTCORE_PROXY_DELEGATION_FAILPOINT_UNSUPPORTED,
};

static const char *rtcore_proxy_delegation_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_PROXY_DELEGATION_FAILPOINT";
}

static rtcore_proxy_delegation_failpoint
rtcore_proxy_delegation_failpoint_mode() {
  const char *value = getenv(rtcore_proxy_delegation_failpoint_env_name());
  if (value == NULL || value[0] == '\0' || strcmp(value, "0") == 0 ||
      strcmp(value, "none") == 0) {
    return RTCORE_PROXY_DELEGATION_FAILPOINT_NONE;
  }
  if (strcmp(value, "drop_traversable_root_proxy") == 0) {
    return RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_TRAVERSABLE_ROOT_PROXY;
  }
  if (strcmp(value, "drop_bvh_format_profile") == 0) {
    return RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_BVH_FORMAT_PROFILE;
  }
  if (strcmp(value, "wrong_proxy_source_label") == 0) {
    return RTCORE_PROXY_DELEGATION_FAILPOINT_WRONG_PROXY_SOURCE_LABEL;
  }
  return RTCORE_PROXY_DELEGATION_FAILPOINT_UNSUPPORTED;
}

static const char *rtcore_proxy_delegation_failpoint_name(
    rtcore_proxy_delegation_failpoint mode) {
  switch (mode) {
    case RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_TRAVERSABLE_ROOT_PROXY:
      return "drop_traversable_root_proxy";
    case RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_BVH_FORMAT_PROFILE:
      return "drop_bvh_format_profile";
    case RTCORE_PROXY_DELEGATION_FAILPOINT_WRONG_PROXY_SOURCE_LABEL:
      return "wrong_proxy_source_label";
    case RTCORE_PROXY_DELEGATION_FAILPOINT_UNSUPPORTED:
      return "unsupported";
    case RTCORE_PROXY_DELEGATION_FAILPOINT_NONE:
    default:
      return "none";
  }
}

static void rtcore_apply_proxy_delegation_failpoint_to_decoded_snapshot(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    rtcore_decoded_traversal_input_snapshot *decoded_input_snapshot) {
  if (decoded_input_snapshot == NULL) {
    return;
  }
  const rtcore_proxy_delegation_failpoint mode =
      rtcore_proxy_delegation_failpoint_mode();
  if (mode == RTCORE_PROXY_DELEGATION_FAILPOINT_NONE) {
    return;
  }

  bool drop_traversable_root_proxy = false;
  bool drop_bvh_format_profile = false;
  bool wrong_proxy_source_label = false;
  switch (mode) {
    case RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_TRAVERSABLE_ROOT_PROXY:
      decoded_input_snapshot->has_traversable_root_proxy = false;
      decoded_input_snapshot->traversable_root_proxy_owner =
          RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
      decoded_input_snapshot->traversable_proxy_id = 0;
      decoded_input_snapshot->root_proxy_id = 0;
      drop_traversable_root_proxy = true;
      break;
    case RTCORE_PROXY_DELEGATION_FAILPOINT_DROP_BVH_FORMAT_PROFILE:
      decoded_input_snapshot->has_bvh_format_version = false;
      decoded_input_snapshot->bvh_format_profile_owner =
          RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
      decoded_input_snapshot->bvh_format_version = 0;
      drop_bvh_format_profile = true;
      break;
    case RTCORE_PROXY_DELEGATION_FAILPOINT_WRONG_PROXY_SOURCE_LABEL:
      decoded_input_snapshot->traversable_root_proxy_owner =
          RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION;
      decoded_input_snapshot->bvh_format_profile_owner =
          RTCORE_DECODED_INPUT_OWNER_COMPILER_DRIVER_PUBLICATION;
      wrong_proxy_source_label = true;
      break;
    case RTCORE_PROXY_DELEGATION_FAILPOINT_UNSUPPORTED:
      decoded_input_snapshot->traversable_root_proxy_owner =
          RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
      decoded_input_snapshot->bvh_format_profile_owner =
          RTCORE_DECODED_INPUT_OWNER_FORBIDDEN;
      wrong_proxy_source_label = true;
      break;
    case RTCORE_PROXY_DELEGATION_FAILPOINT_NONE:
    default:
      return;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT proxy-delegation-failpoint (%s:%u), "
         "proxy-delegation-failpoint=1, "
         "failpoint=%s, mode=%s, provider=%s, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, proxy_delegation_source=%s, "
         "drop_traversable_root_proxy=%u, drop_bvh_format_profile=%u, "
         "wrong_proxy_source_label=%u, before_registry_payload_shadow=1, "
         "before_provider_consumed_input=1, before_backend_input_route=1, "
         "before_traversal_completion=1, "
         "actual_abi_evidence_for_proxy_fields=0\n",
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0,
         rtcore_proxy_delegation_failpoint_name(mode),
         rtcore_proxy_delegation_failpoint_name(mode),
         rtcore_traversal_source_provider_name(source_request.provider),
         source_request.context_ptr, source_request.handoff_window_base,
         source_request.lane_slot_index, rtcore_proxy_delegation_source_label(),
         drop_traversable_root_proxy ? 1 : 0,
         drop_bvh_format_profile ? 1 : 0,
         wrong_proxy_source_label ? 1 : 0);
  fflush(stdout);
}

struct rtcore_pre_provider_traversal_data_snapshot {
  rtcore_pre_provider_traversal_data_snapshot() : valid(false) {
    memset(&traversal_snapshot, 0, sizeof(traversal_snapshot));
  }

  bool valid;
  Traversal_data traversal_snapshot;
};

static rtcore_pre_provider_traversal_data_snapshot
rtcore_make_pre_provider_traversal_data_snapshot(
    const rtcore_traversal_source_request &request) {
  rtcore_pre_provider_traversal_data_snapshot snapshot;
  if (request.thread == NULL || request.thread->RT_thread_data == NULL ||
      request.thread->RT_thread_data->traversal_data.empty()) {
    return snapshot;
  }

  memory_space *mem = request.thread->get_global_memory();
  Traversal_data *device_traversal_data =
      request.thread->RT_thread_data->traversal_data.back();
  mem->read((mem_addr_t)device_traversal_data,
            sizeof(snapshot.traversal_snapshot),
            &snapshot.traversal_snapshot);
  snapshot.valid = true;
  return snapshot;
}

struct rtcore_launch_context_input_publication_record {
  rtcore_launch_context_input_publication_record()
      : publication_enabled(false),
        valid(false),
        context_ptr(0),
        handoff_window_base(0),
        lane_slot_index(0),
        source("trace_ray_operand_shadow"),
        source_publication_seq(0),
        source_owner_tuple_match(false),
        has_source_context_window_key(false),
        source_context_window_match(true),
        has_ray_origin_direction_tmin_tmax(false),
        has_ray_flags_cull_mask(false),
        has_launch_context_input(false),
        ray_flags(0),
        cull_mask(0),
        bridge_trace_replay_top_level_as(0),
        sbt_record_offset(0),
        sbt_record_stride(0),
        miss_index(0),
        ray_tmin(0.0f),
        ray_tmax(0.0f) {
    memset(&ray_origin, 0, sizeof(ray_origin));
    memset(&ray_direction, 0, sizeof(ray_direction));
  }

  bool publication_enabled;
  bool valid;
  unsigned long long context_ptr;
  unsigned long long handoff_window_base;
  unsigned lane_slot_index;
  rtcore_context_window_owner_seq_snapshot owner_seq_snapshot;
  const char *source;
  unsigned long long source_publication_seq;
  bool source_owner_tuple_match;
  bool has_source_context_window_key;
  bool source_context_window_match;
  bool has_ray_origin_direction_tmin_tmax;
  bool has_ray_flags_cull_mask;
  bool has_launch_context_input;
  float3 ray_origin;
  float3 ray_direction;
  uint32_t ray_flags;
  uint32_t cull_mask;
  uint64_t bridge_trace_replay_top_level_as;
  uint32_t sbt_record_offset;
  uint32_t sbt_record_stride;
  uint32_t miss_index;
  float ray_tmin;
  float ray_tmax;
};

static bool rtcore_launch_context_input_publication_bridge_enabled() {
  const rtcore_path_mode_policy policy = rtcore_get_path_mode_policy();
  if (rtcore_path_mode_policy_legacy_path_enabled(policy) ||
      rtcore_path_mode_policy_is_invalid(policy)) {
    return false;
  }
  return rtcore_path_mode_policy_enables_custom_path(policy);
}

enum rtcore_launch_context_input_publication_failpoint {
  RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_NONE = 0,
  RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_ORIGIN_DIRECTION_TMIN_TMAX,
  RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_FLAGS_CULL_MASK,
  RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_LAUNCH_CONTEXT_INPUT,
  RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_WRONG_SOURCE_LABEL,
};

static rtcore_launch_context_input_publication_failpoint
rtcore_launch_context_input_publication_failpoint_mode() {
  const char *value =
      getenv("VULKAN_SIM_RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT");
  if (value == NULL || value[0] == '\0' || strcmp(value, "0") == 0 ||
      strcmp(value, "none") == 0) {
    return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_NONE;
  }
  if (strcmp(value, "drop_ray_origin_direction_tmin_tmax") == 0) {
    return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_ORIGIN_DIRECTION_TMIN_TMAX;
  }
  if (strcmp(value, "drop_ray_flags_cull_mask") == 0) {
    return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_FLAGS_CULL_MASK;
  }
  if (strcmp(value, "drop_launch_context_input") == 0) {
    return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_LAUNCH_CONTEXT_INPUT;
  }
  if (strcmp(value, "wrong_source_label") == 0) {
    return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_WRONG_SOURCE_LABEL;
  }
  return RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_NONE;
}

static const char *rtcore_launch_context_input_publication_failpoint_name(
    rtcore_launch_context_input_publication_failpoint mode) {
  switch (mode) {
    case RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_ORIGIN_DIRECTION_TMIN_TMAX:
      return "drop_ray_origin_direction_tmin_tmax";
    case RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_FLAGS_CULL_MASK:
      return "drop_ray_flags_cull_mask";
    case RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_LAUNCH_CONTEXT_INPUT:
      return "drop_launch_context_input";
    case RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_WRONG_SOURCE_LABEL:
      return "wrong_source_label";
    case RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_NONE:
    default:
      return "none";
  }
}

static void rtcore_apply_launch_context_input_publication_failpoint(
    const ptx_instruction *pI,
    rtcore_launch_context_input_publication_record *record) {
  if (record == NULL || !record->publication_enabled) {
    return;
  }
  rtcore_launch_context_input_publication_failpoint mode =
      rtcore_launch_context_input_publication_failpoint_mode();
  if (mode == RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_NONE) {
    return;
  }

  if (mode ==
      RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_ORIGIN_DIRECTION_TMIN_TMAX) {
    record->has_ray_origin_direction_tmin_tmax = false;
  } else if (mode ==
             RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_RAY_FLAGS_CULL_MASK) {
    record->has_ray_flags_cull_mask = false;
  } else if (mode ==
             RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_DROP_LAUNCH_CONTEXT_INPUT) {
    record->has_launch_context_input = false;
  } else if (mode ==
             RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_WRONG_SOURCE_LABEL) {
    record->source = "unexpected_source_label";
  }
  if (mode !=
      RTCORE_LAUNCH_CONTEXT_INPUT_PUBLICATION_FAILPOINT_WRONG_SOURCE_LABEL) {
    record->valid = false;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "launch-context-input-publication-failpoint (%s:%u), "
         "mode=%s, source=%s, context_ptr=0x%llx, "
         "handoff_window_base=0x%llx, lane_slot_index=%u, "
         "has_source_context_window_key=%u, "
         "source_context_window_match=%u, "
         "has_ray_origin_direction_tmin_tmax=%u, "
         "has_ray_flags_cull_mask=%u, has_launch_context_input=%u\n",
         pI->source_file(), pI->source_line(),
         rtcore_launch_context_input_publication_failpoint_name(mode),
         record->source, record->context_ptr, record->handoff_window_base,
         record->lane_slot_index,
         record->has_source_context_window_key ? 1 : 0,
         record->source_context_window_match ? 1 : 0,
         record->has_ray_origin_direction_tmin_tmax ? 1 : 0,
         record->has_ray_flags_cull_mask ? 1 : 0,
         record->has_launch_context_input ? 1 : 0);
  fflush(stdout);
}

static rtcore_launch_context_input_publication_record
rtcore_make_launch_context_input_publication_record(
    const rtcore_traversal_source_request &request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot,
    const rtcore_pre_provider_traversal_data_snapshot
        &pre_provider_traversal_data_snapshot) {
  rtcore_launch_context_input_publication_record record;
  record.publication_enabled =
      rtcore_launch_context_input_publication_bridge_enabled();
  record.context_ptr = request.context_ptr;
  record.handoff_window_base = request.handoff_window_base;
  record.lane_slot_index = request.lane_slot_index;
  record.owner_seq_snapshot = owner_seq_snapshot;
  if (!record.publication_enabled || !owner_seq_snapshot.valid) {
    return record;
  }

  if (rtcore_trace_invocation_publication_source_enabled() ||
      rtcore_compiler_driver_publication_source_enabled()) {
    record.source = rtcore_compiler_driver_publication_source_enabled()
                        ? "compiler_driver_publication_sideband"
                        : "trace_invocation_publication_source_shadow";
    rtcore_trace_invocation_publication_source_shadow source_shadow;
    if (!rtcore_consume_trace_invocation_publication_source_shadow(
            request.thread, &source_shadow)) {
      return record;
    }
    record.source = source_shadow.source;
    record.source_publication_seq = source_shadow.source_publication_seq;
    record.source_owner_tuple_match = source_shadow.owner_tuple_match;
    record.has_source_context_window_key = source_shadow.has_context_window_owner_key;
    record.source_context_window_match =
        !source_shadow.has_context_window_owner_key ||
        (source_shadow.context_ptr == request.context_ptr &&
         source_shadow.handoff_window_base == request.handoff_window_base);
    if (!record.source_context_window_match) {
      return record;
    }
    record.ray_origin = source_shadow.ray_origin;
    record.ray_direction = source_shadow.ray_direction;
    record.ray_tmin = source_shadow.ray_tmin;
    record.ray_tmax = source_shadow.ray_tmax;
    record.has_ray_origin_direction_tmin_tmax = true;
    record.ray_flags = source_shadow.ray_flags;
    record.cull_mask = source_shadow.cull_mask;
    record.has_ray_flags_cull_mask = true;
    record.bridge_trace_replay_top_level_as = source_shadow.top_level_as;
    record.sbt_record_offset = source_shadow.sbt_record_offset;
    record.sbt_record_stride = source_shadow.sbt_record_stride;
    record.miss_index = source_shadow.miss_index;
    record.has_launch_context_input = source_shadow.has_top_level_as;
    rtcore_apply_launch_context_input_publication_failpoint(request.pI, &record);
    record.valid = record.has_ray_origin_direction_tmin_tmax &&
                   record.has_ray_flags_cull_mask &&
                   record.has_launch_context_input &&
                   record.source_owner_tuple_match &&
                   record.source_context_window_match;
    return record;
  }

  if (!pre_provider_traversal_data_snapshot.valid) {
    return record;
  }

  const Traversal_data &traversal =
      pre_provider_traversal_data_snapshot.traversal_snapshot;
  record.ray_origin = traversal.ray_world_origin;
  record.ray_direction = traversal.ray_world_direction;
  record.ray_tmin = traversal.Tmin;
  record.ray_tmax = traversal.Tmax;
  record.has_ray_origin_direction_tmin_tmax = true;
  record.ray_flags = traversal.rayFlags;
  record.cull_mask = traversal.cullMask;
  record.has_ray_flags_cull_mask = true;
  record.bridge_trace_replay_top_level_as =
      traversal.rtcore_trace_input_top_level_as;
  record.sbt_record_offset = traversal.sbtRecordOffset;
  record.sbt_record_stride = traversal.sbtRecordStride;
  record.miss_index = traversal.missIndex;
  record.has_launch_context_input =
      traversal.rtcore_trace_input_has_top_level_as != 0;
  rtcore_apply_launch_context_input_publication_failpoint(request.pI, &record);
  record.valid = record.has_ray_origin_direction_tmin_tmax &&
                 record.has_ray_flags_cull_mask &&
                 record.has_launch_context_input;
  return record;
}

static bool rtcore_compiler_driver_sideband_requires_context_window_key(
    const rtcore_launch_context_input_publication_record &record) {
  if (strcmp(record.source, "compiler_driver_publication_sideband") != 0) {
    return true;
  }
  return record.has_source_context_window_key &&
         record.source_context_window_match;
}

static bool rtcore_launch_context_input_publication_record_is_complete(
    const rtcore_launch_context_input_publication_record &record) {
  return record.valid && record.has_ray_origin_direction_tmin_tmax &&
         record.has_ray_flags_cull_mask && record.has_launch_context_input &&
         record.owner_seq_snapshot.valid && record.source_context_window_match &&
         rtcore_compiler_driver_sideband_requires_context_window_key(record);
}

static void rtcore_log_launch_context_input_publication_record(
    const ptx_instruction *pI,
    const rtcore_launch_context_input_publication_record &record) {
  if (!record.publication_enabled) {
    return;
  }
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "launch-context-input-publication-bridge (%s:%u), "
         "source=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, valid=%u, "
         "source_publication_seq=%llu, source_owner_tuple_match=%u, "
         "has_source_context_window_key=%u, "
         "source_context_window_match=%u, "
         "has_ray_origin_direction_tmin_tmax=%u, "
         "has_ray_flags_cull_mask=%u, has_launch_context_input=%u, "
         "ray_flags=%u, cull_mask=%u, bridge_trace_replay_top_level_as=0x%llx, "
         "sbt_record_offset=%u, sbt_record_stride=%u, miss_index=%u\n",
         pI->source_file(), pI->source_line(), record.source,
         record.context_ptr, record.handoff_window_base,
         record.lane_slot_index, record.valid ? 1 : 0,
         record.source_publication_seq,
         record.source_owner_tuple_match ? 1 : 0,
         record.has_source_context_window_key ? 1 : 0,
         record.source_context_window_match ? 1 : 0,
         record.has_ray_origin_direction_tmin_tmax ? 1 : 0,
         record.has_ray_flags_cull_mask ? 1 : 0,
         record.has_launch_context_input ? 1 : 0, record.ray_flags,
         record.cull_mask,
         (unsigned long long)record.bridge_trace_replay_top_level_as,
         record.sbt_record_offset, record.sbt_record_stride,
         record.miss_index);
  fflush(stdout);
}

static bool rtcore_fail_closed_on_launch_context_input_publication_record(
    const ptx_instruction *pI,
    const rtcore_launch_context_input_publication_record &record) {
  if (!record.publication_enabled ||
      rtcore_launch_context_input_publication_record_is_complete(record)) {
    return false;
  }
  printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
         "reason=LAUNCH_CONTEXT_INPUT_PUBLICATION_PARTIAL, "
         "source=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, valid=%u, owner_seq_valid=%u, "
         "source_publication_seq=%llu, source_owner_tuple_match=%u, "
         "has_source_context_window_key=%u, "
         "source_context_window_match=%u, "
         "has_ray_origin_direction_tmin_tmax=%u, "
         "has_ray_flags_cull_mask=%u, has_launch_context_input=%u\n",
         pI->source_file(), pI->source_line(), record.source,
         record.context_ptr, record.handoff_window_base,
         record.lane_slot_index, record.valid ? 1 : 0,
         record.owner_seq_snapshot.valid ? 1 : 0,
         record.source_publication_seq,
         record.source_owner_tuple_match ? 1 : 0,
         record.has_source_context_window_key ? 1 : 0,
         record.source_context_window_match ? 1 : 0,
         record.has_ray_origin_direction_tmin_tmax ? 1 : 0,
         record.has_ray_flags_cull_mask ? 1 : 0,
         record.has_launch_context_input ? 1 : 0);
  fflush(stdout);
  return true;
}

static void
rtcore_apply_launch_context_input_publication_record_to_decoded_snapshot(
    rtcore_decoded_traversal_input_snapshot *decoded_input_snapshot,
    const rtcore_launch_context_input_publication_record &record) {
  if (decoded_input_snapshot == NULL ||
      !rtcore_launch_context_input_publication_record_is_complete(record)) {
    return;
  }
  const rtcore_decoded_input_field_owner_class publication_owner =
      rtcore_decoded_input_owner_from_publication_source(record.source);
  decoded_input_snapshot->ray_origin = record.ray_origin;
  decoded_input_snapshot->ray_direction = record.ray_direction;
  decoded_input_snapshot->ray_tmin = record.ray_tmin;
  decoded_input_snapshot->ray_tmax = record.ray_tmax;
  decoded_input_snapshot->has_ray_origin_direction_tmin_tmax =
      record.has_ray_origin_direction_tmin_tmax;
  decoded_input_snapshot->ray_origin_direction_tmin_tmax_owner =
      publication_owner;
  decoded_input_snapshot->ray_flags = record.ray_flags;
  decoded_input_snapshot->cull_mask = record.cull_mask;
  decoded_input_snapshot->has_ray_flags_cull_mask =
      record.has_ray_flags_cull_mask;
  decoded_input_snapshot->ray_flags_cull_mask_owner = publication_owner;
  decoded_input_snapshot->bridge_trace_replay_top_level_as =
      record.bridge_trace_replay_top_level_as;
  decoded_input_snapshot->sbt_record_offset = record.sbt_record_offset;
  decoded_input_snapshot->sbt_record_stride = record.sbt_record_stride;
  decoded_input_snapshot->miss_index = record.miss_index;
  decoded_input_snapshot->has_launch_context_input =
      record.has_launch_context_input;
  decoded_input_snapshot->launch_context_input_owner = publication_owner;
}

