static rtcore_runtime_as_proxy_registry_key
rtcore_make_runtime_as_proxy_registry_key(
    const rtcore_traversal_source_request &source_request,
    const rtcore_context_window_owner_seq_snapshot &owner_seq_snapshot,
    const rtcore_driver_runtime_context_window_lifetime_bridge_snapshot
        &lifetime_bridge_snapshot,
    const rtcore_launch_context_input_publication_record
        &launch_context_input_publication_record) {
  rtcore_runtime_as_proxy_registry_key key;
  key.context_ptr = source_request.context_ptr;
  key.handoff_window_base = source_request.handoff_window_base;
  key.lane_slot_index = source_request.lane_slot_index;
  key.owner_generation = lifetime_bridge_snapshot.owner_generation;
  key.owner_hw_sid = owner_seq_snapshot.warp_metadata.owner_hw_sid;
  key.warp_uid = owner_seq_snapshot.warp_metadata.warp_uid;
  key.warp_id = owner_seq_snapshot.warp_metadata.warp_id;
  key.has_top_level_as =
      launch_context_input_publication_record.has_launch_context_input;
  key.top_level_as =
      launch_context_input_publication_record.bridge_trace_replay_top_level_as;
  key.valid = owner_seq_snapshot.valid && lifetime_bridge_snapshot.valid &&
              lifetime_bridge_snapshot.provider_lifetime_ready &&
              rtcore_launch_context_input_publication_record_is_complete(
                  launch_context_input_publication_record) &&
              key.has_top_level_as && key.owner_generation != 0;
  return key;
}

static rtcore_runtime_as_proxy_registry_entry
rtcore_publish_runtime_as_proxy_registry_entry(
    const rtcore_runtime_as_proxy_registry_key &key,
    const rtcore_pre_provider_traversal_data_snapshot
        &pre_provider_traversal_data_snapshot,
    const rtcore_bvh_format_profile_object_bridge_snapshot
        &bvh_format_profile_object_bridge_snapshot) {
  rtcore_runtime_as_proxy_registry_entry entry;
  entry.key = key;
  entry.proxy_token_source = rtcore_top_level_as_proxy_token_source_label();
  entry.bvh_format_version =
      bvh_format_profile_object_bridge_snapshot.bvh_format_version;
  entry.profile_object_source =
      bvh_format_profile_object_bridge_snapshot.profile_object_source;
  entry.profile_ref_source =
      bvh_format_profile_object_bridge_snapshot.profile_ref_source;
  entry.profile_ref = bvh_format_profile_object_bridge_snapshot.profile_ref;
  entry.has_bvh_format_profile_object =
      bvh_format_profile_object_bridge_snapshot.has_bvh_format_profile_object;
  entry.selected_compatibility_backend_profile =
      bvh_format_profile_object_bridge_snapshot
          .selected_compatibility_backend_profile;
  entry.bvh_format_profile_object_bridge_passed =
      bvh_format_profile_object_bridge_snapshot
          .bvh_format_profile_object_bridge_passed;
  if (!key.valid || !pre_provider_traversal_data_snapshot.valid) {
    return entry;
  }

  const Traversal_data &traversal =
      pre_provider_traversal_data_snapshot.traversal_snapshot;
  const bool traversal_top_level_as_match =
      traversal.rtcore_trace_input_has_top_level_as != 0 &&
      traversal.rtcore_trace_input_top_level_as == key.top_level_as;
  entry.traversable_proxy_id = traversal.rtcore_traversable_proxy_id;
  entry.root_proxy_id = traversal.rtcore_root_proxy_id;
  entry.valid = traversal_top_level_as_match &&
                entry.traversable_proxy_id != 0 && entry.root_proxy_id != 0;
  entry.live = entry.valid;
  entry.actual_abi_evidence_for_proxy_fields = false;
  if (entry.valid) {
    g_rtcore_runtime_as_proxy_registry[key] = entry;
  }
  return entry;
}

static void rtcore_recompute_runtime_as_proxy_registry_lookup_snapshot(
    rtcore_runtime_as_proxy_registry_lookup_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->entry_live =
      snapshot->entry_found && snapshot->entry.live && snapshot->entry.valid;
  snapshot->registry_owner_match =
      snapshot->entry_found &&
      rtcore_runtime_as_proxy_registry_owner_equal(snapshot->key,
                                                  snapshot->entry.key);
  snapshot->registry_generation_match =
      snapshot->entry_found &&
      snapshot->key.owner_generation == snapshot->entry.key.owner_generation;
  snapshot->top_level_as_match =
      snapshot->entry_found && snapshot->key.has_top_level_as &&
      snapshot->entry.key.has_top_level_as &&
      snapshot->key.top_level_as == snapshot->entry.key.top_level_as;
  snapshot->registry_key_match =
      snapshot->entry_found &&
      rtcore_runtime_as_proxy_registry_key_equal(snapshot->key,
                                                snapshot->entry.key);
  snapshot->has_proxy_token = snapshot->entry_live &&
                              snapshot->entry.traversable_proxy_id != 0 &&
                              snapshot->entry.root_proxy_id != 0;
  snapshot->has_bvh_format_profile_object =
      snapshot->entry_live && snapshot->entry.has_bvh_format_profile_object &&
      snapshot->entry.profile_object_source != NULL &&
      strcmp(snapshot->entry.profile_object_source,
             rtcore_bvh_format_profile_object_bridge_source_label()) == 0;
  snapshot->selected_compatibility_backend_profile =
      snapshot->entry_live &&
      snapshot->entry.selected_compatibility_backend_profile &&
      snapshot->entry.bvh_format_version ==
          RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT;
  snapshot->bvh_format_profile_object_bridge_passed =
      snapshot->has_bvh_format_profile_object &&
      snapshot->selected_compatibility_backend_profile &&
      snapshot->entry.bvh_format_profile_object_bridge_passed;
  snapshot->has_profile_ref =
      snapshot->bvh_format_profile_object_bridge_passed &&
      snapshot->entry.bvh_format_version ==
          RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT &&
      snapshot->entry.profile_ref_source != NULL &&
      strcmp(snapshot->entry.profile_ref_source,
             rtcore_bvh_format_profile_ref_source_label()) == 0 &&
      snapshot->entry.profile_ref != NULL &&
      strcmp(snapshot->entry.profile_ref,
             "RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT") == 0;
  snapshot->profile_object_source =
      snapshot->entry_found && snapshot->entry.profile_object_source != NULL
          ? snapshot->entry.profile_object_source
          : "unavailable";
  snapshot->profile_ref_source =
      snapshot->entry_found && snapshot->entry.profile_ref_source != NULL
          ? snapshot->entry.profile_ref_source
          : "unavailable";
  snapshot->profile_ref =
      snapshot->has_profile_ref ? snapshot->entry.profile_ref : "unavailable";
  snapshot->proxy_token_source =
      snapshot->entry_found && snapshot->entry.proxy_token_source != NULL &&
              strcmp(snapshot->entry.proxy_token_source, "unavailable") != 0
          ? snapshot->entry.proxy_token_source
          : rtcore_top_level_as_proxy_token_source_label();
  snapshot->registry_lookup_passed =
      snapshot->key.valid && snapshot->entry_found && snapshot->entry_live &&
      snapshot->registry_key_match && snapshot->registry_owner_match &&
      snapshot->registry_generation_match && snapshot->top_level_as_match &&
      snapshot->has_proxy_token && snapshot->has_profile_ref;
  snapshot->valid = snapshot->registry_lookup_passed;
  snapshot->actual_abi_evidence_for_proxy_fields = false;
}

static rtcore_runtime_as_proxy_registry_lookup_snapshot
rtcore_lookup_runtime_as_proxy_registry_entry(
    const rtcore_runtime_as_proxy_registry_key &key) {
  rtcore_runtime_as_proxy_registry_lookup_snapshot snapshot;
  snapshot.key = key;
  std::map<rtcore_runtime_as_proxy_registry_key,
           rtcore_runtime_as_proxy_registry_entry>::const_iterator entry =
      g_rtcore_runtime_as_proxy_registry.find(key);
  if (entry != g_rtcore_runtime_as_proxy_registry.end()) {
    snapshot.entry_found = true;
    snapshot.entry = entry->second;
  }
  rtcore_recompute_runtime_as_proxy_registry_lookup_snapshot(&snapshot);
  return snapshot;
}

enum rtcore_runtime_as_proxy_registry_failpoint {
  RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE = 0,
  RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_DROP_REGISTRY_ENTRY,
  RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_WRONG_OWNER,
  RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_STALE_GENERATION,
};

static const char *rtcore_runtime_as_proxy_registry_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_AS_PROXY_REGISTRY_FAILPOINT";
}

static rtcore_runtime_as_proxy_registry_failpoint
rtcore_runtime_as_proxy_registry_failpoint_mode() {
  const char *value =
      getenv(rtcore_runtime_as_proxy_registry_failpoint_env_name());
  if (value == NULL || value[0] == '\0' || strcmp(value, "0") == 0 ||
      strcmp(value, "none") == 0) {
    return RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE;
  }
  if (strcmp(value, "drop_registry_entry") == 0) {
    return RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_DROP_REGISTRY_ENTRY;
  }
  if (strcmp(value, "wrong_owner") == 0) {
    return RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_WRONG_OWNER;
  }
  if (strcmp(value, "stale_generation") == 0) {
    return RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_STALE_GENERATION;
  }
  return RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE;
}

static const char *rtcore_runtime_as_proxy_registry_failpoint_name(
    rtcore_runtime_as_proxy_registry_failpoint mode) {
  switch (mode) {
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_DROP_REGISTRY_ENTRY:
      return "drop_registry_entry";
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_WRONG_OWNER:
      return "wrong_owner";
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_STALE_GENERATION:
      return "stale_generation";
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE:
    default:
      return "none";
  }
}

static void
rtcore_apply_runtime_as_proxy_registry_failpoint_to_lookup_snapshot(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    rtcore_runtime_as_proxy_registry_lookup_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  const rtcore_runtime_as_proxy_registry_failpoint mode =
      rtcore_runtime_as_proxy_registry_failpoint_mode();
  if (mode == RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE) {
    return;
  }

  bool drop_registry_entry = false;
  bool wrong_owner = false;
  bool stale_generation = false;
  switch (mode) {
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_DROP_REGISTRY_ENTRY:
      snapshot->entry_found = false;
      snapshot->entry = rtcore_runtime_as_proxy_registry_entry();
      drop_registry_entry = true;
      break;
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_WRONG_OWNER:
      if (snapshot->entry_found) {
        snapshot->entry.key.owner_hw_sid = snapshot->key.owner_hw_sid + 1;
        if (snapshot->entry.key.owner_hw_sid == snapshot->key.owner_hw_sid) {
          snapshot->entry.key.owner_hw_sid = snapshot->key.owner_hw_sid ^ 1;
        }
      }
      wrong_owner = true;
      break;
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_STALE_GENERATION:
      if (snapshot->entry_found) {
        snapshot->entry.key.owner_generation = snapshot->key.owner_generation + 1;
        if (snapshot->entry.key.owner_generation ==
            snapshot->key.owner_generation) {
          snapshot->entry.key.owner_generation = snapshot->key.owner_generation ^ 1;
        }
      }
      stale_generation = true;
      break;
    case RTCORE_RUNTIME_AS_PROXY_REGISTRY_FAILPOINT_NONE:
    default:
      return;
  }
  rtcore_recompute_runtime_as_proxy_registry_lookup_snapshot(snapshot);

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "runtime-as-proxy-registry-failpoint=1, "
         "failpoint=%s, mode=%s, provider=%s, registry_source=%s, "
         "proxy_token_source=%s, context_ptr=0x%llx, "
         "handoff_window_base=0x%llx, lane_slot_index=%u, "
         "owner_generation=%u, top_level_as=0x%llx, "
         "drop_registry_entry=%u, wrong_owner=%u, stale_generation=%u, "
         "entry_found=%u, entry_live=%u, registry_key_match=%u, "
         "registry_owner_match=%u, registry_generation_match=%u, "
         "top_level_as_match=%u, has_bvh_format_profile_object=%u, "
         "has_profile_ref=%u, bvh_format_profile_object_bridge_passed=%u, "
         "registry_lookup_passed=%u, "
         "actual_abi_evidence_for_proxy_fields=0 (%s:%u)\n",
         rtcore_runtime_as_proxy_registry_failpoint_name(mode),
         rtcore_runtime_as_proxy_registry_failpoint_name(mode),
         rtcore_traversal_source_provider_name(source_request.provider),
         rtcore_runtime_as_proxy_registry_source_label(),
         snapshot->proxy_token_source, snapshot->key.context_ptr,
         snapshot->key.handoff_window_base, snapshot->key.lane_slot_index,
         snapshot->key.owner_generation,
         (unsigned long long)snapshot->key.top_level_as,
         drop_registry_entry ? 1 : 0, wrong_owner ? 1 : 0,
         stale_generation ? 1 : 0, snapshot->entry_found ? 1 : 0,
         snapshot->entry_live ? 1 : 0,
         snapshot->registry_key_match ? 1 : 0,
         snapshot->registry_owner_match ? 1 : 0,
         snapshot->registry_generation_match ? 1 : 0,
         snapshot->top_level_as_match ? 1 : 0,
         snapshot->has_bvh_format_profile_object ? 1 : 0,
         snapshot->has_profile_ref ? 1 : 0,
         snapshot->bvh_format_profile_object_bridge_passed ? 1 : 0,
         snapshot->registry_lookup_passed ? 1 : 0,
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0);
  fflush(stdout);
}

static void rtcore_log_runtime_as_proxy_registry_lookup_snapshot(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    const rtcore_runtime_as_proxy_registry_lookup_snapshot &snapshot) {
  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "runtime-as-proxy-registry-lookup=1, "
         "registry_source=%s, proxy_token_source=%s, provider=%s, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, owner_generation=%u, owner_hw_sid=%u, "
         "warp_uid=%u, warp_id=%u, has_top_level_as=%u, "
         "top_level_as=0x%llx, entry_found=%u, entry_live=%u, "
         "registry_key_match=%u, registry_owner_match=%u, "
         "registry_generation_match=%u, top_level_as_match=%u, "
         "has_proxy_token=%u, traversable_proxy_id=0x%llx, "
         "root_proxy_id=0x%llx, profile_object_source=%s, "
         "profile_ref_source=%s, has_bvh_format_profile_object=%u, "
         "has_profile_ref=%u, profile_ref=%s, "
         "bvh_format_version=%u, registry_lookup_passed=%u, "
         "selected_compatibility_backend_profile=%u, "
         "bvh_format_profile_object_bridge_passed=%u, "
         "actual_abi_evidence_for_proxy_fields=0 (%s:%u)\n",
         snapshot.registry_source, snapshot.proxy_token_source,
         rtcore_traversal_source_provider_name(source_request.provider),
         snapshot.key.context_ptr, snapshot.key.handoff_window_base,
         snapshot.key.lane_slot_index, snapshot.key.owner_generation,
         snapshot.key.owner_hw_sid, snapshot.key.warp_uid,
         snapshot.key.warp_id, snapshot.key.has_top_level_as ? 1 : 0,
         (unsigned long long)snapshot.key.top_level_as,
         snapshot.entry_found ? 1 : 0, snapshot.entry_live ? 1 : 0,
         snapshot.registry_key_match ? 1 : 0,
         snapshot.registry_owner_match ? 1 : 0,
         snapshot.registry_generation_match ? 1 : 0,
         snapshot.top_level_as_match ? 1 : 0,
         snapshot.has_proxy_token ? 1 : 0,
         (unsigned long long)snapshot.entry.traversable_proxy_id,
         (unsigned long long)snapshot.entry.root_proxy_id,
         snapshot.profile_object_source, snapshot.profile_ref_source,
         snapshot.has_bvh_format_profile_object ? 1 : 0,
         snapshot.has_profile_ref ? 1 : 0, snapshot.profile_ref,
         snapshot.entry.bvh_format_version,
         snapshot.registry_lookup_passed ? 1 : 0,
         snapshot.selected_compatibility_backend_profile ? 1 : 0,
         snapshot.bvh_format_profile_object_bridge_passed ? 1 : 0,
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0);
  fflush(stdout);
}

static bool rtcore_fail_closed_on_runtime_as_proxy_registry_lookup_snapshot(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    const rtcore_runtime_as_proxy_registry_lookup_snapshot &snapshot) {
  if (snapshot.valid) {
    return false;
  }
  printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
         "reason=RUNTIME_AS_PROXY_REGISTRY_NOT_READY, "
         "registry_source=%s, proxy_token_source=%s, provider=%s, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, owner_generation=%u, top_level_as=0x%llx, "
         "entry_found=%u, entry_live=%u, registry_key_match=%u, "
         "registry_owner_match=%u, registry_generation_match=%u, "
         "top_level_as_match=%u, has_proxy_token=%u, has_profile_ref=%u, "
         "profile_object_source=%s, profile_ref_source=%s, "
         "has_bvh_format_profile_object=%u, profile_ref=%s, "
         "selected_compatibility_backend_profile=%u, "
         "bvh_format_profile_object_bridge_passed=%u, "
         "registry_lookup_passed=%u, "
         "before_top_level_as_proxy_resolve_adapter=1, "
         "before_registry_payload_shadow=1, "
         "before_provider_consumed_input=1, before_backend_input_route=1, "
         "before_traversal_completion=1, before_completion_release=1, "
         "actual_abi_evidence_for_proxy_fields=0\n",
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0, snapshot.registry_source,
         snapshot.proxy_token_source,
         rtcore_traversal_source_provider_name(source_request.provider),
         snapshot.key.context_ptr, snapshot.key.handoff_window_base,
         snapshot.key.lane_slot_index, snapshot.key.owner_generation,
         (unsigned long long)snapshot.key.top_level_as,
         snapshot.entry_found ? 1 : 0, snapshot.entry_live ? 1 : 0,
         snapshot.registry_key_match ? 1 : 0,
         snapshot.registry_owner_match ? 1 : 0,
         snapshot.registry_generation_match ? 1 : 0,
         snapshot.top_level_as_match ? 1 : 0,
         snapshot.has_proxy_token ? 1 : 0,
         snapshot.has_profile_ref ? 1 : 0, snapshot.profile_object_source,
         snapshot.profile_ref_source,
         snapshot.has_bvh_format_profile_object ? 1 : 0,
         snapshot.profile_ref,
         snapshot.selected_compatibility_backend_profile ? 1 : 0,
         snapshot.bvh_format_profile_object_bridge_passed ? 1 : 0,
         snapshot.registry_lookup_passed ? 1 : 0);
  fflush(stdout);
  return true;
}

struct rtcore_resolve_table_runtime_proxy_consistency_snapshot {
  rtcore_resolve_table_runtime_proxy_consistency_snapshot()
      : valid(false),
        bridge_source(
            rtcore_resolve_table_runtime_proxy_consistency_bridge_source_label()),
        resolve_table_source("unavailable"),
        runtime_registry_source("unavailable"),
        proxy_token_source("unavailable"),
        has_driver_as_resolve_table_lookup(false),
        driver_as_resolve_table_lookup_passed(false),
        has_runtime_as_proxy_registry_lookup(false),
        runtime_as_proxy_registry_lookup_passed(false),
        registered_as_reference(0),
        runtime_top_level_as(0),
        registered_as_matches_runtime_top_level_as(false),
        owner_tuple_match(false),
        owner_generation_match(false),
        profile_ref_match(false),
        bvh_format_version_match(false),
        runtime_proxy_token_ready(false),
        runtime_proxy_bound_to_resolved_as_profile(false),
        resolve_runtime_proxy_bridge_passed(false),
        backend_root_descriptor_actual_producer_authority_enabled(false),
        runtime_proxy_consistency_bypassed_by_actual_producer_authority(false),
        actual_abi_evidence_for_proxy_fields(false),
        existing_traversal_backend_reused(true),
        claims_new_hardware_bvh_engine(false) {}

  bool valid;
  const char *bridge_source;
  const char *resolve_table_source;
  const char *runtime_registry_source;
  const char *proxy_token_source;
  bool has_driver_as_resolve_table_lookup;
  bool driver_as_resolve_table_lookup_passed;
  bool has_runtime_as_proxy_registry_lookup;
  bool runtime_as_proxy_registry_lookup_passed;
  uint64_t registered_as_reference;
  uint64_t runtime_top_level_as;
  bool registered_as_matches_runtime_top_level_as;
  bool owner_tuple_match;
  bool owner_generation_match;
  bool profile_ref_match;
  bool bvh_format_version_match;
  bool runtime_proxy_token_ready;
  bool runtime_proxy_bound_to_resolved_as_profile;
  bool resolve_runtime_proxy_bridge_passed;
  bool backend_root_descriptor_actual_producer_authority_enabled;
  bool runtime_proxy_consistency_bypassed_by_actual_producer_authority;
  bool actual_abi_evidence_for_proxy_fields;
  bool existing_traversal_backend_reused;
  bool claims_new_hardware_bvh_engine;
};

static void
rtcore_recompute_resolve_table_runtime_proxy_consistency_snapshot(
    rtcore_resolve_table_runtime_proxy_consistency_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  snapshot->runtime_proxy_bound_to_resolved_as_profile =
      snapshot->registered_as_matches_runtime_top_level_as &&
      snapshot->profile_ref_match && snapshot->bvh_format_version_match &&
      snapshot->runtime_proxy_token_ready &&
      !snapshot->actual_abi_evidence_for_proxy_fields;
  snapshot->resolve_runtime_proxy_bridge_passed =
      snapshot->has_driver_as_resolve_table_lookup &&
      snapshot->driver_as_resolve_table_lookup_passed &&
      snapshot->has_runtime_as_proxy_registry_lookup &&
      snapshot->runtime_as_proxy_registry_lookup_passed &&
      snapshot->owner_tuple_match && snapshot->owner_generation_match &&
      snapshot->runtime_proxy_bound_to_resolved_as_profile &&
      snapshot->existing_traversal_backend_reused &&
      !snapshot->claims_new_hardware_bvh_engine;
  // actual_producer_runtime_proxy_consistency_bypass_gate=1;
  snapshot->runtime_proxy_consistency_bypassed_by_actual_producer_authority =
      snapshot->backend_root_descriptor_actual_producer_authority_enabled;
  snapshot->valid =
      snapshot->resolve_runtime_proxy_bridge_passed ||
      snapshot->runtime_proxy_consistency_bypassed_by_actual_producer_authority;
}

static rtcore_resolve_table_runtime_proxy_consistency_snapshot
rtcore_make_resolve_table_runtime_proxy_consistency_snapshot(
    const rtcore_driver_as_resolve_table_lookup_snapshot
        &driver_as_resolve_table_lookup_snapshot,
    const rtcore_runtime_as_proxy_registry_lookup_snapshot
        &runtime_as_proxy_registry_lookup_snapshot) {
  rtcore_resolve_table_runtime_proxy_consistency_snapshot snapshot;
  snapshot.resolve_table_source =
      driver_as_resolve_table_lookup_snapshot.resolve_table_source;
  snapshot.runtime_registry_source =
      runtime_as_proxy_registry_lookup_snapshot.registry_source;
  snapshot.proxy_token_source =
      runtime_as_proxy_registry_lookup_snapshot.proxy_token_source;
  snapshot.has_driver_as_resolve_table_lookup =
      driver_as_resolve_table_lookup_snapshot.entry_found;
  snapshot.driver_as_resolve_table_lookup_passed =
      driver_as_resolve_table_lookup_snapshot.resolve_lookup_passed;
  snapshot.has_runtime_as_proxy_registry_lookup =
      runtime_as_proxy_registry_lookup_snapshot.entry_found;
  snapshot.runtime_as_proxy_registry_lookup_passed =
      runtime_as_proxy_registry_lookup_snapshot.registry_lookup_passed;
  snapshot.registered_as_reference =
      driver_as_resolve_table_lookup_snapshot.key.registered_as_reference;
  snapshot.runtime_top_level_as =
      runtime_as_proxy_registry_lookup_snapshot.key.top_level_as;
  snapshot.registered_as_matches_runtime_top_level_as =
      driver_as_resolve_table_lookup_snapshot.key.has_registered_as_reference &&
      runtime_as_proxy_registry_lookup_snapshot.key.has_top_level_as &&
      snapshot.registered_as_reference == snapshot.runtime_top_level_as;
  snapshot.owner_tuple_match =
      driver_as_resolve_table_lookup_snapshot.key.context_ptr ==
          runtime_as_proxy_registry_lookup_snapshot.key.context_ptr &&
      driver_as_resolve_table_lookup_snapshot.key.handoff_window_base ==
          runtime_as_proxy_registry_lookup_snapshot.key.handoff_window_base &&
      driver_as_resolve_table_lookup_snapshot.key.lane_slot_index ==
          runtime_as_proxy_registry_lookup_snapshot.key.lane_slot_index &&
      driver_as_resolve_table_lookup_snapshot.key.owner_hw_sid ==
          runtime_as_proxy_registry_lookup_snapshot.key.owner_hw_sid &&
      driver_as_resolve_table_lookup_snapshot.key.warp_uid ==
          runtime_as_proxy_registry_lookup_snapshot.key.warp_uid &&
      driver_as_resolve_table_lookup_snapshot.key.warp_id ==
          runtime_as_proxy_registry_lookup_snapshot.key.warp_id;
  snapshot.owner_generation_match =
      driver_as_resolve_table_lookup_snapshot.key.owner_generation ==
      runtime_as_proxy_registry_lookup_snapshot.key.owner_generation;
  snapshot.profile_ref_match =
      driver_as_resolve_table_lookup_snapshot.profile_state_match &&
      driver_as_resolve_table_lookup_snapshot.has_bvh_format_profile_object &&
      driver_as_resolve_table_lookup_snapshot
          .bvh_format_profile_object_bridge_passed &&
      runtime_as_proxy_registry_lookup_snapshot.has_profile_ref &&
      driver_as_resolve_table_lookup_snapshot.profile_ref != NULL &&
      runtime_as_proxy_registry_lookup_snapshot.profile_ref != NULL &&
      strcmp(driver_as_resolve_table_lookup_snapshot.profile_ref,
             runtime_as_proxy_registry_lookup_snapshot.profile_ref) == 0;
  snapshot.bvh_format_version_match =
      driver_as_resolve_table_lookup_snapshot.key.bvh_format_version ==
          runtime_as_proxy_registry_lookup_snapshot.entry.bvh_format_version &&
      driver_as_resolve_table_lookup_snapshot.key.bvh_format_version ==
          RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT;
  snapshot.runtime_proxy_token_ready =
      runtime_as_proxy_registry_lookup_snapshot.has_proxy_token &&
      runtime_as_proxy_registry_lookup_snapshot.entry.traversable_proxy_id != 0 &&
      runtime_as_proxy_registry_lookup_snapshot.entry.root_proxy_id != 0 &&
      !runtime_as_proxy_registry_lookup_snapshot
           .actual_abi_evidence_for_proxy_fields;
  snapshot.actual_abi_evidence_for_proxy_fields =
      driver_as_resolve_table_lookup_snapshot
          .actual_abi_evidence_for_proxy_fields ||
      runtime_as_proxy_registry_lookup_snapshot
          .actual_abi_evidence_for_proxy_fields;
  const rtcore_backend_root_descriptor_actual_producer_evidence_snapshot
      actual_producer_evidence_snapshot =
          rtcore_make_backend_root_descriptor_actual_producer_evidence_snapshot(
              driver_as_resolve_table_lookup_snapshot);
  snapshot.backend_root_descriptor_actual_producer_authority_enabled =
      rtcore_backend_root_descriptor_actual_producer_consumption_opt_in_requested() &&
      actual_producer_evidence_snapshot.evidence_ready;
  snapshot.existing_traversal_backend_reused = true;
  snapshot.claims_new_hardware_bvh_engine = false;
  rtcore_recompute_resolve_table_runtime_proxy_consistency_snapshot(
      &snapshot);
  return snapshot;
}

enum rtcore_resolve_table_runtime_proxy_consistency_failpoint {
  RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE = 0,
  RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_OWNER,
  RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_REGISTERED_AS_REFERENCE,
  RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_PROFILE_MISMATCH,
  RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_DROP_PROXY_BINDING,
};

static const char *
rtcore_resolve_table_runtime_proxy_consistency_failpoint_env_name() {
  return "VULKAN_SIM_RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_BRIDGE_FAILPOINT";
}

static rtcore_resolve_table_runtime_proxy_consistency_failpoint
rtcore_resolve_table_runtime_proxy_consistency_failpoint_mode() {
  const char *value = getenv(
      rtcore_resolve_table_runtime_proxy_consistency_failpoint_env_name());
  if (value == NULL || value[0] == '\0' || strcmp(value, "0") == 0 ||
      strcmp(value, "none") == 0) {
    return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE;
  }
  if (strcmp(value, "wrong_owner") == 0) {
    return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_OWNER;
  }
  if (strcmp(value, "wrong_registered_as_reference") == 0) {
    return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_REGISTERED_AS_REFERENCE;
  }
  if (strcmp(value, "profile_mismatch") == 0) {
    return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_PROFILE_MISMATCH;
  }
  if (strcmp(value, "drop_proxy_binding") == 0) {
    return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_DROP_PROXY_BINDING;
  }
  return RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE;
}

static const char *
rtcore_resolve_table_runtime_proxy_consistency_failpoint_name(
    rtcore_resolve_table_runtime_proxy_consistency_failpoint mode) {
  switch (mode) {
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_OWNER:
      return "wrong_owner";
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_REGISTERED_AS_REFERENCE:
      return "wrong_registered_as_reference";
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_PROFILE_MISMATCH:
      return "profile_mismatch";
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_DROP_PROXY_BINDING:
      return "drop_proxy_binding";
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE:
    default:
      return "none";
  }
}

static void rtcore_apply_resolve_table_runtime_proxy_consistency_failpoint(
    const ptx_instruction *pI,
    const rtcore_traversal_source_request &source_request,
    rtcore_resolve_table_runtime_proxy_consistency_snapshot *snapshot) {
  if (snapshot == NULL) {
    return;
  }
  const rtcore_resolve_table_runtime_proxy_consistency_failpoint mode =
      rtcore_resolve_table_runtime_proxy_consistency_failpoint_mode();
  if (mode == RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE) {
    return;
  }

  bool wrong_owner = false;
  bool wrong_registered_as_reference = false;
  bool profile_mismatch = false;
  bool drop_proxy_binding = false;
  switch (mode) {
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_OWNER:
      snapshot->owner_tuple_match = false;
      wrong_owner = true;
      break;
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_WRONG_REGISTERED_AS_REFERENCE:
      snapshot->registered_as_matches_runtime_top_level_as = false;
      wrong_registered_as_reference = true;
      break;
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_PROFILE_MISMATCH:
      snapshot->profile_ref_match = false;
      snapshot->bvh_format_version_match = false;
      profile_mismatch = true;
      break;
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_DROP_PROXY_BINDING:
      snapshot->runtime_proxy_token_ready = false;
      drop_proxy_binding = true;
      break;
    case RTCORE_RESOLVE_TABLE_RUNTIME_PROXY_CONSISTENCY_FAILPOINT_NONE:
    default:
      return;
  }
  rtcore_recompute_resolve_table_runtime_proxy_consistency_snapshot(snapshot);

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "resolve-runtime-proxy-consistency-failpoint=1, "
         "failpoint=%s, mode=%s, provider=%s, "
         "resolve_runtime_proxy_bridge_source=%s, "
         "resolve_table_source=%s, runtime_registry_source=%s, "
         "proxy_token_source=%s, context_ptr=0x%llx, "
         "handoff_window_base=0x%llx, lane_slot_index=%u, "
         "wrong_owner=%u, wrong_registered_as_reference=%u, "
         "profile_mismatch=%u, drop_proxy_binding=%u, "
         "registered_as_matches_runtime_top_level_as=%u, "
         "owner_tuple_match=%u, owner_generation_match=%u, "
         "profile_ref_match=%u, bvh_format_version_match=%u, "
         "runtime_proxy_token_ready=%u, "
         "runtime_proxy_bound_to_resolved_as_profile=%u, "
         "resolve_runtime_proxy_bridge_passed=%u, "
         "backend_root_descriptor_actual_producer_authority_enabled=%u, "
         "runtime_proxy_consistency_bypassed_by_actual_producer_authority=%u, "
         "actual_abi_evidence_for_proxy_fields=0 (%s:%u)\n",
         rtcore_resolve_table_runtime_proxy_consistency_failpoint_name(mode),
         rtcore_resolve_table_runtime_proxy_consistency_failpoint_name(mode),
         rtcore_traversal_source_provider_name(source_request.provider),
         snapshot->bridge_source, snapshot->resolve_table_source,
         snapshot->runtime_registry_source, snapshot->proxy_token_source,
         source_request.context_ptr, source_request.handoff_window_base,
         source_request.lane_slot_index, wrong_owner ? 1 : 0,
         wrong_registered_as_reference ? 1 : 0, profile_mismatch ? 1 : 0,
         drop_proxy_binding ? 1 : 0,
         snapshot->registered_as_matches_runtime_top_level_as ? 1 : 0,
         snapshot->owner_tuple_match ? 1 : 0,
         snapshot->owner_generation_match ? 1 : 0,
         snapshot->profile_ref_match ? 1 : 0,
         snapshot->bvh_format_version_match ? 1 : 0,
         snapshot->runtime_proxy_token_ready ? 1 : 0,
         snapshot->runtime_proxy_bound_to_resolved_as_profile ? 1 : 0,
         snapshot->resolve_runtime_proxy_bridge_passed ? 1 : 0,
         snapshot->backend_root_descriptor_actual_producer_authority_enabled
             ? 1
             : 0,
         snapshot
                 ->runtime_proxy_consistency_bypassed_by_actual_producer_authority
             ? 1
             : 0,
         pI != NULL ? pI->source_file() : "<unknown>",
         pI != NULL ? pI->source_line() : 0);
  fflush(stdout);
}

