static void
rtcore_annotate_provider_response_with_registry_payload_observation(
    rtcore_traversal_provider_response *response,
    const rtcore_traversal_work_descriptor &descriptor) {
  if (response == NULL) {
    return;
  }

  rtcore_registry_payload_response_annotation &annotation =
      response->registry_payload_response_annotation;
  annotation.provider_payload_consumption_enabled =
      descriptor.provider_payload_consumption_enabled;

  if (!descriptor.has_registry_payload_shadow ||
      descriptor.registry_payload_shadow == NULL) {
    return;
  }

  const rtcore_provider_facing_registry_payload_shadow &shadow =
      *descriptor.registry_payload_shadow;
  if (!shadow.valid) {
    return;
  }

  annotation.valid = true;
  annotation.observed_valid_shadow = true;
  annotation.has_ray_origin_direction_tmin_tmax =
      shadow.has_ray_origin_direction_tmin_tmax;
  annotation.has_ray_flags_cull_mask = shadow.has_ray_flags_cull_mask;
  annotation.has_launch_context_input = shadow.has_launch_context_input;
  annotation.has_traversable_root_proxy = shadow.has_traversable_root_proxy;
  annotation.has_bvh_format_profile = shadow.has_bvh_format_profile;
  annotation.bvh_format_version = shadow.bvh_format_version;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "provider-response-registry-payload-annotation, provider=%s, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, provider-response-registry-payload-annotation=1, "
         "registry_payload_response_annotation_valid=1, "
         "registry_payload_shadow_observed=1, "
         "provider_payload_consumption_enabled=%u, "
         "response_annotation_consumes_traversal_behavior=0, "
         "has_ray_origin_direction_tmin_tmax=%u, has_ray_flags_cull_mask=%u, "
         "has_launch_context_input=%u, has_traversable_root_proxy=%u, "
         "has_bvh_format_profile=%u, bvh_format_version=%u\n",
         rtcore_traversal_source_provider_name(descriptor.provider),
         descriptor.context_ptr, descriptor.handoff_window_base,
         descriptor.lane_slot_index,
         annotation.provider_payload_consumption_enabled ? 1 : 0,
         annotation.has_ray_origin_direction_tmin_tmax ? 1 : 0,
         annotation.has_ray_flags_cull_mask ? 1 : 0,
         annotation.has_launch_context_input ? 1 : 0,
         annotation.has_traversable_root_proxy ? 1 : 0,
         annotation.has_bvh_format_profile ? 1 : 0,
         annotation.bvh_format_version);
  fflush(stdout);
}

struct rtcore_traversal_completion_event {
  rtcore_traversal_completion_event()
      : warp_metadata(),
        context_ptr(0),
        handoff_window_base(0),
        lane_slot_index(0),
        window_generation(0),
        completion_seq_low(0),
        resume_seq_low(0),
        window_tag(0),
        reason(0),
        completion_flags(0),
        result_word(0),
        provider_backend_input_completion_event_annotation(),
        has_traversal_data(false),
        hit_geometry(false) {
    memset(&traversal_snapshot, 0, sizeof(traversal_snapshot));
    memset(&handoff_key, 0, sizeof(handoff_key));
    memset(&token_key, 0, sizeof(token_key));
    memset(&reservation_key, 0, sizeof(reservation_key));
    memset(&header, 0, sizeof(header));
  }

  Traversal_data traversal_snapshot;
  ptx_thread_info::rtcore_current_warp_metadata warp_metadata;
  rtcore_synthetic_handoff_key handoff_key;
  rtcore_symbolic_rt_token_key token_key;
  rtcore_symbolic_rt_token_reservation_key reservation_key;
  rtcore_context_window_owner_seq_snapshot owner_seq_snapshot;
  rtcore_driver_runtime_context_window_lifetime_bridge_snapshot
      driver_runtime_context_window_lifetime_bridge_snapshot;
  rtcore_decoded_traversal_input_snapshot decoded_input_snapshot;
  rtcore_provider_facing_registry_payload_shadow registry_payload_shadow;
  unsigned long long context_ptr;
  unsigned long long handoff_window_base;
  unsigned lane_slot_index;
  unsigned window_generation;
  unsigned completion_seq_low;
  unsigned resume_seq_low;
  unsigned window_tag;
  unsigned reason;
  unsigned completion_flags;
  unsigned result_word;
  rtcore_traversal_completion_provider_backend_input_annotation
      provider_backend_input_completion_event_annotation;
  rtcore_synthetic_handoff_header header;
  bool has_traversal_data;
  bool hit_geometry;
};

static void
rtcore_copy_source_snapshot_backend_input_annotation_to_completion_event(
    rtcore_traversal_completion_event *event,
    const rtcore_traversal_source_snapshot &snapshot) {
  if (event == NULL ||
      !snapshot.provider_backend_input_source_snapshot_annotation.valid) {
    return;
  }

  const rtcore_traversal_source_provider_backend_input_annotation
      &source_annotation =
          snapshot.provider_backend_input_source_snapshot_annotation;
  rtcore_traversal_completion_provider_backend_input_annotation &annotation =
      event->provider_backend_input_completion_event_annotation;
  annotation.valid = true;
  annotation.provider_payload_consumption_enabled =
      source_annotation.provider_payload_consumption_enabled;
  annotation.backend_input_snapshot_required =
      source_annotation.backend_input_snapshot_required;
  annotation.has_provider_payload_backend_input_snapshot =
      source_annotation.has_provider_payload_backend_input_snapshot;
  annotation.provider_payload_backend_input_snapshot_valid =
      source_annotation.provider_payload_backend_input_snapshot_valid;
  annotation.provider_payload_backend_input_snapshot_accepted =
      source_annotation.provider_payload_backend_input_snapshot_accepted;
  annotation.has_provider_materialized_traversal_input_snapshot =
      source_annotation.has_provider_materialized_traversal_input_snapshot;
  annotation.provider_materialized_traversal_input_snapshot_valid =
      source_annotation.provider_materialized_traversal_input_snapshot_valid;
  annotation.provider_materialized_traversal_input_snapshot_source =
      source_annotation.provider_materialized_traversal_input_snapshot_source;
  annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      source_annotation
          .provider_materialized_traversal_input_actual_abi_snapshot_admitted;

  printf("GPGPU-Sim PTX: RT_SUBMIT "
         "traversal-completion-provider-backend-input-annotation, "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, "
         "traversal-completion-provider-backend-input-annotation=1, "
         "provider_backend_input_completion_event_annotation_valid=1, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_completion_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "completion_event_backend_input_annotation_consumes_traversal_behavior=0\n",
         event->context_ptr, event->handoff_window_base,
         event->lane_slot_index,
         annotation.provider_payload_consumption_enabled ? 1 : 0,
         annotation.backend_input_snapshot_required ? 1 : 0,
         annotation.has_provider_payload_backend_input_snapshot ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_valid ? 1 : 0,
         annotation.provider_payload_backend_input_snapshot_accepted ? 1 : 0,
         annotation.has_provider_materialized_traversal_input_snapshot ? 1 : 0,
         annotation.provider_materialized_traversal_input_snapshot_valid ? 1
                                                                         : 0,
         annotation.provider_materialized_traversal_input_snapshot_source,
         annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
}

static void rtcore_apply_traversal_source_snapshot(
    rtcore_traversal_completion_event *event,
    const rtcore_traversal_source_snapshot &snapshot) {
  if (event == NULL) {
    return;
  }
  event->has_traversal_data = snapshot.has_traversal_data;
  event->traversal_snapshot = snapshot.traversal_snapshot;
  event->hit_geometry = snapshot.hit_geometry;
  rtcore_copy_source_snapshot_backend_input_annotation_to_completion_event(
      event, snapshot);
}

static void
rtcore_copy_completion_backend_input_annotation_to_pending(
    rtcore_pending_traversal_completion *record,
    const rtcore_traversal_completion_event &event) {
  if (record == NULL ||
      !event.provider_backend_input_completion_event_annotation.valid) {
    return;
  }

  const rtcore_traversal_completion_provider_backend_input_annotation
      &event_annotation =
          event.provider_backend_input_completion_event_annotation;
  rtcore_traversal_completion_provider_backend_input_annotation &annotation =
      record->provider_backend_input_pending_completion_annotation;
  annotation.valid = true;
  annotation.provider_payload_consumption_enabled =
      event_annotation.provider_payload_consumption_enabled;
  annotation.backend_input_snapshot_required =
      event_annotation.backend_input_snapshot_required;
  annotation.has_provider_payload_backend_input_snapshot =
      event_annotation.has_provider_payload_backend_input_snapshot;
  annotation.provider_payload_backend_input_snapshot_valid =
      event_annotation.provider_payload_backend_input_snapshot_valid;
  annotation.provider_payload_backend_input_snapshot_accepted =
      event_annotation.provider_payload_backend_input_snapshot_accepted;
  annotation.has_provider_materialized_traversal_input_snapshot =
      event_annotation.has_provider_materialized_traversal_input_snapshot;
  annotation.provider_materialized_traversal_input_snapshot_valid =
      event_annotation.provider_materialized_traversal_input_snapshot_valid;
  annotation.provider_materialized_traversal_input_snapshot_source =
      event_annotation.provider_materialized_traversal_input_snapshot_source;
  annotation.provider_materialized_traversal_input_actual_abi_snapshot_admitted =
      event_annotation
          .provider_materialized_traversal_input_actual_abi_snapshot_admitted;
}

rtcore_pending_traversal_completion
rtcore_make_pending_traversal_completion_from_event(
    const rtcore_traversal_completion_event &event) {
  rtcore_pending_traversal_completion record;
  record.valid = true;
  record.warp_uid = event.warp_metadata.warp_uid;
  record.warp_id = event.warp_metadata.warp_id;
  record.owner_hw_sid = event.warp_metadata.owner_hw_sid;
  record.active_mask = event.warp_metadata.active_mask;
  record.static_inst_uid = event.warp_metadata.static_inst_uid;
  record.lane_slot_index = event.lane_slot_index;
  record.lane_thread_mask =
      rtcore_lane_thread_mask(event.lane_slot_index);
  record.context_ptr = event.context_ptr;
  record.handoff_window_base = event.handoff_window_base;
  record.result_word = event.result_word;
  record.window_generation = event.window_generation;
  record.completion_seq_low = event.completion_seq_low;
  record.resume_seq_low = event.resume_seq_low;
  record.window_tag = event.window_tag;
  record.reason = event.reason;
  record.traversal_snapshot = event.traversal_snapshot;
  rtcore_copy_completion_backend_input_annotation_to_pending(&record, event);
  return record;
}

