rtcore_adapter_completion_publication
rtcore_make_adapter_completion_publication_from_event(
    const rtcore_traversal_completion_event &event) {
  rtcore_adapter_completion_publication publication;
  publication.warp_uid = event.warp_metadata.warp_uid;
  publication.warp_id = event.warp_metadata.warp_id;
  publication.owner_hw_sid = event.warp_metadata.owner_hw_sid;
  publication.active_mask = event.warp_metadata.active_mask;
  publication.static_inst_uid = event.warp_metadata.static_inst_uid;
  publication.lane_slot_index = event.lane_slot_index;
  publication.lane_thread_mask =
      rtcore_lane_thread_mask(event.lane_slot_index);
  publication.node_visits = event.traversal_snapshot.rtcore_node_visits;
  publication.primitive_tests =
      event.traversal_snapshot.rtcore_primitive_tests;
  rtcore_copy_completion_backend_input_annotation_to_publication(&publication,
                                                                event);
  return publication;
}

static bool rtcore_enqueue_pending_traversal_completion(
    const rtcore_traversal_completion_event &event) {
  if (rtcore_test_adapter_claim_failure_enabled()) {
    return false;
  }

  rtcore_pending_traversal_completion record =
      rtcore_make_pending_traversal_completion_from_event(event);
  const bool test_metadata_mismatch =
      rtcore_test_delayed_completion_metadata_mismatch_enabled();
  if (test_metadata_mismatch) {
    record.owner_hw_sid = event.warp_metadata.owner_hw_sid + 1;
  }

  const std::pair<unsigned, unsigned> key =
      std::make_pair(record.warp_uid, record.lane_slot_index);
  g_rtcore_pending_traversal_completions[key] = record;
  const rtcore_traversal_completion_provider_backend_input_annotation
      &backend_input_annotation =
          record.provider_backend_input_pending_completion_annotation;

  printf("GPGPU-Sim PTX: RT_SUBMIT delayed-completion-enqueue, "
         "warp_uid=%u, warp_id=%u, owner_hw_sid=%u, active_mask=0x%08x, "
         "static_inst_uid=%u, lane_slot_index=%u, "
         "lane_thread_mask=0x%08x, context_ptr=0x%llx, "
         "handoff_window_base=0x%llx, result=0x%08x, "
         "completion_seq=%u, resume_seq=%u, window_tag=%u, reason=%u, "
         "delayed-completion-provider-backend-input-annotation=1, "
         "provider_backend_input_pending_completion_annotation_valid=%u, "
         "provider_payload_consumption_enabled=%u, "
         "backend_input_snapshot_required=%u, "
         "has_provider_payload_backend_input_snapshot=%u, "
         "provider_payload_backend_input_snapshot_valid=%u, "
         "provider_payload_backend_input_snapshot_accepted=%u, "
         "provider_materialized_traversal_input_pending_provenance=1, "
         "provider_materialized_traversal_input_snapshot=1, "
         "has_provider_materialized_traversal_input_snapshot=%u, "
         "provider_materialized_traversal_input_snapshot_valid=%u, "
         "provider_materialized_traversal_input_snapshot_source=%s, "
         "provider_materialized_traversal_input_actual_abi_snapshot_admitted=%u, "
         "delayed_completion_backend_input_annotation_consumes_completion_behavior=0\n",
         record.warp_uid, record.warp_id, record.owner_hw_sid,
         record.active_mask, record.static_inst_uid,
         record.lane_slot_index, record.lane_thread_mask,
         record.context_ptr, record.handoff_window_base,
         record.result_word, record.completion_seq_low,
         record.resume_seq_low, record.window_tag, record.reason,
         backend_input_annotation.valid ? 1 : 0,
         backend_input_annotation.provider_payload_consumption_enabled ? 1 : 0,
         backend_input_annotation.backend_input_snapshot_required ? 1 : 0,
         backend_input_annotation.has_provider_payload_backend_input_snapshot ? 1
                                                                        : 0,
         backend_input_annotation.provider_payload_backend_input_snapshot_valid
             ? 1
             : 0,
         backend_input_annotation
                 .provider_payload_backend_input_snapshot_accepted
             ? 1
             : 0,
         backend_input_annotation
                 .has_provider_materialized_traversal_input_snapshot
             ? 1
             : 0,
         backend_input_annotation
                 .provider_materialized_traversal_input_snapshot_valid
             ? 1
             : 0,
         backend_input_annotation
             .provider_materialized_traversal_input_snapshot_source,
         backend_input_annotation
                 .provider_materialized_traversal_input_actual_abi_snapshot_admitted
             ? 1
             : 0);
  fflush(stdout);
  return true;
}

bool rtcore_build_traversal_completion_event(
    const ptx_instruction *pI, ptx_thread_info *thread,
    unsigned long long context_ptr, unsigned long long handoff_window_base,
    unsigned lane_slot_index,
    const rtcore_runtime_context_window_allocation_record &allocation_record,
    const rtcore_launch_allocation_lifetime_record *lifetime_record,
    rtcore_traversal_completion_event *event) {
  if (event == NULL) {
    return false;
  }

  *event = rtcore_traversal_completion_event();
  event->context_ptr = context_ptr;
  event->handoff_window_base = handoff_window_base;
  event->lane_slot_index = lane_slot_index;
  event->handoff_key =
      rtcore_make_synthetic_handoff_key(handoff_window_base, lane_slot_index,
                                        thread);
  event->token_key =
      rtcore_make_symbolic_rt_token_key(context_ptr, handoff_window_base,
                                        lane_slot_index, thread);
  thread->get_rtcore_current_warp_metadata(&event->warp_metadata);
  if (!rtcore_current_warp_metadata_is_valid(
          "RT_SUBMIT", pI, thread, &event->warp_metadata, lane_slot_index)) {
    return false;
  }
  event->reservation_key = rtcore_make_symbolic_rt_token_reservation_key(
      event->warp_metadata, context_ptr, handoff_window_base);
  event->window_generation =
      rtcore_peek_next_synthetic_window_generation(event->handoff_key);
  event->completion_seq_low =
      rtcore_synthetic_completion_seq_for_generation(event->window_generation);
  event->resume_seq_low = 0;
  event->window_tag =
      rtcore_synthetic_window_tag_for_generation(event->window_generation);
  event->owner_seq_snapshot = rtcore_make_context_window_owner_seq_snapshot(
      event->context_ptr, event->handoff_window_base, event->lane_slot_index,
      event->warp_metadata, event->window_generation,
      event->completion_seq_low, event->resume_seq_low, event->window_tag);
  event->driver_runtime_context_window_lifetime_bridge_snapshot =
      rtcore_make_driver_runtime_context_window_lifetime_bridge_snapshot(
          allocation_record, lifetime_record, event->owner_seq_snapshot,
          event->token_key);
  rtcore_log_driver_runtime_context_window_lifetime_bridge_snapshot(
      pI, event->driver_runtime_context_window_lifetime_bridge_snapshot);
  if (rtcore_fail_closed_on_driver_runtime_context_window_lifetime_bridge_snapshot(
          pI, event->driver_runtime_context_window_lifetime_bridge_snapshot)) {
    return false;
  }
  event->decoded_input_snapshot = rtcore_make_decoded_traversal_input_snapshot(
      event->owner_seq_snapshot);

  rtcore_traversal_source_request source_request =
      rtcore_make_traversal_source_request(
          pI, thread, event->context_ptr, event->handoff_window_base,
          event->lane_slot_index, &event->warp_metadata);
  rtcore_pre_provider_traversal_data_snapshot
      pre_provider_traversal_data_snapshot =
          rtcore_make_pre_provider_traversal_data_snapshot(source_request);
  rtcore_driver_as_resolve_table_lookup_snapshot
      driver_as_resolve_table_lookup_snapshot;
  bool has_driver_as_resolve_table_lookup_snapshot = false;
  rtcore_launch_context_input_publication_record
      launch_context_input_publication_record =
          rtcore_make_launch_context_input_publication_record(
              source_request, event->owner_seq_snapshot,
              pre_provider_traversal_data_snapshot);
  if (launch_context_input_publication_record.publication_enabled) {
    rtcore_log_launch_context_input_publication_record(
        pI, launch_context_input_publication_record);
    if (rtcore_launch_context_input_publication_record_is_complete(
            launch_context_input_publication_record)) {
      rtcore_apply_launch_context_input_publication_record_to_decoded_snapshot(
          &event->decoded_input_snapshot,
          launch_context_input_publication_record);
      rtcore_driver_as_handle_registry_key driver_as_handle_registry_key =
          rtcore_make_driver_as_handle_registry_key(
              source_request, event->owner_seq_snapshot,
              event->driver_runtime_context_window_lifetime_bridge_snapshot,
              launch_context_input_publication_record);
      (void)rtcore_publish_driver_as_handle_registry_entry(
          driver_as_handle_registry_key,
          event->driver_runtime_context_window_lifetime_bridge_snapshot);
      rtcore_driver_as_handle_registry_lookup_snapshot
          driver_as_handle_registry_lookup_snapshot =
              rtcore_lookup_driver_as_handle_registry_entry(
                  driver_as_handle_registry_key);
      rtcore_apply_driver_as_handle_registry_failpoint_to_lookup_snapshot(
          pI, source_request, &driver_as_handle_registry_lookup_snapshot);
      rtcore_log_driver_as_handle_registry_lookup_snapshot(
          pI, source_request, driver_as_handle_registry_lookup_snapshot);
      if (rtcore_fail_closed_on_driver_as_handle_registry_lookup_snapshot(
              pI, source_request, driver_as_handle_registry_lookup_snapshot)) {
        return false;
      }
      rtcore_bvh_format_profile_object_bridge_snapshot
          bvh_format_profile_object_bridge_snapshot =
              rtcore_make_bvh_format_profile_object_bridge_snapshot(
                  RTCORE_BVH_FORMAT_VULKAN_SIM_GEN_RT);
      rtcore_apply_bvh_format_profile_object_bridge_failpoint(
          pI, source_request, &bvh_format_profile_object_bridge_snapshot);
      rtcore_log_bvh_format_profile_object_bridge_snapshot(
          pI, source_request, bvh_format_profile_object_bridge_snapshot);
      rtcore_driver_as_resolve_table_key driver_as_resolve_table_key =
          rtcore_make_driver_as_resolve_table_key(
              driver_as_handle_registry_lookup_snapshot,
              bvh_format_profile_object_bridge_snapshot);
      (void)rtcore_publish_driver_as_resolve_table_entry(
          driver_as_resolve_table_key,
          driver_as_handle_registry_lookup_snapshot,
          bvh_format_profile_object_bridge_snapshot);
      driver_as_resolve_table_lookup_snapshot =
          rtcore_lookup_driver_as_resolve_table_entry(
              driver_as_resolve_table_key);
      has_driver_as_resolve_table_lookup_snapshot = true;
      rtcore_apply_driver_as_resolve_table_failpoint_to_lookup_snapshot(
          pI, source_request, &driver_as_resolve_table_lookup_snapshot);
      rtcore_apply_backend_root_descriptor_failpoint_to_lookup_snapshot(
          pI, source_request, &driver_as_resolve_table_lookup_snapshot);
      rtcore_log_driver_as_resolve_table_lookup_snapshot(
          pI, source_request, driver_as_resolve_table_lookup_snapshot);
      if (rtcore_fail_closed_on_driver_as_resolve_table_lookup_snapshot(
              pI, source_request, driver_as_resolve_table_lookup_snapshot)) {
        return false;
      }
      rtcore_runtime_as_proxy_registry_key runtime_as_proxy_registry_key =
          rtcore_make_runtime_as_proxy_registry_key(
              source_request, event->owner_seq_snapshot,
              event->driver_runtime_context_window_lifetime_bridge_snapshot,
              launch_context_input_publication_record);
      (void)rtcore_publish_runtime_as_proxy_registry_entry(
          runtime_as_proxy_registry_key, pre_provider_traversal_data_snapshot,
          bvh_format_profile_object_bridge_snapshot);
      rtcore_runtime_as_proxy_registry_lookup_snapshot
          runtime_as_proxy_registry_lookup_snapshot =
              rtcore_lookup_runtime_as_proxy_registry_entry(
                  runtime_as_proxy_registry_key);
      rtcore_apply_runtime_as_proxy_registry_failpoint_to_lookup_snapshot(
          pI, source_request, &runtime_as_proxy_registry_lookup_snapshot);
      rtcore_log_runtime_as_proxy_registry_lookup_snapshot(
          pI, source_request, runtime_as_proxy_registry_lookup_snapshot);
      if (rtcore_fail_closed_on_runtime_as_proxy_registry_lookup_snapshot(
              pI, source_request, runtime_as_proxy_registry_lookup_snapshot)) {
        return false;
      }
      rtcore_resolve_table_runtime_proxy_consistency_snapshot
          resolve_table_runtime_proxy_consistency_snapshot =
              rtcore_make_resolve_table_runtime_proxy_consistency_snapshot(
                  driver_as_resolve_table_lookup_snapshot,
                  runtime_as_proxy_registry_lookup_snapshot);
      rtcore_apply_resolve_table_runtime_proxy_consistency_failpoint(
          pI, source_request,
          &resolve_table_runtime_proxy_consistency_snapshot);
      rtcore_log_resolve_table_runtime_proxy_consistency_snapshot(
          pI, source_request,
          resolve_table_runtime_proxy_consistency_snapshot);
      if (rtcore_fail_closed_on_resolve_table_runtime_proxy_consistency_snapshot(
              pI, source_request,
              resolve_table_runtime_proxy_consistency_snapshot)) {
        return false;
      }
      rtcore_top_level_as_proxy_resolve_adapter_snapshot
          top_level_as_proxy_resolve_adapter_snapshot =
              rtcore_make_top_level_as_proxy_resolve_adapter_snapshot(
                  launch_context_input_publication_record,
                  runtime_as_proxy_registry_lookup_snapshot);
      rtcore_apply_top_level_as_proxy_resolve_failpoint_to_adapter_snapshot(
          pI, source_request, &top_level_as_proxy_resolve_adapter_snapshot);
      rtcore_log_top_level_as_proxy_resolve_adapter_snapshot(
          pI, source_request, top_level_as_proxy_resolve_adapter_snapshot);
      if (rtcore_fail_closed_on_top_level_as_proxy_resolve_adapter_snapshot(
              pI, source_request, top_level_as_proxy_resolve_adapter_snapshot)) {
        return false;
      }
      rtcore_apply_top_level_as_proxy_resolve_adapter_snapshot_to_decoded_snapshot(
          &event->decoded_input_snapshot,
          top_level_as_proxy_resolve_adapter_snapshot);
      rtcore_apply_proxy_delegation_failpoint_to_decoded_snapshot(
          pI, source_request, &event->decoded_input_snapshot);
    }
    rtcore_default_compiler_driver_publication_route_record
        default_publication_route_record =
            rtcore_make_default_compiler_driver_publication_route_record(
                launch_context_input_publication_record,
                event->decoded_input_snapshot);
    rtcore_log_default_compiler_driver_publication_route_record(
        pI, default_publication_route_record);
    if (rtcore_fail_closed_on_default_compiler_driver_publication_route_record(
            pI, default_publication_route_record)) {
      return false;
    }
  } else {
    rtcore_update_decoded_traversal_input_from_pre_provider_traversal_data_snapshot(
        &event->decoded_input_snapshot, pre_provider_traversal_data_snapshot);
    rtcore_apply_proxy_delegation_failpoint_to_decoded_snapshot(
        pI, source_request, &event->decoded_input_snapshot);
  }
  rtcore_input_provenance_registry_publication_snapshot registry_publication_snapshot =
      rtcore_publish_input_provenance_registry_entry_snapshot_from_decoded_input(
          source_request, event->owner_seq_snapshot,
          event->decoded_input_snapshot);
  (void)registry_publication_snapshot;
  rtcore_input_provenance_registry_validation_result registry_validation_result =
      rtcore_validate_input_provenance_registry_key_before_provider(
          registry_publication_snapshot, source_request,
          event->owner_seq_snapshot);
  (void)registry_validation_result;
  rtcore_input_provenance_registry_owned_field_coverage_result
      registry_owned_field_coverage_result =
          rtcore_validate_input_provenance_registry_owned_field_coverage_before_provider(
              registry_publication_snapshot);
  (void)registry_owned_field_coverage_result;
  rtcore_input_provenance_registry_read_gate_result registry_read_gate_result =
      rtcore_gate_input_provenance_registry_read_before_provider(
          registry_validation_result, registry_owned_field_coverage_result);
  if (rtcore_fail_closed_on_input_provenance_registry_read_gate_before_provider(
          pI, source_request, registry_read_gate_result)) {
    return false;
  }
  rtcore_log_input_provenance_registry_read_gate_allowed_before_provider(
      pI, source_request, registry_read_gate_result,
      registry_owned_field_coverage_result);
  // Observation-only: attach decoded input to the provider descriptor/bridge
  // as a non-consuming sidecar; traversal still uses the existing request path.
  event->registry_payload_shadow =
      rtcore_make_provider_facing_registry_payload_shadow_after_read_gate(
          registry_publication_snapshot, registry_read_gate_result,
          event->decoded_input_snapshot,
          event->driver_runtime_context_window_lifetime_bridge_snapshot,
          has_driver_as_resolve_table_lookup_snapshot
              ? &driver_as_resolve_table_lookup_snapshot
              : NULL);
  rtcore_apply_provider_decoded_abi_authority_fault_to_registry_payload_shadow(
      pI, source_request, &event->registry_payload_shadow);
  rtcore_log_provider_facing_registry_payload_shadow_before_provider(
      pI, source_request, event->registry_payload_shadow);
  const rtcore_provider_facing_registry_payload_shadow
      *registry_payload_shadow_sidecar =
          event->registry_payload_shadow.valid ? &event->registry_payload_shadow
                                               : NULL;
  const rtcore_provider_decoded_input_observation
      provider_decoded_input_observation =
          rtcore_make_provider_decoded_input_observation(
              registry_payload_shadow_sidecar);
  rtcore_traversal_source_snapshot source_snapshot =
      rtcore_make_traversal_source_snapshot(
          source_request, registry_payload_shadow_sidecar,
          &provider_decoded_input_observation);
  const bool provider_unsupported = !source_snapshot.provider_supported;
  const bool provider_rejected =
      source_snapshot.provider_supported && !source_snapshot.provider_accepted;
  const bool provider_payload_missing =
      source_snapshot.provider_supported && source_snapshot.provider_accepted &&
      !rtcore_traversal_source_snapshot_has_accepted_payload(source_snapshot);
  if (provider_payload_missing) {
    source_snapshot.reject_reason = RTCORE_TRAVERSAL_PROVIDER_REJECT_ACCEPTED_PAYLOAD_MISSING;
  }
  if (provider_unsupported || provider_rejected || provider_payload_missing) {
    printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
           "reason=%s, "
           "provider=%s, context_ptr=0x%llx, handoff_window_base=0x%llx, "
           "lane_slot_index=%u, provider_supported=%u, "
           "provider_accepted=%u, traversal-source-provider-unsupported=%u, "
           "traversal-source-provider-rejected=%u, "
           "traversal-source-provider-payload-missing=%u\n",
           pI->source_file(), pI->source_line(),
           rtcore_traversal_provider_reject_reason_name(
               source_snapshot.reject_reason),
           rtcore_traversal_source_provider_name(source_snapshot.provider),
           event->context_ptr, event->handoff_window_base,
           event->lane_slot_index,
           source_snapshot.provider_supported ? 1 : 0,
           source_snapshot.provider_accepted ? 1 : 0,
           provider_unsupported ? 1 : 0, provider_rejected ? 1 : 0,
           provider_payload_missing ? 1 : 0);
    fflush(stdout);
    return false;
  }
  rtcore_apply_traversal_source_snapshot(event, source_snapshot);
  rtcore_update_decoded_traversal_input_ray_proxy_snapshot(
      &event->decoded_input_snapshot, source_snapshot);
  rtcore_update_decoded_traversal_input_flags_mask_proxy_snapshot(
      &event->decoded_input_snapshot, source_snapshot);
  rtcore_update_decoded_traversal_input_launch_context_snapshot(
      &event->decoded_input_snapshot, source_snapshot);
  rtcore_update_decoded_traversal_input_traversable_root_proxy_snapshot(
      &event->decoded_input_snapshot, source_snapshot);
  rtcore_update_decoded_traversal_input_bvh_format_profile_snapshot(
      &event->decoded_input_snapshot, source_snapshot);

  const bool forced_memory_fault =
      rtcore_test_memory_fault_publication_enabled();
  event->reason =
      forced_memory_fault
          ? RTCORE_RETURN_FOR_MEMORY_FAULT
          : (event->hit_geometry ? RTCORE_RETURN_FOR_CLOSEST_HIT
                                 : RTCORE_RETURN_FOR_MISS);
  event->completion_flags =
      forced_memory_fault ? RTCORE_COMPLETION_FLAG_MEMORY_FAULT
                          : RTCORE_COMPLETION_FLAG_TRACE_DONE;
  event->result_word = rtcore_compact_result(
      event->reason, event->completion_flags, event->completion_seq_low,
      event->resume_seq_low, event->window_tag);

  memset(&event->header, 0, sizeof(event->header));
  event->header.context_ptr = event->context_ptr;
  event->header.window_generation = event->window_generation;
  event->header.completion_seq = event->completion_seq_low;
  event->header.resume_seq = event->resume_seq_low;
  event->header.window_tag = event->window_tag;
  event->header.w0 = event->result_word;
  event->header.w1 = rtcore_test_memory_fault_header_omission_enabled()
                         ? 1u
                         : (1u | (event->reason << 8) |
                            (event->completion_flags << 16));
  event->header.w2 = event->completion_seq_low |
                     (event->resume_seq_low << 16);
  event->header.w3 = event->window_tag;
  rtcore_populate_synthetic_owner_tuple(
      &event->header, event->handoff_key, thread,
      event->warp_metadata.active_mask);
  rtcore_publish_synthetic_dependent_groups(
      pI, event->traversal_snapshot, event->reason,
      event->completion_seq_low, event->resume_seq_low, event->window_tag,
      &event->header);
  return rtcore_synthetic_result_lane_binding_matches(
      pI, event->handoff_key, event->header, event->context_ptr,
      event->result_word);
}

bool rtcore_materialize_traversal_completion_lane_transaction(
    const ptx_instruction *pI, ptx_thread_info *thread,
    const operand_info &result,
    const rtcore_traversal_completion_event &event) {
  if (!rtcore_acquire_symbolic_rt_token(
          pI, event.token_key, event.window_generation,
          event.completion_seq_low, event.resume_seq_low, event.window_tag,
          event.result_word)) {
    return false;
  }
  if (rtcore_test_fail_after_token_acquire_enabled()) {
    rtcore_rollback_symbolic_submit_after_token_acquire(
        pI, event.token_key, event.reservation_key, event.handoff_key);
    return false;
  }
  if (!rtcore_note_symbolic_rt_token_reservation_lane_acquired(
          pI, event.reservation_key, event.lane_slot_index)) {
    return false;
  }
  rtcore_publish_synthetic_handoff_window(
      pI, event.handoff_key, event.header);
  if (rtcore_test_fail_after_handoff_publish_enabled()) {
    rtcore_rollback_symbolic_submit_after_handoff_publish(
        pI, event.token_key, event.reservation_key, event.handoff_key);
    return false;
  }

  ptx_reg_t result_data;
  result_data.u32 = event.result_word;
  thread->set_operand_value(result, result_data, U32_TYPE, thread, pI);
  if (rtcore_test_fail_after_result_write_enabled()) {
    rtcore_rollback_symbolic_submit_after_result_write(
        pI, event.token_key, event.reservation_key, event.handoff_key);
    return false;
  }

  return rtcore_software_acquire_synthetic_completion(
      pI, event.context_ptr, event.handoff_window_base,
      event.lane_slot_index, event.result_word, thread);
}

bool rtcore_publish_or_enqueue_traversal_completion_event(
    const ptx_instruction *pI,
    const rtcore_traversal_completion_event &event) {
  bool adapter_claim_accepted = false;
  if (rtcore_delayed_traversal_completion_enabled()) {
    adapter_claim_accepted =
        rtcore_enqueue_pending_traversal_completion(event);
  } else if (rtcore_test_adapter_claim_failure_enabled()) {
    adapter_claim_accepted = false;
  } else {
    rtcore_adapter_completion_publication publication =
        rtcore_make_adapter_completion_publication_from_event(event);
    adapter_claim_accepted =
        rtcore_publish_adapter_completion_record(publication);
  }

  if (!adapter_claim_accepted) {
    printf("GPGPU-Sim PTX: RT_SUBMIT fail-closed (%s:%u), "
           "reason=RT_TOKEN_ADAPTER_CLAIM_FAILED, context_ptr=0x%llx, "
           "handoff_window_base=0x%llx, lane_slot_index=%u, "
           "adapter_claim_accepted=%u, completed_token=0, "
           "remaining_windows=%zu, remaining_tokens=%zu, "
           "remaining_reservations=%zu, remaining_allocator_live=%zu, "
           "consumed=0\n",
           pI->source_file(), pI->source_line(), event.context_ptr,
           event.handoff_window_base, event.lane_slot_index,
           adapter_claim_accepted ? 1 : 0,
           rtcore_synthetic_handoff_window_count(),
           rtcore_symbolic_rt_token_count(),
           rtcore_symbolic_rt_token_reservation_count(),
           rtcore_symbolic_rt_token_allocator_live_count());
    fflush(stdout);
    return false;
  }
  return true;
}

bool rtcore_complete_traversal_completion_event_token(
    const ptx_instruction *pI,
    const rtcore_traversal_completion_event &event) {
  return rtcore_complete_symbolic_rt_token(
      pI, event.token_key, event.result_word, event.completion_seq_low,
      event.resume_seq_low, event.window_tag);
}

// Adapter boundary from functional traversal results to the architectural
// per-lane result/window/token completion transaction.
void rtcore_traversal_completion_adapter_publish(
    const ptx_instruction *pI, ptx_thread_info *thread,
    const operand_info &result, unsigned long long context_ptr,
    unsigned long long handoff_window_base,
    const rtcore_runtime_context_window_allocation_record &allocation_record,
    const rtcore_launch_allocation_lifetime_record *lifetime_record) {
  const unsigned lane_slot_index = rtcore_lane_slot_index(thread);
  rtcore_traversal_completion_event event;
  if (!rtcore_build_traversal_completion_event(
          pI, thread, context_ptr, handoff_window_base, lane_slot_index,
          allocation_record, lifetime_record, &event)) {
    inst_not_implemented(pI);
    return;
  }
  if (!rtcore_materialize_traversal_completion_lane_transaction(
          pI, thread, result, event)) {
    inst_not_implemented(pI);
    return;
  }
  if (!rtcore_publish_or_enqueue_traversal_completion_event(pI, event)) {
    inst_not_implemented(pI);
    return;
  }
  if (!rtcore_complete_traversal_completion_event_token(pI, event)) {
    inst_not_implemented(pI);
    return;
  }

  printf("GPGPU-Sim PTX: RT_SUBMIT traversal-complete (%s:%u), "
         "context_ptr=0x%llx, handoff_window_base=0x%llx, "
         "lane_slot_index=%u, reason=%s, has_traversal=%u, hit_geometry=%u, "
         "result=0x%08x, w0=0x%08x, w1=0x%08x, w2=0x%08x, w3=0x%08x, "
         "node_visits=%u, primitive_tests=%u\n",
         pI->source_file(), pI->source_line(), event.context_ptr,
         event.handoff_window_base, event.lane_slot_index,
         rtcore_return_reason_name(event.reason),
         event.has_traversal_data ? 1 : 0, event.hit_geometry ? 1 : 0,
         event.result_word, event.header.w0, event.header.w1,
         event.header.w2, event.header.w3,
         event.traversal_snapshot.rtcore_node_visits,
         event.traversal_snapshot.rtcore_primitive_tests);
  fflush(stdout);
}

